#[derive(Clone, Debug, Default)]
struct LayerVisibilityCounts {
    feature_kind_counts: HashMap<String, usize>,
    repeat_feature_kind_counts: HashMap<String, usize>,
    repeat_feature_count: usize,
    array_feature_count: usize,
    construct_reasoning_evidence_count: usize,
    contextual_transcript_feature_count: usize,
    regulatory_feature_count: usize,
    restriction_site_count: usize,
    restriction_site_total_count: usize,
    restriction_site_preferred_count: usize,
    restriction_site_unique_count: usize,
    gc_region_count: usize,
    orf_count: usize,
    methylation_site_count: usize,
}

impl LayerVisibilityCounts {
    fn kind_count(&self, kind: &str) -> usize {
        self.feature_kind_counts
            .get(&kind.trim().to_ascii_uppercase())
            .copied()
            .unwrap_or(0)
    }

    fn tfbs_count(&self) -> usize {
        self.kind_count("TFBS")
            + self.kind_count("TF_BINDING_SITE")
            + self.kind_count("PROTEIN_BIND")
    }

    fn repeat_count(&self) -> usize {
        self.repeat_feature_count
    }

    fn array_count(&self) -> usize {
        self.array_feature_count
    }

    fn construct_reasoning_evidence_count(&self) -> usize {
        self.construct_reasoning_evidence_count
    }

    fn total_feature_count(&self) -> usize {
        self.feature_kind_counts.values().sum()
    }

    fn contextual_transcript_count(&self) -> usize {
        self.contextual_transcript_feature_count
    }
}

