    /// Replace placeholder DNA content after a deferred/lazy window open.
    ///
    /// The `true` flag preserves the "loaded from engine" semantics used by the
    /// lazy open path rather than treating this as an ordinary in-window edit.
    pub fn replace_loaded_sequence(&mut self, dna: DNAsequence) {
        self.replace_active_dna(dna, true);
    }

    /// Defer feature-tree construction until the first user interaction.
    ///
    /// This keeps first paint lighter for feature-dense windows opened through
    /// lazy-load flows.
    pub fn defer_feature_tree_until_interaction(&mut self) {
        self.feature_tree_deferred_until_interaction = true;
    }

    fn maybe_auto_enable_deferred_feature_tree(&mut self) -> bool {
        if self.feature_tree_deferred_until_interaction {
            self.feature_tree_deferred_until_interaction = false;
            true
        } else {
            false
        }
    }

    pub fn refresh_from_engine_sequence_state(&mut self) {
        let Some(seq_id) = self.seq_id.clone() else {
            return;
        };
        let Some(engine) = &self.engine else {
            return;
        };
        let updated_dna = {
            let Ok(guard) = engine.try_read() else {
                return;
            };
            guard.state().sequences.get(&seq_id).cloned()
        };
        let Some(updated_dna) = updated_dna else {
            return;
        };
        self.replace_active_dna(updated_dna, false);
        let selected_feature_invalid = self
            .get_selected_feature_id()
            .map(|id| {
                self.dna
                    .read()
                    .map(|dna| id >= dna.features().len())
                    .unwrap_or(true)
            })
            .unwrap_or(false);
        if selected_feature_invalid {
            self.map_dna.select_feature(None);
        }
        self.prune_multi_selected_feature_ids();
    }

    fn replace_active_dna(&mut self, dna: DNAsequence, clear_feature_focus: bool) {
        let previous_is_circular = self
            .dna
            .read()
            .map(|existing| existing.is_circular())
            .unwrap_or(true);
        let new_is_circular = dna.is_circular();
        let topology_changed = previous_is_circular != new_is_circular;
        let previous_len = self
            .dna
            .read()
            .map(|existing| existing.len())
            .unwrap_or_default();
        if topology_changed {
            self.log_topology_transition_status("replace_active_dna: begin");
        }
        *self.dna.write().expect("DNA lock poisoned") = dna;
        if clear_feature_focus {
            self.clear_feature_focus();
        }
        if topology_changed {
            self.log_topology_transition_status("replace_active_dna: dna swapped");
        }
        self.description_cache_initialized = false;
        self.invalidate_dotplot_cache();
        self.invalidate_feature_tree_cache();
        self.cached_restriction_site_scan = None;
        self.cached_tfbs_hit_scan = None;
        self.cached_tfbs_score_tracks = None;
        self.cached_tfbs_track_similarity = None;
        self.mark_dna_layout_dirty();
        if topology_changed {
            self.log_topology_transition_status("replace_active_dna: caches invalidated");
        }
        self.reconcile_linear_viewport_after_dna_replace(previous_len, previous_is_circular);
        if topology_changed {
            self.log_topology_transition_status("replace_active_dna: viewport reconciled");
        }
        self.update_dna_map();
        if topology_changed {
            self.log_topology_transition_status("replace_active_dna: renderer updated");
        }
        self.construct_reasoning_overlay_sync_key = None;
        self.refresh_construct_reasoning_overlay_if_needed(true);
        if topology_changed {
            self.log_topology_transition_status("replace_active_dna: overlay refreshed");
        }
    }

    fn invalidate_dotplot_cache(&mut self) {
        self.dotplot_cached_view = None;
        self.dotplot_cached_flex_track = None;
        self.dotplot_cache_seq_id.clear();
        self.dotplot_cache_view_id.clear();
        self.dotplot_cache_track_id.clear();
        self.dotplot_hover_crosshair_bp = None;
        self.dotplot_locked_crosshair_bp = None;
    }

    fn invalidate_feature_tree_cache(&mut self) {
        self.feature_tree_cache = None;
    }

    fn mark_dna_layout_dirty(&self) {
        if let Ok(mut display) = self.dna_display.write() {
            display.update_layout_mut().update_all();
        }
    }

    fn suggested_linear_viewport_span_after_topology_switch(
        sequence_length: usize,
    ) -> Option<usize> {
        (sequence_length > LINEAR_TOPOLOGY_SWITCH_MAX_INITIAL_SPAN_BP)
            .then_some(LINEAR_TOPOLOGY_SWITCH_MAX_INITIAL_SPAN_BP.min(sequence_length))
    }

    fn reconcile_linear_viewport_after_dna_replace(
        &self,
        previous_len: usize,
        previous_is_circular: bool,
    ) {
        if self.is_circular() {
            return;
        }
        let new_len = self.dna.read().map(|dna| dna.len()).unwrap_or_default();
        if new_len == 0 {
            return;
        }
        let (start_bp, span_bp) = self
            .dna_display
            .read()
            .map(|display| {
                (
                    display.linear_view_start_bp(),
                    display.linear_view_span_bp(),
                )
            })
            .unwrap_or((0, new_len));

        let was_full_sequence_view = previous_len > 0 && (span_bp == 0 || span_bp >= previous_len);
        if previous_is_circular
            && was_full_sequence_view
            && let Some(initial_span) =
                Self::suggested_linear_viewport_span_after_topology_switch(new_len)
        {
            self.set_linear_viewport(0, initial_span);
            return;
        }

        if was_full_sequence_view && new_len > previous_len {
            self.set_linear_viewport(0, new_len);
            return;
        }
        self.set_linear_viewport(start_bp, span_bp);
    }

    fn log_topology_transition_status(&mut self, stage: &str) {
        if !Self::topology_transition_tracing_enabled() {
            return;
        }
        let (sequence_length, is_circular, feature_count) = self
            .dna
            .read()
            .map(|dna| (dna.len(), dna.is_circular(), dna.features().len()))
            .unwrap_or((0, true, 0));
        let (view_start, view_span) = self
            .dna_display
            .read()
            .map(|display| {
                (
                    display.linear_view_start_bp(),
                    display.linear_view_span_bp(),
                )
            })
            .unwrap_or((0, 0));
        let status = format!(
            "Topology transition [{stage}] | topology={} | len={} bp | features={} | mode={} | primary_map={} | linear_view={}..{} (span {} bp)",
            if is_circular { "circular" } else { "linear" },
            sequence_length,
            feature_count,
            self.dna_presentation_mode.label(),
            self.primary_map_mode.label(),
            view_start.saturating_add(1),
            view_start.saturating_add(view_span),
            view_span,
        );
        self.op_status = status.clone();
        eprintln!("{status}");
    }

    fn topology_transition_tracing_enabled() -> bool {
        env::var(TOPOLOGY_TRANSITION_TRACE_ENV)
            .map(|value| {
                let normalized = value.trim().to_ascii_lowercase();
                !normalized.is_empty()
                    && normalized != "0"
                    && normalized != "false"
                    && normalized != "off"
                    && normalized != "no"
            })
            .unwrap_or(false)
    }

