    fn render_selection_simple_pcr_context_action(&mut self, ui: &mut egui::Ui) -> bool {
        let active_pcr_roi_source = self.active_pcr_roi_source_0based();
        let set_roi_response = ui.add_enabled(
            active_pcr_roi_source.is_some(),
            egui::Button::new("Set PCR ROI from selection / painted ROI"),
        );
        let set_roi_response = if let Some((start, end_exclusive, source)) = active_pcr_roi_source {
            set_roi_response.on_hover_text(format!(
                "Seed Primer/qPCR ROI from {source}: {start}..{end_exclusive} and open the dedicated PCR Designer"
            ))
        } else {
            set_roi_response.on_hover_text(
                "Requires a non-empty current selection or a painted ROI interval on the linear DNA map",
            )
        };
        if set_roi_response.clicked() {
            if let Err(err) = self.seed_primer_design_roi_from_active_region() {
                self.op_status = err;
            }
            return true;
        }

        let selection_roi = self.current_selection_range_0based();
        let response = ui.add_enabled(
            selection_roi.is_some(),
            egui::Button::new("Simple PCR from selection"),
        );
        let response = if let Some((start, end_exclusive)) = selection_roi {
            response.on_hover_text(format!(
                "Seed a simple PCR from the current core selection {}..{}, apply flank windows, and open PCR Designer",
                start, end_exclusive
            ))
        } else {
            response.on_hover_text("Requires a non-empty current selection on the linear DNA map")
        };
        if response.clicked() {
            self.open_simple_pcr_designer_from_current_selection();
            return true;
        }
        false
    }

    fn queue_current_primer_roi_fields_for_pcr(&mut self) {
        let template = self.seq_id.clone().unwrap_or_default();
        if template.trim().is_empty() {
            self.op_status = "No active template sequence".to_string();
            return;
        }
        let (start, end_exclusive) = match self.resolve_roi_range_inputs_0based(
            &self.primer_design_ui.roi_start_0based,
            &self.primer_design_ui.roi_end_0based,
            "primer_design",
        ) {
            Ok(value) => value,
            Err(message) => {
                self.op_status = message;
                return;
            }
        };
        self.primer_design_ui.roi_start_0based = start.to_string();
        self.primer_design_ui.roi_end_0based = end_exclusive.to_string();
        match self.queue_pcr_region(&template, start, end_exclusive, "primer ROI form") {
            Ok(true) => {
                self.show_engine_ops = true;
                self.op_status = format!(
                    "Queued PCR region spec from form: {start}..{end_exclusive} (0-based, end-exclusive); queue stores region specs, not running Primer3 jobs"
                );
                self.save_engine_ops_state();
            }
            Ok(false) => {
                self.op_status = format!(
                    "PCR region spec already queued for template '{}': {}..{}",
                    template, start, end_exclusive
                );
            }
            Err(message) => {
                self.op_status = format!("Could not queue PCR region spec: {message}");
            }
        }
    }

    fn queue_selected_features_for_pcr(&mut self) {
        let template = self.seq_id.clone().unwrap_or_default();
        if template.trim().is_empty() {
            self.op_status = "No active template sequence".to_string();
            return;
        }
        let selected_feature_ids = self.selected_feature_ids_for_pcr_roi_actions();
        if selected_feature_ids.is_empty() {
            self.op_status = "No selected features available to queue for PCR".to_string();
            return;
        }
        let mut queued = 0usize;
        let mut duplicates = 0usize;
        let mut invalid_feature_ids: Vec<usize> = vec![];
        for feature_id in selected_feature_ids {
            let Some((start, end_exclusive)) = self.feature_roi_range_0based(feature_id) else {
                invalid_feature_ids.push(feature_id);
                continue;
            };
            match self.queue_pcr_region(
                &template,
                start,
                end_exclusive,
                &format!("feature n-{feature_id}"),
            ) {
                Ok(true) => {
                    queued += 1;
                }
                Ok(false) => {
                    duplicates += 1;
                }
                Err(_) => {
                    invalid_feature_ids.push(feature_id);
                }
            }
        }
        self.op_status = format!(
            "Queued {} PCR region(s) from selected features; duplicates skipped: {}; invalid features: {}",
            queued,
            duplicates,
            invalid_feature_ids.len()
        );
        self.save_engine_ops_state();
    }

    fn remove_pcr_queued_region(&mut self, idx: usize) {
        if idx < self.pcr_queued_regions_ui.len() {
            self.pcr_queued_regions_ui.remove(idx);
            self.op_status = format!(
                "Removed PCR queued region #{:02}; {} region(s) remain",
                idx + 1,
                self.pcr_queued_regions_ui.len()
            );
            self.save_engine_ops_state();
        }
    }

    fn clear_pcr_region_queue(&mut self) {
        if self.pcr_queued_regions_ui.is_empty() {
            self.op_status = "PCR region queue is already empty".to_string();
            return;
        }
        self.pcr_queued_regions_ui.clear();
        self.op_status = "Cleared PCR region queue".to_string();
        self.save_engine_ops_state();
    }

    fn clear_pcr_batch_results(&mut self) {
        if self.pcr_batch_results_ui.is_empty() {
            self.op_status = "PCR batch results are already empty".to_string();
            return;
        }
        self.pcr_batch_results_ui.clear();
        self.op_status = "Cleared PCR batch results".to_string();
        self.save_engine_ops_state();
    }

    fn latest_primer_report_id_for_template(&self, template: &str) -> Option<String> {
        let template = template.trim();
        if template.is_empty() {
            return None;
        }
        let engine = self.engine.as_ref()?;
        let guard = engine.try_read().ok()?;
        guard
            .list_primer_design_reports()
            .into_iter()
            .filter(|row| row.template == template)
            .max_by_key(|row| (row.generated_at_unix_ms, row.report_id.clone()))
            .map(|row| row.report_id)
    }

    fn open_sequence_by_id(&mut self, seq_id: &str) -> Result<(), String> {
        let seq_id = seq_id.trim();
        if seq_id.is_empty() {
            return Err("Sequence id is empty".to_string());
        }
        let Some(engine) = self.engine.clone() else {
            return Err("No engine attached".to_string());
        };
        let dna = {
            let guard = engine
                .read()
                .map_err(|_| "Engine lock poisoned while opening sequence".to_string())?;
            guard
                .state()
                .sequences
                .get(seq_id)
                .cloned()
                .ok_or_else(|| format!("Sequence '{seq_id}' not found"))?
        };
        self.seq_id = Some(seq_id.to_string());
        self.replace_active_dna(dna, true);
        self.op_status = format!("Opened sequence '{seq_id}' from PCR batch results");
        self.show_engine_ops = true;
        Ok(())
    }

    fn splicing_group_roi_range_0based(view: &SplicingExpertView) -> Option<(usize, usize)> {
        if view.region_start_1based == 0 || view.region_end_1based < view.region_start_1based {
            return None;
        }
        Some((
            view.region_start_1based.saturating_sub(1),
            view.region_end_1based,
        ))
    }

    fn splicing_selected_transcript_feature_id(
        &mut self,
        view: &SplicingExpertView,
    ) -> Option<usize> {
        let exists = self
            .splicing_expert_selected_transcript_feature_id
            .and_then(|feature_id| {
                view.transcripts
                    .iter()
                    .any(|row| row.transcript_feature_id == feature_id)
                    .then_some(feature_id)
            });
        if let Some(feature_id) = exists {
            return Some(feature_id);
        }
        let fallback = view
            .transcripts
            .first()
            .map(|row| row.transcript_feature_id);
        self.splicing_expert_selected_transcript_feature_id = fallback;
        fallback
    }

    fn splicing_transcript_dotplot_mode(
        view: &SplicingExpertView,
        transcript_feature_id: usize,
    ) -> DotplotMode {
        view.transcripts
            .iter()
            .find(|row| row.transcript_feature_id == transcript_feature_id)
            .map(|row| row.strand.trim() == "-")
            .unwrap_or_else(|| view.strand.trim() == "-")
            .then_some(DotplotMode::PairReverseComplement)
            .unwrap_or(DotplotMode::PairForward)
    }

    fn recommend_pair_dotplot_step(
        query_span_bp: usize,
        reference_span_bp: usize,
        word_size: usize,
        requested_step_bp: usize,
    ) -> usize {
        let query_span_bp = query_span_bp.max(1);
        let reference_span_bp = reference_span_bp.max(1);
        let word_size = word_size.max(1);
        let mut step_bp = requested_step_bp.max(1);
        loop {
            let query_windows = Self::dotplot_window_count(query_span_bp, word_size, step_bp);
            let reference_windows =
                Self::dotplot_window_count(reference_span_bp, word_size, step_bp);
            if query_windows == 0
                || reference_windows == 0
                || query_windows.saturating_mul(reference_windows) <= MAX_DOTPLOT_PAIR_EVALUATIONS
            {
                return step_bp;
            }
            if step_bp >= query_span_bp.max(reference_span_bp) {
                return step_bp;
            }
            step_bp = step_bp.saturating_add(1);
        }
    }

    fn normalize_operation_id_token(raw: &str) -> String {
        let mut token = String::new();
        for c in raw.chars() {
            if c.is_ascii_alphanumeric() {
                token.push(c.to_ascii_lowercase());
            } else if matches!(c, '_' | '-' | '.') && !token.ends_with('_') {
                token.push('_');
            }
        }
        token.trim_matches('_').to_string()
    }

    fn derive_selected_transcript_and_open_dotplot(&mut self, view: &SplicingExpertView) {
        let Some(source_seq_id) = self.seq_id.clone() else {
            self.op_status =
                "No active genomic sequence selected for transcript derivation".to_string();
            return;
        };
        let Some(transcript_feature_id) = self.splicing_selected_transcript_feature_id(view) else {
            self.op_status = "No transcript lane is available in this splicing group".to_string();
            return;
        };
        let derive_result = self.derive_transcript_sequences_with_compact_feedback(
            source_seq_id.clone(),
            vec![transcript_feature_id],
            None,
            &format!("selected transcript lane n-{}", transcript_feature_id + 1),
        );
        let Some(derive_result) = derive_result else {
            return;
        };
        let Some(derived_seq_id) = derive_result.created_seq_ids.first().cloned() else {
            self.op_status =
                "Transcript derivation succeeded but no output sequence was returned".to_string();
            return;
        };
        let query_len = self
            .engine
            .as_ref()
            .and_then(|engine| {
                engine.read().ok().and_then(|guard| {
                    guard
                        .state()
                        .sequences
                        .get(&derived_seq_id)
                        .map(|dna| dna.len())
                })
            })
            .unwrap_or(0);
        if query_len == 0 {
            self.op_status = format!(
                "Derived transcript '{}' is empty; dotplot was skipped",
                derived_seq_id
            );
            return;
        }
        let reference_span_start_0based = view.region_start_1based.saturating_sub(1);
        let reference_span_end_0based = view.region_end_1based;
        if reference_span_end_0based <= reference_span_start_0based {
            self.op_status =
                "Splicing view region is invalid for transcript-vs-genomic dotplot".to_string();
            return;
        }
        let word_size =
            Self::parse_positive_usize_text(&self.dotplot_ui.word_size, "dotplot word_size")
                .unwrap_or(7);
        let requested_step_bp =
            Self::parse_positive_usize_text(&self.dotplot_ui.step_bp, "dotplot step_bp")
                .unwrap_or(1);
        let reference_span_bp =
            reference_span_end_0based.saturating_sub(reference_span_start_0based);
        let adjusted_step_bp = Self::recommend_pair_dotplot_step(
            query_len,
            reference_span_bp,
            word_size,
            requested_step_bp,
        );
        self.dotplot_ui.mode = Self::splicing_transcript_dotplot_mode(view, transcript_feature_id);
        self.dotplot_ui.reference_seq_id = source_seq_id.clone();
        self.dotplot_ui.reference_span_start_0based = reference_span_start_0based.to_string();
        self.dotplot_ui.reference_span_end_0based = reference_span_end_0based.to_string();
        self.dotplot_ui.step_bp = adjusted_step_bp.to_string();
        self.dotplot_ui.dotplot_id = format!(
            "{}_vs_{}_f{}",
            Self::normalize_operation_id_token(&derived_seq_id),
            Self::normalize_operation_id_token(&source_seq_id),
            transcript_feature_id + 1
        );
        self.primary_map_mode = PrimaryMapMode::Dotplot;
        self.compute_primary_dotplot();
        self.open_dotplot_window();
        if adjusted_step_bp != requested_step_bp {
            self.op_status = format!(
                "Auto-adjusted dotplot step to {} to keep pair evaluations <= {}; {}",
                adjusted_step_bp, MAX_DOTPLOT_PAIR_EVALUATIONS, self.op_status
            );
        }
    }

    fn open_construct_reasoning_dotplot_action(
        &mut self,
        action: &ConstructReasoningDotplotAction,
    ) -> Result<(), String> {
        let seq_id = self.seq_id.clone().ok_or_else(|| {
            "No active sequence selected for reasoning-guided dotplot".to_string()
        })?;
        let sequence_len = self.dna.read().map(|dna| dna.len()).unwrap_or(0);
        if sequence_len == 0 {
            return Err("Active sequence is empty; dotplot span unavailable".to_string());
        }
        let focus_start_0based = action
            .focus_start_0based
            .min(sequence_len.saturating_sub(1));
        let focus_end_0based_exclusive = action
            .focus_end_0based_exclusive
            .max(focus_start_0based.saturating_add(1))
            .min(sequence_len);
        let focus_span_bp = focus_end_0based_exclusive
            .saturating_sub(focus_start_0based)
            .max(1);
        let target_span_bp = if sequence_len <= 200 {
            sequence_len
        } else {
            focus_span_bp.saturating_mul(3).clamp(200, sequence_len)
        };
        let half_window_bp = target_span_bp.saturating_sub(1) / 2;
        let focus_center_0based = focus_start_0based
            .saturating_add(focus_span_bp / 2)
            .min(sequence_len.saturating_sub(1));
        let (viewport_start_0based, viewport_end_0based_exclusive) =
            Self::bounded_center_window(sequence_len, focus_center_0based, half_window_bp)
                .ok_or_else(|| "Could not resolve a viewport for the repeat region".to_string())?;
        self.set_linear_viewport(
            viewport_start_0based,
            viewport_end_0based_exclusive.saturating_sub(viewport_start_0based),
        );
        self.sync_linear_view_input_fields_to_viewport();
        self.dotplot_ui.mode = action.mode;
        self.dotplot_ui.half_window_bp = half_window_bp.max(1).to_string();
        self.dotplot_ui.overlay_enabled = false;
        self.dotplot_ui.reference_seq_id.clear();
        self.dotplot_ui.reference_span_start_0based.clear();
        self.dotplot_ui.reference_span_end_0based.clear();
        self.dotplot_ui.flex_track_id.clear();
        self.clear_dotplot_query_override();
        let mode_tag = match action.mode {
            DotplotMode::SelfForward => "self",
            DotplotMode::SelfReverseComplement => "revcomp",
            DotplotMode::PairForward => "pair_forward",
            DotplotMode::PairReverseComplement => "pair_revcomp",
        };
        self.dotplot_ui.dotplot_id = format!(
            "{}_reasoning_{}_{}_{}",
            Self::normalize_operation_id_token(&seq_id),
            focus_start_0based.saturating_add(1),
            focus_end_0based_exclusive,
            mode_tag
        );
        self.primary_map_mode = PrimaryMapMode::Dotplot;
        self.compute_primary_dotplot();
        self.open_dotplot_window();
        Ok(())
    }

    fn extract_current_selection_as_sequence(&mut self) {
        let template = self.seq_id.clone().unwrap_or_default();
        if template.is_empty() {
            self.op_status = "No active template sequence".to_string();
            return;
        }
        let selection = self
            .dna_display
            .read()
            .ok()
            .and_then(|display| display.selection());
        let Some(selection) = selection else {
            self.op_status = "No sequence selection available on map/sequence panel".to_string();
            return;
        };
        let from = selection.from();
        let to = selection.to();
        if from == to {
            self.op_status = "Selected span is empty; drag-select a non-empty interval".to_string();
            return;
        }
        self.extract_from = from.to_string();
        self.extract_to = to.to_string();
        self.apply_operation_with_feedback(Operation::ExtractRegion {
            input: template,
            from,
            to,
            output_id: if self.extract_output_id.trim().is_empty() {
                None
            } else {
                Some(self.extract_output_id.trim().to_string())
            },
        });
    }

    fn select_current_visible_span(&mut self) {
        let Some((start, end_exclusive)) = self.current_visible_linear_span_range_0based() else {
            self.op_status =
                "Visible linear span is unavailable; switch to a non-empty linear view".to_string();
            return;
        };
        match self.set_selection_range_0based(start, end_exclusive) {
            Ok(()) => {
                self.op_status = format!(
                    "Selected visible span: {}..{} (0-based, end-exclusive)",
                    start, end_exclusive
                );
            }
            Err(err) => {
                self.op_status = err;
            }
        }
    }

    fn set_linear_viewport(&self, start_bp: usize, span_bp: usize) {
        let sequence_length = self.dna.read().expect("DNA lock poisoned").len();
        if sequence_length == 0 {
            return;
        }
        let span = if span_bp == 0 {
            sequence_length
        } else {
            span_bp.clamp(1, sequence_length)
        };
        let max_start = sequence_length.saturating_sub(span);
        let start = start_bp.min(max_start);

        self.dna_display
            .write()
            .expect("DNA display lock poisoned")
            .set_linear_viewport(start, span);
        let Some(engine) = &self.engine else {
            return;
        };
        let mut guard = engine.write().expect("Engine lock poisoned");
        let display = &mut guard.state_mut().display;
        display.linear_view_start_bp = start;
        display.linear_view_span_bp = span;
    }

    fn sync_linear_view_input_fields_to_viewport(&mut self) {
        let (start_bp, span_bp, sequence_length) = self.current_linear_viewport();
        if sequence_length == 0 {
            self.linear_view_start_1based_input.clear();
            self.linear_view_end_1based_input.clear();
            return;
        }
        let end_bp = start_bp.saturating_add(span_bp).min(sequence_length);
        self.linear_view_start_1based_input = start_bp.saturating_add(1).to_string();
        self.linear_view_end_1based_input = end_bp.to_string();
    }

    fn apply_linear_viewport_from_input_fields(&mut self) {
        let sequence_length = self.dna.read().expect("DNA lock poisoned").len();
        if sequence_length == 0 {
            self.op_status = "No active sequence loaded for viewport navigation".to_string();
            return;
        }
        let start_1based = match Self::parse_required_usize_text(
            &self.linear_view_start_1based_input,
            "view_start_1based",
        ) {
            Ok(value) => value,
            Err(err) => {
                self.op_status = err;
                return;
            }
        };
        let end_1based = match Self::parse_required_usize_text(
            &self.linear_view_end_1based_input,
            "view_end_1based",
        ) {
            Ok(value) => value,
            Err(err) => {
                self.op_status = err;
                return;
            }
        };
        if start_1based == 0 {
            self.op_status = "view_start_1based must be >= 1".to_string();
            return;
        }
        if start_1based > sequence_length {
            self.op_status = format!(
                "view_start_1based={} exceeds sequence length {}",
                start_1based, sequence_length
            );
            return;
        }
        if end_1based < start_1based {
            self.op_status = format!(
                "view_end_1based={} must be >= view_start_1based={}",
                end_1based, start_1based
            );
            return;
        }
        let clamped_end_1based = end_1based.min(sequence_length);
        let start_0based = start_1based.saturating_sub(1);
        let span_bp = clamped_end_1based
            .saturating_sub(start_1based)
            .saturating_add(1);
        if span_bp == 0 {
            self.op_status = "Requested viewport span is empty".to_string();
            return;
        }
        self.set_linear_viewport(start_0based, span_bp);
        self.op_status = format!(
            "Set linear map view to {}..{} (1-based, {} bp)",
            start_1based, clamped_end_1based, span_bp
        );
        self.sync_linear_view_input_fields_to_viewport();
    }

    fn set_linear_vertical_offset_px(&self, offset_px: f32) {
        let offset_px = if offset_px.is_finite() {
            offset_px
        } else {
            0.0
        };
        let stored_offset = {
            let mut display = self.dna_display.write().expect("DNA display lock poisoned");
            display.set_linear_view_vertical_offset_px(offset_px);
            display.linear_view_vertical_offset_px()
        };
        let Some(engine) = &self.engine else {
            return;
        };
        let mut guard = engine.write().expect("Engine lock poisoned");
        guard.state_mut().display.linear_view_vertical_offset_px = stored_offset;
    }

    fn pan_linear_vertical_viewport(&self, delta_px: f32) {
        if !delta_px.is_finite() || delta_px.abs() <= f32::EPSILON {
            return;
        }
        let current = self.current_linear_vertical_offset_px();
        self.set_linear_vertical_offset_px(current + delta_px);
    }

    fn linear_vertical_fit_delta(
        area_top: f32,
        area_bottom: f32,
        content_top: f32,
        content_bottom: f32,
        margin_px: f32,
    ) -> f32 {
        if !area_top.is_finite()
            || !area_bottom.is_finite()
            || !content_top.is_finite()
            || !content_bottom.is_finite()
        {
            return 0.0;
        }
        if area_bottom <= area_top || content_bottom <= content_top {
            return 0.0;
        }
        let margin = margin_px.max(0.0);
        let viewport_top = area_top + margin;
        let viewport_bottom = area_bottom - margin;
        if viewport_bottom <= viewport_top {
            return 0.0;
        }
        let viewport_center = (viewport_top + viewport_bottom) * 0.5;
        let content_center = (content_top + content_bottom) * 0.5;
        viewport_center - content_center
    }

    fn clamp_linear_vertical_fit_delta(delta: f32, area_top: f32, area_bottom: f32) -> f32 {
        if !delta.is_finite() || !area_top.is_finite() || !area_bottom.is_finite() {
            return 0.0;
        }
        let viewport_height = (area_bottom - area_top).abs();
        let max_delta = (viewport_height * 2.0).clamp(200.0, 5_000.0);
        delta.clamp(-max_delta, max_delta)
    }

    fn fit_linear_features_in_view(&self) {
        if self.is_circular() {
            return;
        }
        let Some((area_top, area_bottom, content_top, content_bottom)) =
            self.map_dna.linear_visible_vertical_bounds()
        else {
            self.set_linear_vertical_offset_px(0.0);
            return;
        };
        let delta = Self::linear_vertical_fit_delta(
            area_top,
            area_bottom,
            content_top,
            content_bottom,
            12.0,
        );
        let delta = Self::clamp_linear_vertical_fit_delta(delta, area_top, area_bottom);
        self.pan_linear_vertical_viewport(delta);
    }

    fn zoom_linear_viewport_around(&self, center_bp: usize, zoom_in: bool) {
        let (start, span, sequence_length) = self.current_linear_viewport();
        if sequence_length == 0 {
            return;
        }
        let mut new_span = if zoom_in {
            (span / 2).max(1)
        } else {
            span.saturating_mul(2).min(sequence_length)
        };
        if new_span == 0 {
            new_span = sequence_length;
        }
        let center_bp = center_bp.min(sequence_length.saturating_sub(1));
        let half = new_span / 2;
        let proposed_start = center_bp.saturating_sub(half);
        let max_start = sequence_length.saturating_sub(new_span);
        let new_start = proposed_start.min(max_start);
        if new_start != start || new_span != span {
            self.set_linear_viewport(new_start, new_span);
        }
    }

    fn pan_linear_viewport(&self, delta_bp: isize) {
        let (start, span, sequence_length) = self.current_linear_viewport();
        if sequence_length == 0 || span >= sequence_length || delta_bp == 0 {
            return;
        }
        let max_start = sequence_length.saturating_sub(span) as isize;
        let new_start = (start as isize + delta_bp).clamp(0, max_start) as usize;
        if new_start != start {
            self.set_linear_viewport(new_start, span);
        }
    }

    fn feature_bounds(&self, feature_id: usize) -> Option<(usize, usize)> {
        let dna = self.dna.read().expect("DNA lock poisoned");
        let feature = dna.features().get(feature_id)?;
        let (from, to) = feature.location.find_bounds().ok()?;
        if from < 0 || to < 0 {
            return None;
        }
        let seq_len = dna.len();
        if seq_len == 0 {
            return None;
        }
        let start = (from as usize).min(seq_len.saturating_sub(1));
        let end = (to as usize).min(seq_len.saturating_sub(1));
        Some((start, end))
    }

    fn sync_linear_external_feature_labels(&self) {
        self.map_dna
            .set_linear_external_labeled_feature_numbers(self.multi_selected_feature_ids.clone());
    }

    fn prune_multi_selected_feature_ids(&mut self) {
        let feature_count = self
            .dna
            .read()
            .map(|dna| dna.features().len())
            .unwrap_or_default();
        self.multi_selected_feature_ids
            .retain(|feature_id| *feature_id < feature_count);
        let next_focused = self
            .focused_feature_id
            .filter(|feature_id| self.multi_selected_feature_ids.contains(feature_id))
            .or_else(|| self.multi_selected_feature_ids.iter().next_back().copied());
        self.focused_feature_id = next_focused;
        self.map_dna.select_feature(next_focused);
        self.sync_linear_external_feature_labels();
        if next_focused.is_none() {
            self.pending_feature_tree_scroll_to = None;
            self.dna_display
                .write()
                .expect("DNA display lock poisoned")
                .deselect();
        }
    }

    fn apply_feature_selection_range(&mut self, feature_id: usize, center_linear_view: bool) {
        let Some((start, end)) = self.feature_bounds(feature_id) else {
            return;
        };
        let sequence_length = self.dna.read().expect("DNA lock poisoned").len();
        if sequence_length == 0 {
            return;
        }
        self.dna_display
            .write()
            .expect("DNA display lock poisoned")
            .select(Selection::new(start, end, sequence_length));
        self.map_sequence.request_scroll_to_selection();

        if center_linear_view && !self.is_circular() {
            let center = start.saturating_add(end.saturating_sub(start) / 2);
            let (_, span, len) = self.current_linear_viewport();
            if len > 0 {
                let span = span.clamp(1, len);
                let max_start = len.saturating_sub(span);
                let new_start = center.saturating_sub(span / 2).min(max_start);
                self.set_linear_viewport(new_start, span);
            }
        }
    }

    fn focus_feature(&mut self, feature_id: usize) {
        if self.focused_feature_id == Some(feature_id)
            && self.multi_selected_feature_ids.len() == 1
            && self.multi_selected_feature_ids.contains(&feature_id)
            && self.pending_feature_tree_scroll_to.is_none()
        {
            return;
        }
        self.focused_feature_id = Some(feature_id);
        self.multi_selected_feature_ids.clear();
        self.multi_selected_feature_ids.insert(feature_id);
        self.map_dna.select_feature(Some(feature_id));
        self.sync_linear_external_feature_labels();
        self.pending_feature_tree_scroll_to = Some(feature_id);
        self.apply_feature_selection_range(feature_id, true);
    }

    fn toggle_feature_multi_select(&mut self, feature_id: usize) {
        if self.multi_selected_feature_ids.remove(&feature_id) {
            if self.multi_selected_feature_ids.is_empty() {
                self.clear_feature_focus();
                return;
            }
            let next_focused = self
                .focused_feature_id
                .filter(|focused| self.multi_selected_feature_ids.contains(focused))
                .or_else(|| self.multi_selected_feature_ids.iter().next_back().copied());
            self.focused_feature_id = next_focused;
            self.map_dna.select_feature(next_focused);
            if let Some(next_focused) = next_focused {
                self.pending_feature_tree_scroll_to = Some(next_focused);
                self.apply_feature_selection_range(next_focused, false);
            }
            self.sync_linear_external_feature_labels();
            return;
        }

        self.multi_selected_feature_ids.insert(feature_id);
        self.focused_feature_id = Some(feature_id);
        self.map_dna.select_feature(Some(feature_id));
        self.sync_linear_external_feature_labels();
        self.pending_feature_tree_scroll_to = Some(feature_id);
        self.apply_feature_selection_range(feature_id, false);
    }

    fn array_feature_match_key(feature: &gb_io::seq::Feature) -> Option<String> {
        if !RenderDna::is_array_track_feature(feature) {
            return None;
        }
        Self::feature_tree_first_nonempty_qualifier(
            feature,
            &[
                "feature_id",
                "gentle_array_feature_id",
                "transcript_cluster_id",
                "exon_id",
            ],
        )
        .map(|value| value.trim().to_ascii_lowercase())
        .filter(|value| !value.is_empty())
    }

    fn focus_matching_array_features(&mut self, feature_id: usize) {
        let (match_key, matching_ids) = {
            let dna = self.dna.read().expect("DNA lock poisoned");
            let Some(feature) = dna.features().get(feature_id) else {
                return;
            };
            let Some(match_key) = Self::array_feature_match_key(feature) else {
                return;
            };
            let matching_ids = dna
                .features()
                .iter()
                .enumerate()
                .filter_map(|(id, candidate)| {
                    (Self::array_feature_match_key(candidate).as_deref()
                        == Some(match_key.as_str()))
                    .then_some(id)
                })
                .collect::<BTreeSet<_>>();
            (match_key, matching_ids)
        };
        if matching_ids.is_empty() {
            return;
        }
        self.focused_feature_id = Some(feature_id);
        self.multi_selected_feature_ids = matching_ids;
        self.map_dna.select_feature(Some(feature_id));
        self.sync_linear_external_feature_labels();
        self.pending_feature_tree_scroll_to = Some(feature_id);
        self.apply_feature_selection_range(feature_id, true);
        self.op_status = format!(
            "Focused {} matching array feature(s) for '{}'",
            self.multi_selected_feature_ids.len(),
            match_key
        );
    }

    fn clear_multi_select_keep_primary(&mut self) {
        if self.multi_selected_feature_ids.len() <= 1 {
            return;
        }
        let primary = self
            .focused_feature_id
            .filter(|feature_id| self.multi_selected_feature_ids.contains(feature_id))
            .or_else(|| self.multi_selected_feature_ids.iter().next_back().copied());
        let Some(primary) = primary else {
            self.clear_feature_focus();
            return;
        };
        self.multi_selected_feature_ids.clear();
        self.multi_selected_feature_ids.insert(primary);
        self.focused_feature_id = Some(primary);
        self.map_dna.select_feature(Some(primary));
        self.sync_linear_external_feature_labels();
        self.pending_feature_tree_scroll_to = Some(primary);
        self.apply_feature_selection_range(primary, false);
    }

    fn fit_feature_in_linear_view(&self, feature_id: usize) {
        if self.is_circular() {
            return;
        }
        let Some((start, end)) = self.feature_bounds(feature_id) else {
            return;
        };
        let sequence_length = self.dna.read().expect("DNA lock poisoned").len();
        if sequence_length == 0 {
            return;
        }
        let feature_span = end
            .saturating_sub(start)
            .saturating_add(1)
            .clamp(1, sequence_length);
        let padding = (feature_span / 4).max(8);
        let target_span = feature_span
            .saturating_add(padding.saturating_mul(2))
            .clamp(1, sequence_length);
        let center = start.saturating_add(feature_span / 2);
        let max_start = sequence_length.saturating_sub(target_span);
        let new_start = center.saturating_sub(target_span / 2).min(max_start);
        self.set_linear_viewport(new_start, target_span);
    }

    fn clear_feature_focus(&mut self) {
        self.focused_feature_id = None;
        self.multi_selected_feature_ids.clear();
        self.map_dna.select_reasoning_evidence(None);
        self.map_dna.select_restriction_site(None);
        self.map_dna.select_feature(None);
        self.sync_linear_external_feature_labels();
        self.pending_feature_tree_scroll_to = None;
        self.dna_display
            .write()
            .expect("DNA display lock poisoned")
            .deselect();
    }

    fn clear_feature_focus_keep_map_selection(&mut self) {
        self.focused_feature_id = None;
        self.multi_selected_feature_ids.clear();
        self.sync_linear_external_feature_labels();
        self.pending_feature_tree_scroll_to = None;
        self.dna_display
            .write()
            .expect("DNA display lock poisoned")
            .deselect();
    }

