    fn set_construct_reasoning_annotation_candidate_status(
        &mut self,
        graph_id: &str,
        annotation_id: &str,
        editable_status: EditableStatus,
    ) {
        let Some(engine) = &self.engine else {
            self.op_status =
                "Could not update annotation candidate: no engine is attached".to_string();
            return;
        };
        let outcome = engine
            .write()
            .unwrap()
            .set_construct_reasoning_annotation_candidate_status(
                graph_id,
                annotation_id,
                editable_status,
            );
        match outcome {
            Ok(graph) => {
                self.focused_construct_reasoning_graph_id = Some(graph.graph_id.clone());
                self.construct_reasoning_overlay_sync_key = None;
                self.refresh_construct_reasoning_overlay_if_needed(true);
                self.refresh_description_cache();
                self.op_status = format!(
                    "Marked annotation candidate '{}' as {}",
                    annotation_id,
                    Self::construct_reasoning_editable_status_label(editable_status)
                );
            }
            Err(err) => {
                self.op_status = format!(
                    "Could not update annotation candidate '{}': {}",
                    annotation_id, err.message
                );
            }
        }
    }

    fn write_back_construct_reasoning_annotation_candidate(
        &mut self,
        graph_id: &str,
        annotation_id: &str,
    ) {
        let Some(engine) = &self.engine else {
            self.op_status =
                "Could not write back annotation candidate: no engine is attached".to_string();
            return;
        };
        let outcome = engine
            .write()
            .unwrap()
            .write_back_construct_reasoning_annotation_candidate(graph_id, annotation_id);
        match outcome {
            Ok((graph, writeback)) => {
                self.focused_construct_reasoning_graph_id = Some(graph.graph_id.clone());
                self.construct_reasoning_overlay_sync_key = None;
                self.refresh_construct_reasoning_overlay_if_needed(true);
                self.refresh_description_cache();
                if writeback.created {
                    self.op_status = format!(
                        "Wrote back annotation candidate '{}' as feature '{}' on '{}'",
                        annotation_id, writeback.feature_kind, writeback.seq_id
                    );
                } else if writeback.already_present {
                    self.op_status = format!(
                        "Annotation candidate '{}' is already represented as a sequence feature",
                        annotation_id
                    );
                } else {
                    self.op_status = format!(
                        "No feature was written back for annotation candidate '{}'",
                        annotation_id
                    );
                }
            }
            Err(err) => {
                self.op_status = format!(
                    "Could not write back annotation candidate '{}': {}",
                    annotation_id, err.message
                );
            }
        }
    }

    fn render_construct_reasoning_annotation_candidate_actions(
        &mut self,
        ui: &mut egui::Ui,
        graph_id: &str,
        annotation_id: &str,
        editable_status: EditableStatus,
        source_kind: &str,
    ) -> Option<EditableStatus> {
        let status_mutable = editable_status != EditableStatus::Locked;
        if editable_status == EditableStatus::Locked {
            ui.small("This annotation candidate is locked.");
        }
        let mut next_status: Option<EditableStatus> = None;
        ui.horizontal_wrapped(|ui| {
            let accept_label = if editable_status == EditableStatus::Accepted {
                "Accepted"
            } else {
                "Accept"
            };
            if ui
                .add_enabled(
                    status_mutable && editable_status != EditableStatus::Accepted,
                    egui::Button::new(accept_label),
                )
                .on_hover_text(
                    "Mark this annotation candidate as accepted so it stands out as a reviewed automated annotation.",
                )
                .clicked()
            {
                next_status = Some(EditableStatus::Accepted);
            }
            let reject_label = if editable_status == EditableStatus::Rejected {
                "Rejected"
            } else {
                "Reject"
            };
            if ui
                .add_enabled(
                    status_mutable && editable_status != EditableStatus::Rejected,
                    egui::Button::new(reject_label),
                )
                .on_hover_text(
                    "Mark this annotation candidate as rejected so it remains inspectable but clearly not endorsed as an automated annotation.",
                )
                .clicked()
            {
                next_status = Some(EditableStatus::Rejected);
            }
            if ui
                .add_enabled(
                    status_mutable && editable_status != EditableStatus::Draft,
                    egui::Button::new("Mark Draft"),
                )
                .on_hover_text(
                    "Reset this annotation candidate back to draft when it still needs review.",
                )
                .clicked()
            {
                next_status = Some(EditableStatus::Draft);
            }
            let writeback_enabled = matches!(
                editable_status,
                EditableStatus::Accepted | EditableStatus::Locked
            ) && source_kind.trim() == "generated_annotation";
            if ui
                .add_enabled(writeback_enabled, egui::Button::new("Write Back"))
                .on_hover_text(
                    "Write this accepted generated annotation candidate back as an ordinary sequence feature.",
                )
                .clicked()
            {
                self.write_back_construct_reasoning_annotation_candidate(graph_id, annotation_id);
            }
        });
        if let Some(next_status) = next_status {
            self.set_construct_reasoning_annotation_candidate_status(
                graph_id,
                annotation_id,
                next_status,
            );
            return Some(next_status);
        }
        None
    }

    fn render_construct_reasoning_dotplot_actions(
        &mut self,
        ui: &mut egui::Ui,
        actions: &[ConstructReasoningDotplotAction],
    ) {
        if actions.is_empty() {
            return;
        }
        ui.horizontal_wrapped(|ui| {
            for action in actions {
                ui.push_id(
                    ("construct_reasoning_dotplot_action", &action.stable_id),
                    |ui| {
                        if ui
                            .button(action.button_label.as_str())
                            .on_hover_text(action.hover_text.as_str())
                            .clicked()
                        {
                            match self.open_construct_reasoning_dotplot_action(action) {
                                Ok(()) => self.focus_dotplot_workspace_view(ui.ctx()),
                                Err(err) => self.op_status = err,
                            }
                        }
                    },
                );
            }
        });
    }

