    fn construct_reasoning_json_string_list(value: &serde_json::Value, key: &str) -> Vec<String> {
        value
            .get(key)
            .and_then(serde_json::Value::as_array)
            .map(|rows| {
                rows.iter()
                    .filter_map(serde_json::Value::as_str)
                    .map(|value| value.to_string())
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default()
    }

    fn construct_reasoning_json_signal_labels(value: &serde_json::Value, key: &str) -> Vec<String> {
        value
            .get(key)
            .and_then(serde_json::Value::as_array)
            .map(|rows| {
                rows.iter()
                    .filter_map(|row| {
                        row.get("label")
                            .or_else(|| row.get("token"))
                            .and_then(serde_json::Value::as_str)
                            .map(|value| value.to_string())
                    })
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default()
    }

    fn construct_reasoning_inspector_entry_for_fact(
        graph: &ConstructReasoningGraph,
        fact: &DesignFact,
    ) -> ConstructReasoningInspectorEntry {
        let mut detail_lines = vec![];
        let mut warning_lines = vec![];
        if let Some(status) = fact
            .value_json
            .get("status")
            .and_then(serde_json::Value::as_str)
        {
            detail_lines.push(format!("status: {status}"));
            if status == "review_needed" {
                warning_lines.push("Review needed".to_string());
            }
        }
        if !fact.rationale.trim().is_empty() {
            detail_lines.push(format!("why: {}", fact.rationale.trim()));
        }
        if !fact.based_on_evidence_ids.is_empty() {
            detail_lines.push(format!(
                "based_on_evidence: {}",
                fact.based_on_evidence_ids.len()
            ));
        }
        match fact.fact_type.as_str() {
            "host_transition_context" => {
                let ordered_hosts = Self::construct_reasoning_json_string_list(
                    &fact.value_json,
                    "ordered_host_profile_ids",
                );
                if !ordered_hosts.is_empty() {
                    detail_lines.push(format!("hosts: {}", ordered_hosts.join(" -> ")));
                }
            }
            "growth_condition_context" => {
                let medium_conditions = Self::construct_reasoning_json_string_list(
                    &fact.value_json,
                    "medium_conditions",
                );
                if !medium_conditions.is_empty() {
                    detail_lines.push(format!(
                        "medium_conditions: {}",
                        medium_conditions.join(", ")
                    ));
                }
                let signals = Self::construct_reasoning_json_signal_labels(
                    &fact.value_json,
                    "condition_signals",
                );
                if !signals.is_empty() {
                    detail_lines.push(format!("signals: {}", signals.join(", ")));
                }
            }
            "helper_context" => {
                if let Some(helper_profile_id) = fact
                    .value_json
                    .get("helper_profile_id")
                    .and_then(serde_json::Value::as_str)
                {
                    detail_lines.push(format!("helper_profile: {helper_profile_id}"));
                }
                let helper_functions = Self::construct_reasoning_json_string_list(
                    &fact.value_json,
                    "helper_offered_functions",
                );
                if !helper_functions.is_empty() {
                    detail_lines.push(format!(
                        "offered_functions: {}",
                        helper_functions.join(", ")
                    ));
                }
                let helper_components = Self::construct_reasoning_json_string_list(
                    &fact.value_json,
                    "helper_component_labels",
                );
                if !helper_components.is_empty() {
                    detail_lines.push(format!("components: {}", helper_components.join(", ")));
                }
            }
            "host_restriction_methylation_context" => {
                if let Some(patterns) = fact.value_json.get("sequence_pattern_counts") {
                    let dam_count = patterns
                        .get("dam_site_count")
                        .and_then(serde_json::Value::as_u64)
                        .unwrap_or(0);
                    let dcm_count = patterns
                        .get("dcm_site_count")
                        .and_then(serde_json::Value::as_u64)
                        .unwrap_or(0);
                    let eco_k_count = patterns
                        .get("eco_k_target_site_count")
                        .and_then(serde_json::Value::as_u64)
                        .unwrap_or(0);
                    detail_lines.push(format!(
                        "sequence_patterns: dam={dam_count}, dcm={dcm_count}, eco_k_like={eco_k_count}"
                    ));
                }
                let route_steps = fact
                    .value_json
                    .get("route_step_signals")
                    .and_then(serde_json::Value::as_array)
                    .map(|rows| {
                        rows.iter()
                            .filter_map(|row| {
                                let step_id =
                                    row.get("step_id").and_then(serde_json::Value::as_str)?;
                                let traits = row
                                    .get("trait_tokens")
                                    .and_then(serde_json::Value::as_array)
                                    .map(|values| {
                                        values
                                            .iter()
                                            .filter_map(serde_json::Value::as_str)
                                            .collect::<Vec<_>>()
                                    })
                                    .unwrap_or_default();
                                Some(if traits.is_empty() {
                                    step_id.to_string()
                                } else {
                                    format!("{step_id}: {}", traits.join(", "))
                                })
                            })
                            .collect::<Vec<_>>()
                    })
                    .unwrap_or_default();
                if !route_steps.is_empty() {
                    detail_lines.push(format!("route_steps: {}", route_steps.join(" | ")));
                }
                let conflicts = fact
                    .value_json
                    .get("detected_conflicts")
                    .and_then(serde_json::Value::as_array)
                    .map(|rows| {
                        rows.iter()
                            .filter_map(|row| {
                                row.get("label")
                                    .and_then(serde_json::Value::as_str)
                                    .map(|value| value.to_string())
                            })
                            .collect::<Vec<_>>()
                    })
                    .unwrap_or_default();
                if !conflicts.is_empty() {
                    detail_lines.push(format!("conflicts: {}", conflicts.join(", ")));
                    warning_lines.extend(conflicts);
                }
            }
            "adapter_restriction_capture_context" => {
                let capture_rows = fact
                    .value_json
                    .get("capture_plans")
                    .and_then(serde_json::Value::as_array)
                    .map(|rows| {
                        rows.iter()
                            .filter_map(|row| {
                                let capture_id =
                                    row.get("capture_id").and_then(serde_json::Value::as_str)?;
                                let enzyme = row
                                    .get("restriction_enzyme_name")
                                    .and_then(serde_json::Value::as_str)
                                    .unwrap_or("enzyme");
                                let status = row
                                    .get("internal_site_status")
                                    .and_then(serde_json::Value::as_str)
                                    .unwrap_or("unspecified");
                                let count = row
                                    .get("internal_site_count")
                                    .and_then(serde_json::Value::as_u64)
                                    .unwrap_or(0);
                                Some(format!(
                                    "{capture_id}: {enzyme} ({status}, internal_sites={count})"
                                ))
                            })
                            .collect::<Vec<_>>()
                    })
                    .unwrap_or_default();
                if !capture_rows.is_empty() {
                    detail_lines.push(format!("capture_plans: {}", capture_rows.join(" | ")));
                }
                let motif_rows = fact
                    .value_json
                    .get("capture_plans")
                    .and_then(serde_json::Value::as_array)
                    .map(|rows| {
                        rows.iter()
                            .filter_map(|row| {
                                let capture_id = row
                                    .get("capture_id")
                                    .and_then(serde_json::Value::as_str)
                                    .unwrap_or("capture");
                                let motifs = row
                                    .get("motif_summaries")
                                    .and_then(serde_json::Value::as_array)
                                    .map(|entries| {
                                        entries
                                            .iter()
                                            .filter_map(|entry| {
                                                let enzyme = entry
                                                    .get("enzyme_name")
                                                    .and_then(serde_json::Value::as_str)?;
                                                let role = entry
                                                    .get("motif_role")
                                                    .and_then(serde_json::Value::as_str)
                                                    .unwrap_or("motif");
                                                let status = entry
                                                    .get("internal_site_status")
                                                    .and_then(serde_json::Value::as_str)
                                                    .unwrap_or("unspecified");
                                                let count = entry
                                                    .get("internal_site_count")
                                                    .and_then(serde_json::Value::as_u64)
                                                    .unwrap_or(0);
                                                Some(format!(
                                                    "{role}:{enzyme} ({status}, internal_sites={count})"
                                                ))
                                            })
                                            .collect::<Vec<_>>()
                                            .join(", ")
                                    })
                                    .unwrap_or_default();
                                (!motifs.is_empty()).then(|| format!("{capture_id}: {motifs}"))
                            })
                            .collect::<Vec<_>>()
                    })
                    .unwrap_or_default();
                if !motif_rows.is_empty() {
                    detail_lines.push(format!("motifs: {}", motif_rows.join(" | ")));
                }
                let all_present = fact
                    .value_json
                    .get("capture_plans")
                    .and_then(serde_json::Value::as_array)
                    .map(|rows| {
                        rows.iter()
                            .filter_map(|row| {
                                let capture_id =
                                    row.get("capture_id").and_then(serde_json::Value::as_str)?;
                                let all_present = row
                                    .get("all_named_motifs_present_on_insert")
                                    .and_then(serde_json::Value::as_bool)
                                    .unwrap_or(false);
                                all_present
                                    .then(|| format!("{capture_id}: all_named_motifs_present"))
                            })
                            .collect::<Vec<_>>()
                    })
                    .unwrap_or_default();
                if !all_present.is_empty() {
                    detail_lines.push(format!("aggregate: {}", all_present.join(" | ")));
                }
                let review_items = fact
                    .value_json
                    .get("review_items")
                    .and_then(serde_json::Value::as_array)
                    .map(|rows| {
                        rows.iter()
                            .filter_map(|row| {
                                row.get("label")
                                    .and_then(serde_json::Value::as_str)
                                    .map(|value| value.to_string())
                            })
                            .collect::<Vec<_>>()
                    })
                    .unwrap_or_default();
                if !review_items.is_empty() {
                    detail_lines.push(format!("review: {}", review_items.join(", ")));
                    warning_lines.extend(review_items);
                }
            }
            "sequence_complexity_context" => {
                let low_complexity = fact
                    .value_json
                    .get("low_complexity_region_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                let homopolymers = fact
                    .value_json
                    .get("homopolymer_run_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                let tandem = fact
                    .value_json
                    .get("tandem_repeat_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                detail_lines.push(format!(
                    "counts: low_complexity={low_complexity}, homopolymers={homopolymers}, tandem_repeats={tandem}"
                ));
                let labels = Self::construct_reasoning_json_string_list(&fact.value_json, "labels");
                if !labels.is_empty() {
                    detail_lines.push(format!("regions: {}", labels.join(", ")));
                }
                let homopolymer_labels = Self::construct_reasoning_json_string_list(
                    &fact.value_json,
                    "homopolymer_labels",
                );
                if !homopolymer_labels.is_empty() {
                    detail_lines.push(format!("homopolymers: {}", homopolymer_labels.join(", ")));
                }
                let tandem_labels = Self::construct_reasoning_json_string_list(
                    &fact.value_json,
                    "tandem_repeat_labels",
                );
                if !tandem_labels.is_empty() {
                    detail_lines.push(format!("tandem: {}", tandem_labels.join(", ")));
                }
            }
            "repeat_architecture_context" => {
                let direct = fact
                    .value_json
                    .get("direct_repeat_cluster_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                let inverted = fact
                    .value_json
                    .get("inverted_repeat_cluster_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                detail_lines.push(format!("clusters: direct={direct}, inverted={inverted}"));
                let direct_labels = Self::construct_reasoning_json_string_list(
                    &fact.value_json,
                    "direct_repeat_labels",
                );
                if !direct_labels.is_empty() {
                    detail_lines.push(format!("direct: {}", direct_labels.join(", ")));
                }
                let inverted_labels = Self::construct_reasoning_json_string_list(
                    &fact.value_json,
                    "inverted_repeat_labels",
                );
                if !inverted_labels.is_empty() {
                    detail_lines.push(format!("inverted: {}", inverted_labels.join(", ")));
                }
            }
            "mobile_element_context" => {
                let mobile = fact
                    .value_json
                    .get("mobile_element_candidate_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                let alu_like = fact
                    .value_json
                    .get("alu_like_candidate_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                detail_lines.push(format!(
                    "candidates: mobile_elements={mobile}, alu_like={alu_like}"
                ));
                let labels = Self::construct_reasoning_json_string_list(&fact.value_json, "labels");
                if !labels.is_empty() {
                    detail_lines.push(format!("labels: {}", labels.join(", ")));
                }
                if alu_like > 0 {
                    warning_lines.push(
                        "Alu-like calls are still heuristic until a curated repeat-family catalog is integrated"
                            .to_string(),
                    );
                }
            }
            "similarity_operational_risk_context" => {
                let slippage = fact
                    .value_json
                    .get("polymerase_slippage_risk_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                let mapping = fact
                    .value_json
                    .get("mapping_ambiguity_risk_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                let inversion = fact
                    .value_json
                    .get("inversion_risk_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                let cloning = fact
                    .value_json
                    .get("cloning_stability_risk_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                detail_lines.push(format!(
                    "risks: slippage={slippage}, mapping={mapping}, inversion={inversion}, cloning={cloning}"
                ));
                if inversion > 0 {
                    warning_lines.push(
                        "Inverted-repeat evidence suggests localized inversion/recombination review"
                            .to_string(),
                    );
                }
                if slippage > 0 {
                    warning_lines.push(
                        "Low-complexity/tandem-repeat evidence suggests polymerase slippage review"
                            .to_string(),
                    );
                }
            }
            "pcr_operational_risk_context" => {
                let low_complexity = fact
                    .value_json
                    .get("low_complexity_region_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                let homopolymers = fact
                    .value_json
                    .get("homopolymer_run_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                let tandem = fact
                    .value_json
                    .get("tandem_repeat_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                let slippage = fact
                    .value_json
                    .get("polymerase_slippage_risk_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                detail_lines.push(format!(
                    "pcr_review: low_complexity={low_complexity}, homopolymers={homopolymers}, tandem={tandem}, slippage={slippage}"
                ));
                let labels =
                    Self::construct_reasoning_json_string_list(&fact.value_json, "slippage_labels");
                if !labels.is_empty() {
                    detail_lines.push(format!("slippage_regions: {}", labels.join(", ")));
                }
                if homopolymers > 0 || tandem > 0 {
                    warning_lines.push(
                        "Repeated or homopolymer-rich sequence suggests PCR/amplification review"
                            .to_string(),
                    );
                }
            }
            "nanopore_operational_risk_context" => {
                let signal = fact
                    .value_json
                    .get("nanopore_signal_risk_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                let homopolymer = fact
                    .value_json
                    .get("nanopore_homopolymer_risk_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                detail_lines.push(format!(
                    "nanopore_review: signal_risk={signal}, homopolymer_risk={homopolymer}"
                ));
                let labels =
                    Self::construct_reasoning_json_string_list(&fact.value_json, "signal_labels");
                if !labels.is_empty() {
                    detail_lines.push(format!("signal_regions: {}", labels.join(", ")));
                }
                if homopolymer > 0 {
                    warning_lines.push(
                        "Homopolymer-rich sequence suggests nanopore/direct-sequencing review"
                            .to_string(),
                    );
                }
            }
            "mapping_operational_risk_context" => {
                let mapping = fact
                    .value_json
                    .get("mapping_ambiguity_risk_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                let mobile = fact
                    .value_json
                    .get("mobile_element_candidate_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                detail_lines.push(format!(
                    "mapping_review: repeat_ambiguity={mapping}, mobile_elements={mobile}"
                ));
                let mapping_labels =
                    Self::construct_reasoning_json_string_list(&fact.value_json, "mapping_labels");
                if !mapping_labels.is_empty() {
                    detail_lines.push(format!("mapping_regions: {}", mapping_labels.join(", ")));
                }
                let mobile_labels = Self::construct_reasoning_json_string_list(
                    &fact.value_json,
                    "mobile_element_labels",
                );
                if !mobile_labels.is_empty() {
                    detail_lines.push(format!("mobile_elements: {}", mobile_labels.join(", ")));
                }
                if mobile > 0 {
                    warning_lines.push(
                        "Repeat-family/mobile-element context suggests mapping ambiguity review"
                            .to_string(),
                    );
                }
            }
            "cloning_stability_context" => {
                let inversion = fact
                    .value_json
                    .get("inversion_risk_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                let cloning = fact
                    .value_json
                    .get("cloning_stability_risk_count")
                    .and_then(serde_json::Value::as_u64)
                    .unwrap_or(0);
                detail_lines.push(format!(
                    "cloning_review: inversion={inversion}, stability={cloning}"
                ));
                let inversion_labels = Self::construct_reasoning_json_string_list(
                    &fact.value_json,
                    "inversion_labels",
                );
                if !inversion_labels.is_empty() {
                    detail_lines.push(format!(
                        "inversion_regions: {}",
                        inversion_labels.join(", ")
                    ));
                }
                let cloning_labels =
                    Self::construct_reasoning_json_string_list(&fact.value_json, "cloning_labels");
                if !cloning_labels.is_empty() {
                    detail_lines.push(format!("cloning_regions: {}", cloning_labels.join(", ")));
                }
                if inversion > 0 {
                    warning_lines.push(
                        "Inverted-repeat evidence suggests inversion/recombination review"
                            .to_string(),
                    );
                }
            }
            "selection_context" => {
                let candidates = Self::construct_reasoning_json_string_list(
                    &fact.value_json,
                    "selection_candidates",
                );
                if !candidates.is_empty() {
                    detail_lines.push(format!("candidates: {}", candidates.join(", ")));
                }
                let rules = fact
                    .value_json
                    .get("selection_rule_matches")
                    .and_then(serde_json::Value::as_array)
                    .map(|rows| {
                        rows.iter()
                            .filter_map(|row| {
                                let rule_id =
                                    row.get("rule_id").and_then(serde_json::Value::as_str)?;
                                let status =
                                    row.get("status").and_then(serde_json::Value::as_str)?;
                                Some(format!("{rule_id} ({status})"))
                            })
                            .collect::<Vec<_>>()
                    })
                    .unwrap_or_default();
                if !rules.is_empty() {
                    detail_lines.push(format!("rules: {}", rules.join(", ")));
                }
            }
            "variant_effect_context" => {
                let variant_labels =
                    Self::construct_reasoning_json_string_list(&fact.value_json, "variant_labels");
                if !variant_labels.is_empty() {
                    detail_lines.push(format!("variants: {}", variant_labels.join(", ")));
                }
                let effect_tags =
                    Self::construct_reasoning_json_string_list(&fact.value_json, "effect_tags");
                if !effect_tags.is_empty() {
                    detail_lines.push(format!("effect_tags: {}", effect_tags.join(", ")));
                }
                let transcript_rows = fact
                    .value_json
                    .get("variants")
                    .and_then(serde_json::Value::as_array)
                    .map(|rows| {
                        rows.iter()
                            .filter_map(|row| {
                                let label = row.get("label").and_then(serde_json::Value::as_str)?;
                                let status = row
                                    .get("transcript_context_status")
                                    .and_then(serde_json::Value::as_str)
                                    .unwrap_or("unspecified");
                                Some(format!("{label} ({status})"))
                            })
                            .collect::<Vec<_>>()
                    })
                    .unwrap_or_default();
                if !transcript_rows.is_empty() {
                    detail_lines.push(format!(
                        "transcript_context: {}",
                        transcript_rows.join(" | ")
                    ));
                }
                let transcript_effects = fact
                    .value_json
                    .get("variants")
                    .and_then(serde_json::Value::as_array)
                    .map(|rows| {
                        rows.iter()
                            .flat_map(|row| {
                                let variant_label = row
                                    .get("label")
                                    .and_then(serde_json::Value::as_str)
                                    .unwrap_or("variant");
                                row.get("transcript_effect_summaries")
                                    .and_then(serde_json::Value::as_array)
                                    .into_iter()
                                    .flatten()
                                    .filter_map(move |summary| {
                                        let transcript_label = summary
                                            .get("transcript_label")
                                            .and_then(serde_json::Value::as_str)?;
                                        let effect_tags = summary
                                            .get("effect_tags")
                                            .and_then(serde_json::Value::as_array)
                                            .map(|tags| {
                                                tags.iter()
                                                    .filter_map(serde_json::Value::as_str)
                                                    .collect::<Vec<_>>()
                                                    .join(", ")
                                            })
                                            .unwrap_or_default();
                                        Some(format!(
                                            "{variant_label} -> {transcript_label}: {effect_tags}"
                                        ))
                                    })
                            })
                            .collect::<Vec<_>>()
                    })
                    .unwrap_or_default();
                if !transcript_effects.is_empty() {
                    detail_lines.push(format!(
                        "transcript_effects: {}",
                        transcript_effects.join(" | ")
                    ));
                }
            }
            "variant_assay_context" => {
                let variant_labels =
                    Self::construct_reasoning_json_string_list(&fact.value_json, "variant_labels");
                if !variant_labels.is_empty() {
                    detail_lines.push(format!("variants: {}", variant_labels.join(", ")));
                }
                let assay_ids = Self::construct_reasoning_json_string_list(
                    &fact.value_json,
                    "suggested_assay_ids",
                );
                if !assay_ids.is_empty() {
                    detail_lines.push(format!("assays: {}", assay_ids.join(", ")));
                }
                let assay_map = fact
                    .value_json
                    .get("variant_assay_map")
                    .and_then(serde_json::Value::as_array)
                    .map(|rows| {
                        rows.iter()
                            .filter_map(|row| {
                                let label = row.get("label").and_then(serde_json::Value::as_str)?;
                                let assays = row
                                    .get("suggested_assay_ids")
                                    .and_then(serde_json::Value::as_array)
                                    .map(|entries| {
                                        entries
                                            .iter()
                                            .filter_map(serde_json::Value::as_str)
                                            .collect::<Vec<_>>()
                                            .join(", ")
                                    })
                                    .unwrap_or_default();
                                Some(format!("{label}: {assays}"))
                            })
                            .collect::<Vec<_>>()
                    })
                    .unwrap_or_default();
                if !assay_map.is_empty() {
                    detail_lines.push(format!("per_variant: {}", assay_map.join(" | ")));
                }
            }
            _ => {}
        }
        ConstructReasoningInspectorEntry {
            stable_id: if fact.fact_id.trim().is_empty() {
                fact.label.clone()
            } else {
                fact.fact_id.clone()
            },
            title: fact.label.clone(),
            detail_lines,
            warning_lines,
            annotation_id: None,
            editable_status: None,
            source_kind: None,
            dotplot_actions: Self::construct_reasoning_dotplot_actions_for_fact(graph, fact),
        }
    }

    fn construct_reasoning_inspector_entry_for_decision(
        node: &DesignDecisionNode,
    ) -> ConstructReasoningInspectorEntry {
        let mut detail_lines = vec![format!(
            "method: {}",
            Self::construct_reasoning_decision_method_label(node.method)
        )];
        if !node.rationale.trim().is_empty() {
            detail_lines.push(format!("why: {}", node.rationale.trim()));
        }
        if !node.input_fact_ids.is_empty() {
            detail_lines.push(format!("input_facts: {}", node.input_fact_ids.join(", ")));
        }
        if !node.output_fact_ids.is_empty() {
            detail_lines.push(format!("output_facts: {}", node.output_fact_ids.join(", ")));
        }
        ConstructReasoningInspectorEntry {
            stable_id: if node.decision_id.trim().is_empty() {
                node.title.clone()
            } else {
                node.decision_id.clone()
            },
            title: node.title.clone(),
            detail_lines,
            warning_lines: vec![],
            annotation_id: None,
            editable_status: None,
            source_kind: None,
            dotplot_actions: vec![],
        }
    }

    fn construct_reasoning_inspector_entry_for_annotation_summary(
        summary: &AnnotationCandidateSummary,
    ) -> ConstructReasoningInspectorEntry {
        let mut detail_lines = vec![
            format!(
                "role: {}",
                Self::construct_reasoning_role_label(summary.role)
            ),
            format!("collapsed_candidates: {}", summary.candidate_count),
        ];
        if !summary.subtitle.trim().is_empty() {
            detail_lines.push(format!("summary: {}", summary.subtitle.trim()));
        }
        if !summary.review_status_summary.trim().is_empty() {
            detail_lines.push(format!(
                "review_status: {}",
                summary.review_status_summary.trim()
            ));
        }
        if !summary.source_kinds.is_empty() {
            detail_lines.push(format!("sources: {}", summary.source_kinds.join(", ")));
        }
        if !summary.transcript_context_statuses.is_empty() {
            detail_lines.push(format!(
                "transcript_contexts: {}",
                summary.transcript_context_statuses.join(", ")
            ));
        }
        if !summary.effect_tags.is_empty() {
            detail_lines.push(format!("effect_tags: {}", summary.effect_tags.join(", ")));
        }
        if !summary.supporting_fact_labels.is_empty() {
            detail_lines.push(format!(
                "supports_facts: {}",
                summary.supporting_fact_labels.join(", ")
            ));
        }
        if !summary.supporting_decision_titles.is_empty() {
            detail_lines.push(format!(
                "supports_decisions: {}",
                summary.supporting_decision_titles.join(", ")
            ));
        }
        if !summary.annotation_ids.is_empty() {
            detail_lines.push(format!(
                "annotation_ids: {}",
                summary.annotation_ids.join(", ")
            ));
        }
        let mut warning_lines = summary.warnings.clone();
        if summary
            .transcript_context_statuses
            .iter()
            .any(|status| status == "multi_transcript_ambiguous")
        {
            warning_lines.push("Transcript interpretations remain ambiguous".to_string());
        }
        ConstructReasoningInspectorEntry {
            stable_id: if summary.summary_id.trim().is_empty() {
                summary.title.clone()
            } else {
                summary.summary_id.clone()
            },
            title: summary.title.clone(),
            detail_lines,
            warning_lines,
            annotation_id: None,
            editable_status: None,
            source_kind: None,
            dotplot_actions: Self::construct_reasoning_dotplot_actions_for_range(
                if summary.summary_id.trim().is_empty() {
                    summary.title.as_str()
                } else {
                    summary.summary_id.as_str()
                },
                summary.title.as_str(),
                summary.role,
                summary.start_0based,
                summary.end_0based_exclusive,
                &[],
            ),
        }
    }

    fn construct_reasoning_inspector_entry_for_annotation_candidate(
        candidate: &AnnotationCandidate,
    ) -> ConstructReasoningInspectorEntry {
        let mut detail_lines = vec![
            format!(
                "role: {}",
                Self::construct_reasoning_role_label(candidate.role)
            ),
            format!(
                "status: {}",
                Self::construct_reasoning_editable_status_label(candidate.editable_status)
            ),
        ];
        if !candidate.source_kind.trim().is_empty() {
            detail_lines.push(format!("source: {}", candidate.source_kind.trim()));
        }
        if !candidate.rationale.trim().is_empty() {
            detail_lines.push(format!("why: {}", candidate.rationale.trim()));
        }
        if !candidate.supporting_fact_labels.is_empty() {
            detail_lines.push(format!(
                "supports_facts: {}",
                candidate.supporting_fact_labels.join(", ")
            ));
        }
        if !candidate.supporting_decision_titles.is_empty() {
            detail_lines.push(format!(
                "supports_decisions: {}",
                candidate.supporting_decision_titles.join(", ")
            ));
        }
        if let Some(status) = candidate.transcript_context_status.as_deref() {
            detail_lines.push(format!("transcript_context: {status}"));
        }
        if !candidate.effect_tags.is_empty() {
            detail_lines.push(format!("effect_tags: {}", candidate.effect_tags.join(", ")));
        }
        let mut warning_lines = candidate.warnings.clone();
        if candidate.transcript_context_status.as_deref() == Some("multi_transcript_ambiguous") {
            warning_lines.push("Transcript interpretation remains ambiguous".to_string());
        }
        ConstructReasoningInspectorEntry {
            stable_id: if candidate.annotation_id.trim().is_empty() {
                if candidate.label.trim().is_empty() {
                    Self::construct_reasoning_role_label(candidate.role).to_string()
                } else {
                    candidate.label.clone()
                }
            } else {
                candidate.annotation_id.clone()
            },
            title: if candidate.label.trim().is_empty() {
                Self::construct_reasoning_role_label(candidate.role).to_string()
            } else {
                candidate.label.clone()
            },
            detail_lines,
            warning_lines,
            annotation_id: Some(candidate.annotation_id.clone()),
            editable_status: Some(candidate.editable_status),
            source_kind: Some(candidate.source_kind.clone()),
            dotplot_actions: Self::construct_reasoning_dotplot_actions_for_range(
                if candidate.annotation_id.trim().is_empty() {
                    if candidate.label.trim().is_empty() {
                        Self::construct_reasoning_role_label(candidate.role)
                    } else {
                        candidate.label.as_str()
                    }
                } else {
                    candidate.annotation_id.as_str()
                },
                if candidate.label.trim().is_empty() {
                    Self::construct_reasoning_role_label(candidate.role)
                } else {
                    candidate.label.as_str()
                },
                candidate.role,
                candidate.start_0based,
                candidate.end_0based_exclusive,
                &[],
            ),
        }
    }

    fn build_construct_reasoning_inspector_cache(
        graph: &ConstructReasoningGraph,
    ) -> ConstructReasoningInspectorCache {
        let mut annotation_summary_entries = graph
            .annotation_candidate_summaries
            .iter()
            .map(Self::construct_reasoning_inspector_entry_for_annotation_summary)
            .collect::<Vec<_>>();
        let mut annotation_entries = graph
            .annotation_candidates
            .iter()
            .map(Self::construct_reasoning_inspector_entry_for_annotation_candidate)
            .collect::<Vec<_>>();
        let mut fact_entries = graph
            .facts
            .iter()
            .map(|fact| Self::construct_reasoning_inspector_entry_for_fact(graph, fact))
            .collect::<Vec<_>>();
        let mut decision_entries = graph
            .decisions
            .iter()
            .map(Self::construct_reasoning_inspector_entry_for_decision)
            .collect::<Vec<_>>();
        annotation_summary_entries.retain(|entry| !entry.title.trim().is_empty());
        annotation_entries.retain(|entry| !entry.title.trim().is_empty());
        fact_entries.retain(|entry| !entry.title.trim().is_empty());
        decision_entries.retain(|entry| !entry.title.trim().is_empty());
        ConstructReasoningInspectorCache {
            graph_id: graph.graph_id.clone(),
            objective_title: graph.objective.title.clone(),
            objective_goal: graph.objective.goal.clone(),
            annotation_summary_entries,
            annotation_entries,
            fact_entries,
            decision_entries,
            note_lines: graph.notes.clone(),
        }
    }

    fn construct_reasoning_dotplot_title_has_inverted_signal(title: &str) -> bool {
        let lower = title.trim().to_ascii_lowercase();
        lower.contains("inverted")
            || lower.contains("palindromic")
            || lower.contains("inversion")
            || lower.contains("revcomp")
    }

    fn construct_reasoning_dotplot_should_offer_forward(
        role: ConstructRole,
        title: &str,
        context_tags: &[String],
    ) -> bool {
        role == ConstructRole::MobileElement
            || context_tags.iter().any(|tag| {
                matches!(
                    tag.as_str(),
                    "low_complexity"
                        | "homopolymer_run"
                        | "tandem_repeat"
                        | "direct_repeat"
                        | "repeat_dense"
                        | "mapping_ambiguity_risk"
                        | "polymerase_slippage_risk"
                        | "alu_like"
                )
            })
            || title.trim().to_ascii_lowercase().contains("direct")
            || title.trim().to_ascii_lowercase().contains("tandem")
            || title.trim().to_ascii_lowercase().contains("low-complexity")
            || title.trim().to_ascii_lowercase().contains("homopolymer")
            || title.trim().to_ascii_lowercase().contains("alu")
            || title.trim().to_ascii_lowercase().contains("mobile")
    }

    fn construct_reasoning_dotplot_should_offer_revcomp(
        title: &str,
        context_tags: &[String],
    ) -> bool {
        context_tags.iter().any(|tag| {
            matches!(
                tag.as_str(),
                "inverted_repeat" | "palindromic_repeat_risk" | "inversion_risk"
            )
        }) || Self::construct_reasoning_dotplot_title_has_inverted_signal(title)
    }

    fn construct_reasoning_dotplot_actions_for_range(
        stable_id: &str,
        title: &str,
        role: ConstructRole,
        start_0based: usize,
        end_0based_exclusive: usize,
        context_tags: &[String],
    ) -> Vec<ConstructReasoningDotplotAction> {
        if end_0based_exclusive <= start_0based {
            return vec![];
        }
        let mut actions = vec![];
        let start_1based = start_0based.saturating_add(1);
        let end_1based = end_0based_exclusive;
        if Self::construct_reasoning_dotplot_should_offer_forward(role, title, context_tags) {
            actions.push(ConstructReasoningDotplotAction {
                stable_id: format!("{stable_id}:dotplot:self_forward"),
                button_label: "Dotplot".to_string(),
                hover_text: format!(
                    "Open a self-forward dotplot centered on {start_1based}..{end_1based} for '{title}'"
                ),
                mode: DotplotMode::SelfForward,
                focus_start_0based: start_0based,
                focus_end_0based_exclusive: end_0based_exclusive,
            });
        }
        if Self::construct_reasoning_dotplot_should_offer_revcomp(title, context_tags) {
            actions.push(ConstructReasoningDotplotAction {
                stable_id: format!("{stable_id}:dotplot:self_revcomp"),
                button_label: "RevComp Dotplot".to_string(),
                hover_text: format!(
                    "Open a self-reverse-complement dotplot centered on {start_1based}..{end_1based} for '{title}'"
                ),
                mode: DotplotMode::SelfReverseComplement,
                focus_start_0based: start_0based,
                focus_end_0based_exclusive: end_0based_exclusive,
            });
        }
        actions
    }

    fn construct_reasoning_dotplot_actions_for_fact(
        graph: &ConstructReasoningGraph,
        fact: &DesignFact,
    ) -> Vec<ConstructReasoningDotplotAction> {
        let rows = graph
            .evidence
            .iter()
            .filter(|row| {
                row.scope == crate::engine::EvidenceScope::SequenceSpan
                    && fact
                        .based_on_evidence_ids
                        .iter()
                        .any(|evidence_id| evidence_id == &row.evidence_id)
                    && row.end_0based_exclusive > row.start_0based
            })
            .collect::<Vec<_>>();
        if rows.is_empty() {
            return vec![];
        }
        let focus_start_0based = rows
            .iter()
            .map(|row| row.start_0based)
            .min()
            .unwrap_or_default();
        let focus_end_0based_exclusive = rows
            .iter()
            .map(|row| row.end_0based_exclusive)
            .max()
            .unwrap_or(focus_start_0based.saturating_add(1));
        let mut context_tags = rows
            .iter()
            .flat_map(|row| row.context_tags.iter().cloned())
            .collect::<Vec<_>>();
        context_tags.sort();
        context_tags.dedup();
        let role = if rows
            .iter()
            .any(|row| row.role == ConstructRole::MobileElement)
        {
            ConstructRole::MobileElement
        } else {
            ConstructRole::RepeatRegion
        };
        Self::construct_reasoning_dotplot_actions_for_range(
            if fact.fact_id.trim().is_empty() {
                fact.label.as_str()
            } else {
                fact.fact_id.as_str()
            },
            fact.label.as_str(),
            role,
            focus_start_0based,
            focus_end_0based_exclusive,
            &context_tags,
        )
    }

    fn construct_reasoning_title(span: &ConstructReasoningOverlaySpan) -> String {
        let label = span.label.trim();
        if label.is_empty() {
            Self::construct_reasoning_role_label(span.role).to_string()
        } else {
            label.to_string()
        }
    }

    fn construct_reasoning_range_text(span: &ConstructReasoningOverlaySpan) -> String {
        let start_1based = span.start_0based.saturating_add(1);
        let end_1based = span.end_0based_exclusive.max(start_1based);
        let bp_len = span
            .end_0based_exclusive
            .saturating_sub(span.start_0based)
            .max(1);
        let strand = span.strand.as_deref().unwrap_or("?");
        format!("{start_1based}..{end_1based} ({bp_len} bp, strand {strand})")
    }

    fn construct_reasoning_detail_lines(
        overlay: &ConstructReasoningOverlay,
        span: &ConstructReasoningOverlaySpan,
    ) -> Vec<String> {
        let mut details = vec![
            format!("role: {}", Self::construct_reasoning_role_label(span.role)),
            format!(
                "class: {}",
                Self::construct_reasoning_evidence_class_label(span.evidence_class)
            ),
            format!(
                "editable_status: {}",
                Self::construct_reasoning_editable_status_label(span.editable_status)
            ),
        ];
        if !overlay.objective_title.trim().is_empty() {
            details.push(format!("objective: {}", overlay.objective_title.trim()));
        }
        if !overlay.objective_goal.trim().is_empty() {
            details.push(format!("goal: {}", overlay.objective_goal.trim()));
        }
        if !span.rationale.trim().is_empty() {
            details.push(format!("why: {}", span.rationale.trim()));
        }
        if let Some(score) = span.score {
            details.push(format!("score: {score:.3}"));
        }
        if let Some(confidence) = span.confidence {
            details.push(format!("confidence: {confidence:.3}"));
        }
        if !span.context_tags.is_empty() {
            details.push(format!("context: {}", span.context_tags.join(", ")));
        }
        if !span.provenance_kind.trim().is_empty() {
            details.push(format!("provenance: {}", span.provenance_kind.trim()));
        }
        if !span.provenance_refs.is_empty() {
            details.push(format!("refs: {}", span.provenance_refs.join(", ")));
        }
        if !span.source_kind.trim().is_empty() {
            details.push(format!("annotation_source: {}", span.source_kind.trim()));
        }
        if !span.summary_subtitle.trim().is_empty() {
            details.push(format!("summary: {}", span.summary_subtitle.trim()));
        }
        if span.summary_candidate_count > 1 {
            details.push(format!(
                "collapsed_candidates: {}",
                span.summary_candidate_count
            ));
        }
        if !span.summary_review_status.trim().is_empty() {
            details.push(format!(
                "review_summary: {}",
                span.summary_review_status.trim()
            ));
        }
        if !span.supporting_fact_labels.is_empty() {
            details.push(format!(
                "supports_facts: {}",
                span.supporting_fact_labels.join(", ")
            ));
        }
        if !span.supporting_decision_titles.is_empty() {
            details.push(format!(
                "supports_decisions: {}",
                span.supporting_decision_titles.join(", ")
            ));
        }
        if let Some(status) = span.transcript_context_status.as_deref() {
            details.push(format!("transcript_context: {status}"));
        }
        if !span.effect_tags.is_empty() {
            details.push(format!("effect_tags: {}", span.effect_tags.join(", ")));
        }
        for warning in span.warnings.iter().take(2) {
            if !warning.trim().is_empty() {
                details.push(format!("warning: {}", warning.trim()));
            }
        }
        for note in span.notes.iter().take(2) {
            if !note.trim().is_empty() {
                details.push(format!("note: {}", note.trim()));
            }
        }
        details
    }

    fn find_construct_reasoning_span(
        &self,
        evidence_id: &str,
    ) -> Option<(ConstructReasoningOverlay, ConstructReasoningOverlaySpan)> {
        let display = self.dna_display.read().ok()?;
        let overlay = display.construct_reasoning_overlay()?.clone();
        let span = overlay
            .evidence
            .iter()
            .find(|span| span.evidence_id == evidence_id)
            .cloned()?;
        Some((overlay, span))
    }

    fn render_construct_reasoning_hover_ui(
        &self,
        ui: &mut egui::Ui,
        overlay: &ConstructReasoningOverlay,
        span: &ConstructReasoningOverlaySpan,
    ) {
        let detail_font_size = self.feature_details_font_size();
        ui.strong(Self::construct_reasoning_title(span));
        ui.label(
            egui::RichText::new(format!(
                "{} | {}",
                Self::construct_reasoning_evidence_class_label(span.evidence_class),
                Self::construct_reasoning_range_text(span)
            ))
            .monospace()
            .size(detail_font_size),
        );
        for line in Self::construct_reasoning_detail_lines(overlay, span)
            .into_iter()
            .take(4)
        {
            ui.label(egui::RichText::new(line).monospace().size(detail_font_size));
        }
    }

    fn render_construct_reasoning_overlay_menu(&mut self, ui: &mut egui::Ui) {
        let overlay = self
            .dna_display
            .read()
            .ok()
            .and_then(|display| display.construct_reasoning_overlay().cloned());
        let Some(overlay) = overlay else {
            ui.label("No construct reasoning evidence available.");
            return;
        };

        ui.label(egui::RichText::new("Inspect reasoning overlay").strong());
        if !overlay.objective_title.trim().is_empty() {
            ui.label(overlay.objective_title.trim());
        }
        if !overlay.objective_goal.trim().is_empty() {
            ui.small(overlay.objective_goal.trim());
        }
        ui.separator();

        let mut changed = false;
        if let Ok(mut display) = self.dna_display.write() {
            ui.label(egui::RichText::new("Evidence classes").strong());
            for class in [
                EvidenceClass::HardFact,
                EvidenceClass::ReliableAnnotation,
                EvidenceClass::ContextEvidence,
                EvidenceClass::SoftHypothesis,
                EvidenceClass::UserOverride,
            ] {
                let count = overlay
                    .evidence
                    .iter()
                    .filter(|span| span.evidence_class == class)
                    .count();
                if count == 0 {
                    continue;
                }
                let mut visible = display.construct_reasoning_evidence_class_visible(class);
                if ui
                    .checkbox(
                        &mut visible,
                        format!(
                            "{} ({count})",
                            Self::construct_reasoning_evidence_class_label(class)
                        ),
                    )
                    .changed()
                {
                    display.set_construct_reasoning_evidence_class_visible(class, visible);
                    changed = true;
                }
            }

            ui.separator();
            ui.label(egui::RichText::new("Roles").strong());
            let mut role_counts: BTreeMap<ConstructRole, usize> = BTreeMap::new();
            for span in &overlay.evidence {
                *role_counts.entry(span.role).or_insert(0) += 1;
            }
            for (role, count) in role_counts {
                let mut visible = display.construct_reasoning_role_visible(role);
                if ui
                    .checkbox(
                        &mut visible,
                        format!("{} ({count})", Self::construct_reasoning_role_label(role)),
                    )
                    .changed()
                {
                    display.set_construct_reasoning_role_visible(role, visible);
                    changed = true;
                }
            }

            ui.separator();
            if ui
                .button("Show all reasoning evidence")
                .on_hover_text("Clear reasoning overlay filters and show every evidence span again")
                .clicked()
            {
                display.clear_construct_reasoning_filters();
                changed = true;
            }
        }

        if changed {
            let should_clear_selected_reasoning = self
                .map_dna
                .get_selected_reasoning_evidence_id()
                .and_then(|evidence_id| self.find_construct_reasoning_span(evidence_id.as_str()))
                .map(|(_, span)| {
                    self.dna_display
                        .read()
                        .map(|display| !display.construct_reasoning_overlay_span_visible(&span))
                        .unwrap_or(false)
                })
                .unwrap_or(false);
            if should_clear_selected_reasoning {
                self.map_dna.select_reasoning_evidence(None);
            }
            self.description_cache_initialized = false;
            ui.ctx().request_repaint();
        }
    }

    fn inspect_feature_expert_target(
        &self,
        target: &FeatureExpertTarget,
    ) -> Result<FeatureExpertView, String> {
        let seq_id = self
            .seq_id
            .as_deref()
            .ok_or_else(|| "Sequence id is unavailable for expert view".to_string())?;
        let engine = self
            .engine
            .as_ref()
            .ok_or_else(|| "Engine is unavailable for expert view".to_string())?;
        let guard = engine
            .read()
            .map_err(|_| "Engine lock poisoned while preparing expert view".to_string())?;
        guard
            .inspect_feature_expert(seq_id, target)
            .map_err(|e| e.to_string())
    }

    fn restriction_site_expert_target_for_position(
        &self,
        site: &RestrictionEnzymePosition,
    ) -> FeatureExpertTarget {
        let key = site.key();
        let mut names = self
            .dna
            .read()
            .ok()
            .and_then(|dna| dna.restriction_enzyme_groups().get(key).cloned())
            .unwrap_or_default();
        names.sort_by(|a, b| a.to_ascii_uppercase().cmp(&b.to_ascii_uppercase()));
        names.dedup_by(|left, right| left.eq_ignore_ascii_case(right));
        FeatureExpertTarget::RestrictionSite {
            cut_pos_1based: key.pos().max(0) as usize + 1,
            enzyme: names.first().cloned(),
            recognition_start_1based: Some(key.from().max(0) as usize + 1),
            recognition_end_1based: Some(key.to().max(0) as usize),
        }
    }

    fn restriction_site_expert_view_for_position(
        &self,
        site: &RestrictionEnzymePosition,
    ) -> Result<RestrictionSiteExpertView, String> {
        let target = self.restriction_site_expert_target_for_position(site);
        match self.inspect_feature_expert_target(&target)? {
            FeatureExpertView::RestrictionSite(view) => Ok(view),
            other => Err(format!(
                "Expected restriction-site expert view, got {:?}",
                other
            )),
        }
    }

    fn render_restriction_site_hover_ui(
        ui: &mut egui::Ui,
        view: &RestrictionSiteExpertView,
        font_size: f32,
    ) {
        let lines = view.tooltip_summary_lines();
        if let Some(first) = lines.first() {
            ui.label(
                egui::RichText::new(first)
                    .strong()
                    .monospace()
                    .size(font_size),
            );
        }
        for line in lines.iter().skip(1) {
            ui.label(egui::RichText::new(line).monospace().size(font_size));
        }
        ui.separator();
        ui.label(
            egui::RichText::new(
                "Click the site to pin details; pinned view can copy summary/JSON.",
            )
            .italics()
            .size((font_size - 1.0).max(8.0)),
        );
    }

    fn tfbs_base_color(base_idx: usize) -> egui::Color32 {
        match base_idx {
            0 => egui::Color32::from_rgb(43, 138, 62), // A
            1 => egui::Color32::from_rgb(29, 78, 216), // C
            2 => egui::Color32::from_rgb(217, 119, 6), // G
            3 => egui::Color32::from_rgb(185, 28, 28), // T
            _ => egui::Color32::GRAY,
        }
    }

    fn render_tfbs_expert_view_ui(&self, ui: &mut egui::Ui, view: &TfbsExpertView) {
        ui.label(
            egui::RichText::new(format!(
                "{} ({})  {}:{}..{}  strand {}",
                view.tf_name.clone().unwrap_or_else(|| view.tf_id.clone()),
                view.tf_id,
                view.seq_id,
                view.start_1based,
                view.end_1based,
                view.strand
            ))
            .monospace()
            .size(self.feature_details_font_size()),
        );
        ui.label(
            egui::RichText::new(format!(
                "matched={}  llr_bits={:.4}  true_log_odds_bits={:.4}",
                view.matched_sequence,
                view.llr_total_bits.unwrap_or_default(),
                view.true_log_odds_total_bits.unwrap_or_default()
            ))
            .monospace()
            .size(self.feature_details_font_size()),
        );

        let desired_width = (view.columns.len() as f32 * 24.0 + 90.0).max(ui.available_width());
        let desired_height = 220.0;
        egui::ScrollArea::horizontal().show(ui, |ui| {
            scroll_input_policy::apply_scrollarea_keyboard_navigation(
                ui,
                scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
            );
            let (rect, response) = ui.allocate_exact_size(
                egui::Vec2::new(desired_width, desired_height),
                egui::Sense::hover(),
            );
            response.on_hover_text(view.instruction.as_str());
            let painter = ui.painter_at(rect);

            let left = rect.left() + 38.0;
            let right = rect.right() - 10.0;
            let chart_top = rect.top() + 10.0;
            let chart_bottom = rect.bottom() - 50.0;
            let baseline = chart_bottom;
            let n = view.columns.len().max(1);
            let step = ((right - left) / n as f32).max(8.0);
            let bar_width = (step * 0.72).clamp(5.0, 16.0);
            let scale = (chart_bottom - chart_top) / 2.0;

            painter.line_segment(
                [egui::pos2(left, baseline), egui::pos2(right, baseline)],
                egui::Stroke::new(1.0, egui::Color32::from_gray(60)),
            );
            for tick in [0.0_f32, 1.0, 2.0] {
                let y = baseline - tick * scale;
                painter.line_segment(
                    [egui::pos2(left - 4.0, y), egui::pos2(right, y)],
                    egui::Stroke::new(
                        1.0,
                        if tick == 0.0 {
                            egui::Color32::from_gray(70)
                        } else {
                            egui::Color32::from_gray(220)
                        },
                    ),
                );
                painter.text(
                    egui::pos2(left - 6.0, y),
                    egui::Align2::RIGHT_CENTER,
                    format!("{tick:.0}"),
                    egui::FontId::monospace(9.0),
                    egui::Color32::from_gray(80),
                );
            }

            let mut match_points: Vec<egui::Pos2> = Vec::new();
            for (idx, col) in view.columns.iter().enumerate() {
                let x_center = left + step * (idx as f32 + 0.5);
                let x = x_center - bar_width / 2.0;
                let ic = col.information_content_bits.clamp(0.0, 2.0) as f32;
                let full_height = ic * scale;
                let mut y_cursor = baseline;
                let match_idx = match col.match_base.map(|c| c.to_ascii_uppercase()) {
                    Some('A') => Some(0usize),
                    Some('C') => Some(1usize),
                    Some('G') => Some(2usize),
                    Some('T') => Some(3usize),
                    _ => None,
                };
                let mut match_y: Option<f32> = None;
                for base_idx in 0..4 {
                    let freq = col.frequencies[base_idx].clamp(0.0, 1.0) as f32;
                    let segment_h = full_height * freq;
                    if segment_h <= 0.0 {
                        continue;
                    }
                    let y_top = y_cursor - segment_h;
                    painter.rect_filled(
                        egui::Rect::from_min_size(
                            egui::pos2(x, y_top),
                            egui::vec2(bar_width, segment_h),
                        ),
                        0.0,
                        Self::tfbs_base_color(base_idx),
                    );
                    if match_idx == Some(base_idx) {
                        match_y = Some(y_top + segment_h * 0.5);
                    }
                    y_cursor = y_top;
                }
                if let Some(y) = match_y {
                    match_points.push(egui::pos2(x_center, y));
                }
                if idx % 2 == 0 || n <= 24 {
                    painter.text(
                        egui::pos2(x_center, baseline + 11.0),
                        egui::Align2::CENTER_TOP,
                        (idx + 1).to_string(),
                        egui::FontId::monospace(8.0),
                        egui::Color32::from_gray(70),
                    );
                }
                if let Some(base) = col.match_base {
                    painter.text(
                        egui::pos2(x_center, baseline + 24.0),
                        egui::Align2::CENTER_TOP,
                        base.to_ascii_uppercase(),
                        egui::FontId::monospace(9.0),
                        egui::Color32::BLACK,
                    );
                }
            }

            if match_points.len() >= 2 {
                painter.add(egui::Shape::line(
                    match_points.clone(),
                    egui::Stroke::new(1.8, egui::Color32::BLACK),
                ));
                for p in match_points {
                    painter.circle_filled(p, 2.0, egui::Color32::BLACK);
                }
            }
        });
    }

    fn restriction_site_copy_summary_text(view: &RestrictionSiteExpertView) -> String {
        view.tooltip_summary_lines().join("\n")
    }

    fn restriction_site_copy_json_text(view: &RestrictionSiteExpertView) -> String {
        let payload = serde_json::json!({
            "kind": "restriction_site",
            "data": view,
        });
        serde_json::to_string_pretty(&payload).unwrap_or_else(|_| {
            format!(
                "{{\"kind\":\"restriction_site\",\"seq_id\":\"{}\",\"cut_pos_1based\":{}}}",
                view.seq_id, view.cut_pos_1based
            )
        })
    }

    fn restriction_site_context_menu_title(view: &RestrictionSiteExpertView) -> String {
        format!(
            "Restriction site: {} at {} bp",
            view.enzyme_display_label(),
            view.cut_pos_1based
        )
    }

    fn copy_restriction_site_payload_to_clipboard(
        &mut self,
        ctx: &egui::Context,
        view: &RestrictionSiteExpertView,
        label: &str,
        payload: String,
    ) {
        if payload.trim().is_empty() {
            self.op_status = format!(
                "Restriction-site {} for {} at {} bp is empty",
                label,
                view.enzyme_display_label(),
                view.cut_pos_1based
            );
            return;
        }
        ctx.copy_text(payload);
        self.op_status = format!(
            "Copied restriction-site {} for {} at {} bp",
            label,
            view.enzyme_display_label(),
            view.cut_pos_1based
        );
    }

    fn render_restriction_site_context_menu_items(
        &mut self,
        ui: &mut egui::Ui,
        site: &RestrictionEnzymePosition,
        view: &RestrictionSiteExpertView,
    ) -> bool {
        let mut handled = false;
        ui.label(
            egui::RichText::new(Self::restriction_site_context_menu_title(view))
                .strong()
                .monospace(),
        );
        if ui
            .button("Pin Restriction Site Details")
            .on_hover_text(
                "Select this restriction site and show the pinned shared expert record in the Description panel",
            )
            .clicked()
        {
            self.map_dna.select_restriction_site(Some(site.clone()));
            self.clear_feature_focus_keep_map_selection();
            self.description_cache_initialized = false;
            self.op_status = format!(
                "Pinned restriction-site details for {} at {} bp",
                view.enzyme_display_label(),
                view.cut_pos_1based
            );
            handled = true;
        }
        if ui
            .button("Copy Restriction Summary")
            .on_hover_text("Copy the same concise restriction-site summary used by the map tooltip")
            .clicked()
        {
            self.copy_restriction_site_payload_to_clipboard(
                ui.ctx(),
                view,
                "summary",
                Self::restriction_site_copy_summary_text(view),
            );
            handled = true;
        }
        if ui
            .button("Copy Detail JSON")
            .on_hover_text(
                "Copy the shared restriction-site expert record as JSON for CLI/MCP/agent handoff",
            )
            .clicked()
        {
            self.copy_restriction_site_payload_to_clipboard(
                ui.ctx(),
                view,
                "detail JSON",
                Self::restriction_site_copy_json_text(view),
            );
            handled = true;
        }
        if handled {
            ui.close();
        }
        handled
    }

    fn render_restriction_expert_view_ui(
        &mut self,
        ui: &mut egui::Ui,
        view: &RestrictionSiteExpertView,
    ) {
        let geometry_label =
            Self::restriction_end_geometry_display_label(&view.end_geometry, view.overlap_bp);
        let cut_color = Self::restriction_end_geometry_color(&view.end_geometry, view.overlap_bp);
        let paired_cut_pos_1based = if view.paired_cut_pos_1based == 0 {
            view.cut_pos_1based
        } else {
            view.paired_cut_pos_1based
        };
        let paired_cut_index_0based =
            if view.paired_cut_pos_1based == 0 && view.paired_cut_index_0based == 0 {
                view.cut_index_0based
            } else {
                view.paired_cut_index_0based
            };
        let font_size = self.feature_details_font_size();
        ui.horizontal_wrapped(|ui| {
            if ui
                .button("Copy Summary")
                .on_hover_text(
                    "Copy the same concise restriction-site summary used by the map tooltip",
                )
                .clicked()
            {
                self.copy_restriction_site_payload_to_clipboard(
                    ui.ctx(),
                    view,
                    "summary",
                    Self::restriction_site_copy_summary_text(view),
                );
            }
            if ui
                .button("Copy Detail JSON")
                .on_hover_text(
                    "Copy the shared restriction-site expert record as JSON for CLI/MCP/agent handoff",
                )
                .clicked()
            {
                self.copy_restriction_site_payload_to_clipboard(
                    ui.ctx(),
                    view,
                    "detail JSON",
                    Self::restriction_site_copy_json_text(view),
                );
            }
        });
        ui.label(
            egui::RichText::new(format!(
                "{} | cuts={}|{} | {}:{}..{}",
                view.selected_enzyme
                    .clone()
                    .unwrap_or_else(|| view.enzyme_names.join(",")),
                view.cut_pos_1based,
                paired_cut_pos_1based,
                view.seq_id,
                view.recognition_start_1based,
                view.recognition_end_1based
            ))
            .monospace()
            .size(font_size),
        );
        ui.label(
            egui::RichText::new(format!("geometry={geometry_label}"))
                .monospace()
                .size(font_size)
                .color(cut_color),
        );
        if let Some(pattern) = &view.recognition_iupac {
            ui.label(
                egui::RichText::new(format!("recognition_iupac={pattern}"))
                    .monospace()
                    .size(font_size),
            );
        }
        if view.enzyme_cut_offset_0based.is_some() || view.overlap_bp.is_some() {
            let mut fields = Vec::new();
            if let Some(cut_offset) = view.enzyme_cut_offset_0based {
                fields.push(format!("enzyme_cut_offset_0based={cut_offset}"));
            }
            if let Some(overlap) = view.overlap_bp {
                fields.push(format!("overlap_bp={overlap}"));
            }
            if !fields.is_empty() {
                ui.label(
                    egui::RichText::new(fields.join(" | "))
                        .monospace()
                        .size(font_size),
                );
            }
        }
        if let Some(note) = &view.enzyme_note {
            ui.label(
                egui::RichText::new(format!("note={note}"))
                    .monospace()
                    .size(font_size),
            );
        }
        if let Some(url) = &view.rebase_url {
            ui.horizontal_wrapped(|ui| {
                ui.label(
                    egui::RichText::new("rebase_url=")
                        .monospace()
                        .size(font_size),
                );
                ui.hyperlink_to(url, url);
            });
        }
        let top = if view.site_sequence.is_empty() {
            view.recognition_iupac.clone().unwrap_or_default()
        } else {
            view.site_sequence.clone()
        };
        let bottom = view.site_sequence_complement.clone();

        let desired_width = (top.chars().count() as f32 * 24.0 + 110.0).max(ui.available_width());
        let desired_height = 130.0;
        egui::ScrollArea::horizontal().show(ui, |ui| {
            scroll_input_policy::apply_scrollarea_keyboard_navigation(
                ui,
                scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
            );
            let (rect, response) = ui.allocate_exact_size(
                egui::Vec2::new(desired_width, desired_height),
                egui::Sense::hover(),
            );
            response.on_hover_text(view.instruction.as_str());
            let painter = ui.painter_at(rect);
            let n = top.chars().count().max(1);
            let step = ((rect.width() - 90.0) / n as f32).clamp(14.0, 24.0);
            let total = step * n as f32;
            let start_x = rect.left() + (rect.width() - total) * 0.5;
            let top_y = rect.top() + 38.0;
            let bottom_y = rect.top() + 78.0;
            let rail_left = start_x - 10.0;
            let rail_right = start_x + total + 10.0;

            painter.line_segment(
                [
                    egui::pos2(rail_left, top_y - 8.0),
                    egui::pos2(rail_right, top_y - 8.0),
                ],
                egui::Stroke::new(1.4, egui::Color32::BLACK),
            );
            painter.line_segment(
                [
                    egui::pos2(rail_left, bottom_y + 8.0),
                    egui::pos2(rail_right, bottom_y + 8.0),
                ],
                egui::Stroke::new(1.4, egui::Color32::BLACK),
            );

            for (idx, ch) in top.chars().enumerate() {
                let x = start_x + step * (idx as f32 + 0.5);
                painter.text(
                    egui::pos2(x, top_y),
                    egui::Align2::CENTER_CENTER,
                    ch,
                    egui::FontId::monospace(18.0),
                    egui::Color32::from_rgb(17, 24, 39),
                );
            }
            for (idx, ch) in bottom.chars().enumerate() {
                let x = start_x + step * (idx as f32 + 0.5);
                painter.text(
                    egui::pos2(x, bottom_y),
                    egui::Align2::CENTER_CENTER,
                    ch,
                    egui::FontId::monospace(18.0),
                    egui::Color32::from_rgb(51, 65, 85),
                );
            }
            let top_cut_x = start_x + step * view.cut_index_0based as f32;
            let bottom_cut_x = start_x + step * paired_cut_index_0based as f32;
            if (top_cut_x - bottom_cut_x).abs() < 0.5 {
                painter.line_segment(
                    [
                        egui::pos2(top_cut_x, top_y - 28.0),
                        egui::pos2(top_cut_x, bottom_y + 24.0),
                    ],
                    egui::Stroke::new(2.0, cut_color),
                );
            } else {
                painter.line_segment(
                    [
                        egui::pos2(top_cut_x, top_y - 28.0),
                        egui::pos2(top_cut_x, top_y - 4.0),
                    ],
                    egui::Stroke::new(2.0, cut_color),
                );
                painter.line_segment(
                    [
                        egui::pos2(top_cut_x, top_y - 4.0),
                        egui::pos2(bottom_cut_x, bottom_y + 4.0),
                    ],
                    egui::Stroke::new(2.0, cut_color),
                );
                painter.line_segment(
                    [
                        egui::pos2(bottom_cut_x, bottom_y + 4.0),
                        egui::pos2(bottom_cut_x, bottom_y + 24.0),
                    ],
                    egui::Stroke::new(2.0, cut_color),
                );
            }
            painter.text(
                egui::pos2(top_cut_x.max(bottom_cut_x) + 4.0, top_y - 30.0),
                egui::Align2::LEFT_BOTTOM,
                geometry_label,
                egui::FontId::monospace(9.0),
                cut_color,
            );
        });
    }

    fn restriction_end_geometry_display_label(
        end_geometry: &str,
        overlap_bp: Option<isize>,
    ) -> String {
        match end_geometry {
            "5prime_overhang" => {
                format!(
                    "5' overhang ({} bp)",
                    overlap_bp.unwrap_or(0).unsigned_abs()
                )
            }
            "3prime_overhang" => {
                format!(
                    "3' overhang ({} bp)",
                    overlap_bp.unwrap_or(0).unsigned_abs()
                )
            }
            _ => match overlap_bp {
                Some(value) if value > 0 => format!("5' overhang ({} bp)", value as usize),
                Some(value) if value < 0 => {
                    format!("3' overhang ({} bp)", value.unsigned_abs())
                }
                _ => "blunt".to_string(),
            },
        }
    }

    fn restriction_end_geometry_color(
        end_geometry: &str,
        overlap_bp: Option<isize>,
    ) -> egui::Color32 {
        match end_geometry {
            "5prime_overhang" => egui::Color32::from_rgb(37, 99, 235),
            "3prime_overhang" => egui::Color32::from_rgb(217, 119, 6),
            _ => match overlap_bp {
                Some(value) if value > 0 => egui::Color32::from_rgb(37, 99, 235),
                Some(value) if value < 0 => egui::Color32::from_rgb(217, 119, 6),
                _ => egui::Color32::from_rgb(71, 85, 105),
            },
        }
    }

    fn splicing_boundary_motif_rows(view: &SplicingExpertView) -> Vec<SplicingBoundaryMotifRow> {
        let acceptor_lookup = view
            .boundaries
            .iter()
            .filter(|marker| marker.side.eq_ignore_ascii_case("acceptor"))
            .map(|marker| {
                (
                    (marker.transcript_feature_id, marker.position_1based),
                    marker,
                )
            })
            .collect::<HashMap<_, _>>();
        let mut rows = view
            .boundaries
            .iter()
            .filter(|marker| marker.side.eq_ignore_ascii_case("donor"))
            .map(|donor| {
                let acceptor = acceptor_lookup
                    .get(&(donor.transcript_feature_id, donor.partner_position_1based))
                    .copied();
                let (_paired_donor, paired_acceptor) = donor
                    .paired_motif_signature
                    .split_once('-')
                    .unwrap_or((donor.motif_2bp.as_str(), ""));
                SplicingBoundaryMotifRow {
                    transcript_feature_id: donor.transcript_feature_id,
                    transcript_id: donor.transcript_id.clone(),
                    donor_position_1based: donor.position_1based,
                    donor_motif_2bp: donor.motif_2bp.clone(),
                    acceptor_position_1based: donor.partner_position_1based,
                    acceptor_motif_2bp: acceptor
                        .map(|marker| marker.motif_2bp.clone())
                        .unwrap_or_else(|| {
                            if paired_acceptor.is_empty() {
                                String::new()
                            } else {
                                paired_acceptor.to_string()
                            }
                        }),
                    paired_motif_signature: donor.paired_motif_signature.clone(),
                    motif_class: donor.motif_class.clone(),
                    annotation: donor.annotation.clone(),
                }
            })
            .collect::<Vec<_>>();
        rows.sort_by(|left, right| {
            left.donor_position_1based
                .cmp(&right.donor_position_1based)
                .then_with(|| {
                    left.acceptor_position_1based
                        .cmp(&right.acceptor_position_1based)
                })
                .then_with(|| left.transcript_feature_id.cmp(&right.transcript_feature_id))
                .then_with(|| left.transcript_id.cmp(&right.transcript_id))
        });
        rows
    }

    fn splicing_intron_signal_rows(view: &SplicingExpertView) -> Vec<SplicingIntronSignalRow> {
        let mut rows = view
            .intron_signals
            .iter()
            .map(|signal| SplicingIntronSignalRow {
                transcript_feature_id: signal.transcript_feature_id,
                transcript_id: signal.transcript_id.clone(),
                donor_position_1based: signal.donor_position_1based,
                acceptor_position_1based: signal.acceptor_position_1based,
                intron_length_bp: signal.intron_length_bp,
                branchpoint_position_1based: signal.branchpoint_position_1based,
                branchpoint_motif: signal.branchpoint_motif.clone(),
                branchpoint_annotation: signal.branchpoint_annotation.clone(),
                polypyrimidine_start_1based: signal.polypyrimidine_start_1based,
                polypyrimidine_end_1based: signal.polypyrimidine_end_1based,
                polypyrimidine_fraction_percent: (signal.polypyrimidine_fraction * 100.0)
                    .round()
                    .clamp(0.0, 100.0) as usize,
                polypyrimidine_annotation: signal.polypyrimidine_annotation.clone(),
            })
            .collect::<Vec<_>>();
        rows.sort_by(|left, right| {
            left.donor_position_1based
                .cmp(&right.donor_position_1based)
                .then_with(|| {
                    left.acceptor_position_1based
                        .cmp(&right.acceptor_position_1based)
                })
                .then_with(|| left.transcript_feature_id.cmp(&right.transcript_feature_id))
                .then_with(|| left.transcript_id.cmp(&right.transcript_id))
        });
        rows
    }

    fn splicing_intron_signal_key_for_row(
        row: &SplicingIntronSignalRow,
    ) -> SplicingIntronSignalKey {
        SplicingIntronSignalKey {
            transcript_feature_id: row.transcript_feature_id,
            donor_position_1based: row.donor_position_1based,
            acceptor_position_1based: row.acceptor_position_1based,
        }
    }

    fn splicing_intron_signal_key_for_signal(
        signal: &SplicingIntronSignal,
    ) -> SplicingIntronSignalKey {
        SplicingIntronSignalKey {
            transcript_feature_id: signal.transcript_feature_id,
            donor_position_1based: signal.donor_position_1based,
            acceptor_position_1based: signal.acceptor_position_1based,
        }
    }

    fn splicing_intron_key_for_lane_range(
        transcript_feature_id: usize,
        strand: &str,
        intron: &SplicingRange,
    ) -> SplicingIntronSignalKey {
        if strand.trim() == "-" {
            SplicingIntronSignalKey {
                transcript_feature_id,
                donor_position_1based: intron.end_1based,
                acceptor_position_1based: intron.start_1based,
            }
        } else {
            SplicingIntronSignalKey {
                transcript_feature_id,
                donor_position_1based: intron.start_1based,
                acceptor_position_1based: intron.end_1based,
            }
        }
    }

    fn splicing_intron_range_length_bp(intron: &SplicingRange) -> usize {
        intron
            .end_1based
            .max(intron.start_1based)
            .saturating_sub(intron.end_1based.min(intron.start_1based))
            + 1
    }

    fn splicing_boundary_motif_class_label(class: &str) -> &'static str {
        match class {
            "gt_ag_major_canonical" => "canonical major (GT-AG)",
            "gc_ag_major_noncanonical" => "major non-canonical (GC-AG)",
            "at_ac_minor_u12_like" => "minor/U12-like (AT-AC)",
            "at_ag_minor_u12_like" => "minor/U12-like (AT-AG)",
            "other_noncanonical" => "other non-canonical",
            _ => "splice-site motif",
        }
    }

    fn splicing_boundary_motif_class_color(class: &str) -> egui::Color32 {
        match class {
            "gt_ag_major_canonical" => egui::Color32::from_rgb(5, 150, 105),
            "gc_ag_major_noncanonical" => egui::Color32::from_rgb(180, 83, 9),
            "at_ac_minor_u12_like" | "at_ag_minor_u12_like" => {
                egui::Color32::from_rgb(124, 58, 237)
            }
            "other_noncanonical" => egui::Color32::from_rgb(185, 28, 28),
            _ => egui::Color32::from_rgb(71, 85, 105),
        }
    }

    fn splicing_boundary_marker_color(marker: &SplicingBoundaryMarker) -> egui::Color32 {
        let base = Self::splicing_boundary_motif_class_color(marker.motif_class.as_str());
        if marker.side.eq_ignore_ascii_case("donor") {
            base
        } else {
            egui::Color32::from_rgba_premultiplied(base.r(), base.g(), base.b(), 220)
        }
    }

    fn splicing_signal_lookup<'a>(
        view: &'a SplicingExpertView,
    ) -> std::collections::HashMap<(usize, usize, usize), &'a SplicingIntronSignal> {
        view.intron_signals
            .iter()
            .map(|signal| {
                (
                    (
                        signal.transcript_feature_id,
                        signal.donor_position_1based,
                        signal.acceptor_position_1based,
                    ),
                    signal,
                )
            })
            .collect()
    }

    fn splicing_selected_intron_signal_key(
        &mut self,
        view: &SplicingExpertView,
    ) -> Option<SplicingIntronSignalKey> {
        let exists = self
            .splicing_expert_selected_intron_signal_key
            .clone()
            .and_then(|key| {
                view.intron_signals
                    .iter()
                    .any(|signal| Self::splicing_intron_signal_key_for_signal(signal) == key)
                    .then_some(key)
            });
        if let Some(key) = exists {
            return Some(key);
        }
        let fallback = view
            .intron_signals
            .first()
            .map(Self::splicing_intron_signal_key_for_signal);
        self.splicing_expert_selected_intron_signal_key = fallback.clone();
        fallback
    }

    fn splicing_selected_intron_signal_row(
        &mut self,
        view: &SplicingExpertView,
    ) -> Option<SplicingIntronSignalRow> {
        let selected = self.splicing_selected_intron_signal_key(view)?;
        Self::splicing_intron_signal_rows(view)
            .into_iter()
            .find(|row| Self::splicing_intron_signal_key_for_row(row) == selected)
    }

    fn splicing_intron_signal_branchpoint_summary(row: &SplicingIntronSignalRow) -> String {
        row.branchpoint_position_1based
            .map(|position| format!("{position} ({})", row.branchpoint_motif))
            .unwrap_or_else(|| "not detected above the current heuristic".to_string())
    }

    fn splicing_intron_signal_polypyrimidine_summary(row: &SplicingIntronSignalRow) -> String {
        match (
            row.polypyrimidine_start_1based,
            row.polypyrimidine_end_1based,
        ) {
            (Some(start), Some(end)) => format!(
                "{start}..{end} ({}% pyrimidines)",
                row.polypyrimidine_fraction_percent
            ),
            _ => "not detected above the current heuristic".to_string(),
        }
    }

    fn splicing_intron_signal_description_text(row: &SplicingIntronSignalRow) -> String {
        format!(
            "This {} bp intron is now highlighted in the lane view. The branchpoint-like site is {} and the best detected pyrimidine-rich tract is {}.",
            row.intron_length_bp,
            Self::splicing_intron_signal_branchpoint_summary(row),
            Self::splicing_intron_signal_polypyrimidine_summary(row),
        )
    }

    fn attract_hit_matches_intron_signal(
        hit: &AttractSplicingEvidenceHitRow,
        row: &SplicingIntronSignalRow,
    ) -> bool {
        if hit.transcript_feature_id != row.transcript_feature_id {
            return false;
        }
        match hit.region_class {
            AttractRegionClass::DonorFlank => {
                hit.region_start_1based <= row.donor_position_1based
                    && hit.region_end_1based >= row.donor_position_1based
            }
            AttractRegionClass::AcceptorFlank => {
                hit.region_start_1based <= row.acceptor_position_1based
                    && hit.region_end_1based >= row.acceptor_position_1based
            }
            AttractRegionClass::IntronBody => {
                hit.region_start_1based >= row.donor_position_1based
                    && hit.region_end_1based <= row.acceptor_position_1based
            }
            AttractRegionClass::ExonBody => false,
        }
    }

    fn splicing_intron_regulatory_rows(
        view: &SplicingExpertView,
        evidence: Option<&AttractSplicingEvidenceView>,
    ) -> Vec<SplicingIntronRegulatoryRow> {
        let signal_rows = Self::splicing_intron_signal_rows(view);
        signal_rows
            .into_iter()
            .map(|row| {
                let matching_hits = evidence
                    .map(|evidence| {
                        evidence
                            .hit_rows
                            .iter()
                            .filter(|hit| Self::attract_hit_matches_intron_signal(hit, &row))
                            .collect::<Vec<_>>()
                    })
                    .unwrap_or_default();
                let donor_flank_hit_count = matching_hits
                    .iter()
                    .filter(|hit| hit.region_class == AttractRegionClass::DonorFlank)
                    .count();
                let acceptor_flank_hit_count = matching_hits
                    .iter()
                    .filter(|hit| hit.region_class == AttractRegionClass::AcceptorFlank)
                    .count();
                let intron_body_hit_count = matching_hits
                    .iter()
                    .filter(|hit| hit.region_class == AttractRegionClass::IntronBody)
                    .count();
                let mut rbp_set = BTreeSet::new();
                let mut top_rbps = vec![];
                for hit in &matching_hits {
                    let rbp = hit.gene_name.trim();
                    if rbp.is_empty() {
                        continue;
                    }
                    let normalized = rbp.to_ascii_uppercase();
                    if rbp_set.insert(normalized) && top_rbps.len() < 4 {
                        top_rbps.push(rbp.to_string());
                    }
                }
                SplicingIntronRegulatoryRow {
                    transcript_feature_id: row.transcript_feature_id,
                    transcript_id: row.transcript_id,
                    donor_position_1based: row.donor_position_1based,
                    acceptor_position_1based: row.acceptor_position_1based,
                    intron_length_bp: row.intron_length_bp,
                    branchpoint_position_1based: row.branchpoint_position_1based,
                    polypyrimidine_start_1based: row.polypyrimidine_start_1based,
                    polypyrimidine_end_1based: row.polypyrimidine_end_1based,
                    donor_flank_hit_count,
                    acceptor_flank_hit_count,
                    intron_body_hit_count,
                    unique_rbp_count: rbp_set.len(),
                    top_rbps,
                }
            })
            .collect()
    }

    fn splicing_intron_regulatory_summary_text(row: &SplicingIntronRegulatoryRow) -> String {
        let branchpoint = row
            .branchpoint_position_1based
            .map(|pos| format!("branchpoint-like @ {pos}"))
            .unwrap_or_else(|| "no branchpoint-like site".to_string());
        let polyy = match (
            row.polypyrimidine_start_1based,
            row.polypyrimidine_end_1based,
        ) {
            (Some(start), Some(end)) => format!("polyY tract {start}..{end}"),
            _ => "no polyY tract".to_string(),
        };
        let rbp = if row.unique_rbp_count == 0 {
            "no cached RBP hits".to_string()
        } else {
            format!(
                "{} unique RBP(s): {}",
                row.unique_rbp_count,
                row.top_rbps.join(", ")
            )
        };
        format!(
            "{branchpoint}; {polyy}; donor flank hits={}, acceptor flank hits={}, intron-body hits={}; {rbp}.",
            row.donor_flank_hit_count, row.acceptor_flank_hit_count, row.intron_body_hit_count
        )
    }

    fn render_splicing_lane_canvas_ui(
        &mut self,
        ui: &mut egui::Ui,
        view: &SplicingExpertView,
        style: SplicingLaneCanvasStyle,
        interactive: bool,
        id_namespace: &str,
    ) -> Option<usize> {
        let transcript_count = view.transcripts.len();
        let lane_count = transcript_count.max(1);
        let transcript_total = view.transcript_count.max(1);
        let exon_support_by_range = view
            .unique_exons
            .iter()
            .map(|exon| {
                (
                    (exon.start_1based, exon.end_1based),
                    exon.support_transcript_count,
                )
            })
            .collect::<HashMap<_, _>>();
        let max_junction_support = view
            .junctions
            .iter()
            .map(|junction| junction.support_transcript_count.max(1) as f32)
            .fold(1.0_f32, f32::max);
        // Reserve enough vertical headroom so high-support intron arcs do not get clipped.
        let axis_top_padding = (30.0 + max_junction_support * 2.0).clamp(18.0, 84.0) + 10.0;
        let lanes_offset_from_axis = 30.0_f32;
        let plot_height = axis_top_padding
            + lanes_offset_from_axis
            + lane_count as f32 * style.lane_height_px
            + 36.0;
        let desired_width = ui.available_width().max(style.min_plot_width_px);
        let mut clicked_feature_id: Option<usize> = None;
        let selected_intron_signal_key = self.splicing_selected_intron_signal_key(view);

        egui::ScrollArea::horizontal()
            .id_salt((
                "splicing_lane_canvas_scroll",
                id_namespace,
                view.seq_id.as_str(),
                view.target_feature_id,
            ))
            .show(ui, |ui| {
                scroll_input_policy::apply_scrollarea_keyboard_navigation(
                    ui,
                    scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
                );
                let sense = if interactive {
                    egui::Sense::click()
                } else {
                    egui::Sense::hover()
                };
                let (rect, response) =
                    ui.allocate_exact_size(egui::Vec2::new(desired_width, plot_height), sense);
                response.clone().on_hover_text(view.instruction.as_str());
                let painter = ui.painter_at(rect);
                let label_x = rect.left() + 6.0;
                let plot_left = rect.left() + style.label_column_width_px;
                let plot_right = rect.right() - 20.0;
                let axis_y = rect.top() + axis_top_padding;
                let lanes_top = axis_y + lanes_offset_from_axis;
                let span = (view
                    .region_end_1based
                    .saturating_sub(view.region_start_1based))
                .max(1);

                let to_x = |pos_1based: usize| -> f32 {
                    let clamped =
                        pos_1based.clamp(view.region_start_1based, view.region_end_1based);
                    let frac =
                        (clamped.saturating_sub(view.region_start_1based)) as f32 / span as f32;
                    plot_left + frac * (plot_right - plot_left)
                };

                painter.line_segment(
                    [
                        egui::pos2(plot_left, axis_y),
                        egui::pos2(plot_right, axis_y),
                    ],
                    egui::Stroke::new(1.2, egui::Color32::from_gray(50)),
                );
                painter.text(
                    egui::pos2(plot_left, axis_y - 5.0),
                    egui::Align2::LEFT_BOTTOM,
                    format!("{}", view.region_start_1based),
                    egui::FontId::monospace(10.0),
                    egui::Color32::from_gray(70),
                );
                painter.text(
                    egui::pos2(plot_right, axis_y - 5.0),
                    egui::Align2::RIGHT_BOTTOM,
                    format!("{}", view.region_end_1based),
                    egui::FontId::monospace(10.0),
                    egui::Color32::from_gray(70),
                );

                for junction in &view.junctions {
                    let x1 = to_x(junction.donor_1based);
                    let x2 = to_x(junction.acceptor_1based);
                    if (x2 - x1).abs() < 3.0 {
                        continue;
                    }
                    let support = junction.support_transcript_count.max(1) as f32;
                    let height = ((x2 - x1).abs() * 0.12).clamp(9.0, 30.0) + support * 2.0;
                    let color = egui::Color32::from_rgb(59, 130, 246);
                    let mut pts = Vec::with_capacity(17);
                    for idx in 0..=16 {
                        let t = idx as f32 / 16.0;
                        let x = x1 + (x2 - x1) * t;
                        let y = axis_y - height * 4.0 * t * (1.0 - t);
                        pts.push(egui::pos2(x, y));
                    }
                    painter.add(egui::Shape::line(
                        pts,
                        egui::Stroke::new((0.9 + support * 0.45).clamp(0.9, 3.2), color),
                    ));
                    let show_support_label =
                        view.junctions.len() <= 48 || junction.support_transcript_count > 1;
                    if show_support_label {
                        let mid_x = (x1 + x2) * 0.5;
                        let apex_y = axis_y - height;
                        painter.text(
                            egui::pos2(mid_x, apex_y - 2.0),
                            egui::Align2::CENTER_BOTTOM,
                            format!("{}", junction.support_transcript_count),
                            egui::FontId::monospace(8.0),
                            egui::Color32::from_rgb(29, 78, 216),
                        );
                    }
                }

                let lane_index: HashMap<usize, usize> = view
                    .transcripts
                    .iter()
                    .enumerate()
                    .map(|(idx, lane)| (lane.transcript_feature_id, idx))
                    .collect();
                let intron_signal_lookup = Self::splicing_signal_lookup(view);

                for marker in &view.boundaries {
                    let Some(idx) = lane_index.get(&marker.transcript_feature_id) else {
                        continue;
                    };
                    let y =
                        lanes_top + *idx as f32 * style.lane_height_px + style.lane_height_px * 0.5;
                    let x = to_x(marker.position_1based);
                    let dy = if marker.side.eq_ignore_ascii_case("donor") {
                        9.0
                    } else {
                        -9.0
                    };
                    let color = Self::splicing_boundary_marker_color(marker);
                    painter.line_segment(
                        [egui::pos2(x, y), egui::pos2(x, y + dy)],
                        egui::Stroke::new(1.3, color),
                    );
                    painter.circle_filled(egui::pos2(x, y + dy), 2.2, color);
                    if view.boundaries.len() <= 16
                        || marker.motif_class.as_str() != "gt_ag_major_canonical"
                    {
                        painter.text(
                            egui::pos2(x + 3.0, y + dy),
                            if marker.side.eq_ignore_ascii_case("donor") {
                                egui::Align2::LEFT_TOP
                            } else {
                                egui::Align2::LEFT_BOTTOM
                            },
                            marker.motif_2bp.as_str(),
                            egui::FontId::monospace(7.0),
                            color,
                        );
                    }
                }

                for (idx, transcript) in view.transcripts.iter().enumerate() {
                    let y =
                        lanes_top + idx as f32 * style.lane_height_px + style.lane_height_px * 0.5;
                    painter.text(
                        egui::pos2(label_x, y),
                        egui::Align2::LEFT_CENTER,
                        format!(
                            "n-{} {}",
                            transcript.transcript_feature_id, transcript.transcript_id
                        ),
                        egui::FontId::monospace(10.0),
                        egui::Color32::BLACK,
                    );

                    for intron in &transcript.introns {
                        let x1 = to_x(intron.start_1based);
                        let x2 = to_x(intron.end_1based);
                        let signal_key = Self::splicing_intron_key_for_lane_range(
                            transcript.transcript_feature_id,
                            transcript.strand.as_str(),
                            intron,
                        );
                        let is_selected_signal = selected_intron_signal_key
                            .as_ref()
                            .map(|selected| {
                                selected.transcript_feature_id == signal_key.transcript_feature_id
                                    && selected.donor_position_1based
                                        == signal_key.donor_position_1based
                                    && selected.acceptor_position_1based
                                        == signal_key.acceptor_position_1based
                            })
                            .unwrap_or(false)
                            || self
                                .splicing_expert_selected_intron_keys
                                .contains(&signal_key);
                        painter.line_segment(
                            [egui::pos2(x1, y), egui::pos2(x2, y)],
                            egui::Stroke::new(
                                if is_selected_signal { 2.4 } else { 1.0 },
                                if is_selected_signal {
                                    egui::Color32::from_rgb(14, 116, 144)
                                } else {
                                    egui::Color32::from_gray(110)
                                },
                            ),
                        );
                        let signal_tuple = (
                            signal_key.transcript_feature_id,
                            signal_key.donor_position_1based,
                            signal_key.acceptor_position_1based,
                        );
                        if let Some(signal) = intron_signal_lookup.get(&signal_tuple).copied() {
                            if let (Some(tract_start), Some(tract_end)) = (
                                signal.polypyrimidine_start_1based,
                                signal.polypyrimidine_end_1based,
                            ) {
                                let tract_rect = egui::Rect::from_min_max(
                                    egui::pos2(to_x(tract_start), y - 2.2),
                                    egui::pos2(to_x(tract_end.max(tract_start)), y + 2.2),
                                );
                                painter.rect_filled(
                                    tract_rect,
                                    0.0,
                                    if is_selected_signal {
                                        egui::Color32::from_rgba_premultiplied(37, 99, 235, 170)
                                    } else {
                                        egui::Color32::from_rgba_premultiplied(59, 130, 246, 110)
                                    },
                                );
                            }
                            if let Some(branchpoint_position) = signal.branchpoint_position_1based {
                                painter.circle_filled(
                                    egui::pos2(to_x(branchpoint_position), y),
                                    if is_selected_signal { 4.1 } else { 3.1 },
                                    if is_selected_signal {
                                        egui::Color32::from_rgb(109, 40, 217)
                                    } else {
                                        egui::Color32::from_rgb(124, 58, 237)
                                    },
                                );
                            }
                        }
                    }
                    for (exon_idx, exon) in transcript.exons.iter().enumerate() {
                        let x1 = to_x(exon.start_1based);
                        let x2 = to_x(exon.end_1based);
                        let rect = egui::Rect::from_min_max(
                            egui::pos2(x1, y - 6.5),
                            egui::pos2((x2).max(x1 + 1.0), y + 6.5),
                        );
                        let fill = if transcript.has_target_feature {
                            egui::Color32::from_rgb(251, 191, 36)
                        } else {
                            egui::Color32::from_rgb(245, 158, 11)
                        };
                        painter.rect_filled(rect, 1.5, fill);
                        painter.rect_stroke(
                            rect,
                            1.5,
                            egui::Stroke::new(
                                if transcript.has_target_feature {
                                    1.4
                                } else {
                                    0.8
                                },
                                egui::Color32::from_rgb(120, 53, 15),
                            ),
                            egui::StrokeKind::Inside,
                        );
                        let phase_info = transcript
                            .exon_cds_phases
                            .get(exon_idx)
                            .filter(|phase| {
                                phase.start_1based == exon.start_1based
                                    && phase.end_1based == exon.end_1based
                            })
                            .or_else(|| {
                                transcript.exon_cds_phases.iter().find(|phase| {
                                    phase.start_1based == exon.start_1based
                                        && phase.end_1based == exon.end_1based
                                })
                            });
                        if let Some(phase_info) = phase_info {
                            let bar_width = (rect.width() * 0.15).clamp(1.4, 3.2);
                            if let Some(left_phase) = phase_info.left_cds_phase {
                                let left_rect = egui::Rect::from_min_max(
                                    rect.left_top(),
                                    egui::pos2(
                                        (rect.left() + bar_width).min(rect.right()),
                                        rect.bottom(),
                                    ),
                                );
                                painter.rect_filled(
                                    left_rect,
                                    0.0,
                                    Self::splicing_cds_phase_color(left_phase),
                                );
                            }
                            if let Some(right_phase) = phase_info.right_cds_phase {
                                let right_rect = egui::Rect::from_min_max(
                                    egui::pos2(
                                        (rect.right() - bar_width).max(rect.left()),
                                        rect.top(),
                                    ),
                                    rect.right_bottom(),
                                );
                                painter.rect_filled(
                                    right_rect,
                                    0.0,
                                    Self::splicing_cds_phase_color(right_phase),
                                );
                            }
                        }
                    }
                }

                let intron_at_pos = |pointer_pos: egui::Pos2| {
                    for (lane_idx, transcript) in view.transcripts.iter().enumerate() {
                        let y = lanes_top
                            + lane_idx as f32 * style.lane_height_px
                            + style.lane_height_px * 0.5;
                        for intron in &transcript.introns {
                            let x1 = to_x(intron.start_1based);
                            let x2 = to_x(intron.end_1based);
                            let hit_rect = egui::Rect::from_min_max(
                                egui::pos2(x1.min(x2), y - 5.0),
                                egui::pos2(x1.max(x2), y + 5.0),
                            );
                            if !hit_rect.expand(1.0).contains(pointer_pos) {
                                continue;
                            }
                            let key = Self::splicing_intron_key_for_lane_range(
                                transcript.transcript_feature_id,
                                transcript.strand.as_str(),
                                intron,
                            );
                            let signal_tuple = (
                                key.transcript_feature_id,
                                key.donor_position_1based,
                                key.acceptor_position_1based,
                            );
                            let length_bp = intron_signal_lookup
                                .get(&signal_tuple)
                                .map(|signal| signal.intron_length_bp)
                                .unwrap_or_else(|| Self::splicing_intron_range_length_bp(intron));
                            return Some((key, transcript.transcript_id.as_str(), length_bp));
                        }
                    }
                    None
                };

                let mut has_boundary_hover = false;
                let mut has_exon_hover = false;
                if let Some(pointer_pos) = response.hover_pos() {
                    let mut hovered_boundary: Option<&SplicingBoundaryMarker> = None;
                    for marker in &view.boundaries {
                        let Some(idx) = lane_index.get(&marker.transcript_feature_id) else {
                            continue;
                        };
                        let y = lanes_top
                            + *idx as f32 * style.lane_height_px
                            + style.lane_height_px * 0.5;
                        let dy = if marker.side.eq_ignore_ascii_case("donor") {
                            9.0
                        } else {
                            -9.0
                        };
                        let x = to_x(marker.position_1based);
                        let hit_rect = egui::Rect::from_min_max(
                            egui::pos2(x - 6.0, y.min(y + dy) - 4.0),
                            egui::pos2(x + 16.0, y.max(y + dy) + 4.0),
                        );
                        if hit_rect.contains(pointer_pos) {
                            hovered_boundary = Some(marker);
                            break;
                        }
                    }
                    if let Some(marker) = hovered_boundary {
                        has_boundary_hover = true;
                        response.clone().on_hover_ui_at_pointer(|ui| {
                            ui.monospace(format!(
                                "n-{} {}",
                                marker.transcript_feature_id, marker.transcript_id
                            ));
                            ui.monospace(format!(
                                "{} site @ {}  motif={}  pair={}",
                                marker.side,
                                marker.position_1based,
                                marker.motif_2bp,
                                marker.paired_motif_signature
                            ));
                            ui.label(format!(
                                "Class: {}",
                                Self::splicing_boundary_motif_class_label(
                                    marker.motif_class.as_str()
                                )
                            ));
                            ui.label(marker.annotation.as_str());
                            ui.label(format!(
                                "Partner boundary at {}",
                                marker.partner_position_1based
                            ));
                        });
                    }
                }
                if let Some(pointer_pos) = response.hover_pos() {
                    if !has_boundary_hover {
                        if let Some((key, transcript_id, length_bp)) = intron_at_pos(pointer_pos) {
                            let signal_tuple = (
                                key.transcript_feature_id,
                                key.donor_position_1based,
                                key.acceptor_position_1based,
                            );
                            let signal = intron_signal_lookup.get(&signal_tuple).copied();
                            has_boundary_hover = true;
                            response.clone().on_hover_ui_at_pointer(|ui| {
                                ui.monospace(format!(
                                    "n-{} {}",
                                    key.transcript_feature_id, transcript_id
                                ));
                                ui.monospace(format!(
                                    "intron {}..{}  len={} bp",
                                    key.donor_position_1based,
                                    key.acceptor_position_1based,
                                    length_bp
                                ));
                                ui.label(
                                    "Click to select this intron; Shift-click or Command-click toggles multi-selection.",
                                );
                                if let Some(signal) = signal {
                                    if let Some(branchpoint_position) =
                                        signal.branchpoint_position_1based
                                    {
                                        ui.label(format!(
                                            "Branchpoint-like site: {} ({})  score={:.1}",
                                            branchpoint_position,
                                            signal.branchpoint_motif,
                                            signal.branchpoint_score
                                        ));
                                    } else {
                                        ui.label(
                                            "Branchpoint-like site: none above the current heuristic",
                                        );
                                    }
                                    ui.label(signal.branchpoint_annotation.as_str());
                                    if let (Some(tract_start), Some(tract_end)) = (
                                        signal.polypyrimidine_start_1based,
                                        signal.polypyrimidine_end_1based,
                                    ) {
                                        ui.label(format!(
                                            "Polypyrimidine tract: {}..{}  pyrimidines={}%",
                                            tract_start,
                                            tract_end,
                                            (signal.polypyrimidine_fraction * 100.0).round()
                                                as usize
                                        ));
                                    } else {
                                        ui.label(
                                            "Polypyrimidine tract: none above the current heuristic",
                                        );
                                    }
                                    ui.label(signal.polypyrimidine_annotation.as_str());
                                } else {
                                    ui.label("No branchpoint/polyY heuristic row is attached yet.");
                                }
                            });
                        }
                    }
                    if !has_boundary_hover {
                        let mut hovered_exon = None;
                        for (lane_idx, transcript) in view.transcripts.iter().enumerate() {
                            let y = lanes_top
                                + lane_idx as f32 * style.lane_height_px
                                + style.lane_height_px * 0.5;
                            for (exon_idx, exon) in transcript.exons.iter().enumerate() {
                                let x1 = to_x(exon.start_1based);
                                let x2 = to_x(exon.end_1based);
                                let rect = egui::Rect::from_min_max(
                                    egui::pos2(x1, y - 6.5),
                                    egui::pos2((x2).max(x1 + 1.0), y + 6.5),
                                );
                                if !rect.expand(1.0).contains(pointer_pos) {
                                    continue;
                                }
                                let phase_info = transcript
                                    .exon_cds_phases
                                    .get(exon_idx)
                                    .filter(|phase| {
                                        phase.start_1based == exon.start_1based
                                            && phase.end_1based == exon.end_1based
                                    })
                                    .or_else(|| {
                                        transcript.exon_cds_phases.iter().find(|phase| {
                                            phase.start_1based == exon.start_1based
                                                && phase.end_1based == exon.end_1based
                                        })
                                    });
                                let is_reverse = transcript.strand.trim() == "-";
                                let entry_phase = phase_info.and_then(|phase| {
                                    transcript_entry_phase(
                                        phase.left_cds_phase,
                                        phase.right_cds_phase,
                                        is_reverse,
                                    )
                                });
                                hovered_exon = Some((
                                    transcript.transcript_feature_id,
                                    transcript.transcript_id.as_str(),
                                    exon.start_1based,
                                    exon.end_1based,
                                    phase_info.and_then(|phase| phase.left_cds_phase),
                                    phase_info.and_then(|phase| phase.right_cds_phase),
                                    entry_phase,
                                ));
                                break;
                            }
                            if hovered_exon.is_some() {
                                break;
                            }
                        }
                        if let Some((
                            feature_id,
                            transcript_id,
                            start_1based,
                            end_1based,
                            left_phase,
                            right_phase,
                            entry_phase,
                        )) = hovered_exon
                        {
                            has_exon_hover = true;
                            let exon_len = end_1based
                                .max(start_1based)
                                .saturating_sub(end_1based.min(start_1based))
                                + 1;
                            let support_count = exon_support_by_range
                                .get(&(start_1based, end_1based))
                                .copied()
                                .unwrap_or(0);
                            response.clone().on_hover_ui_at_pointer(|ui| {
                                ui.monospace(format!("n-{feature_id} {transcript_id}"));
                                ui.monospace(format!(
                                    "exon {}..{}  len={} bp  len%3={}",
                                    start_1based,
                                    end_1based,
                                    exon_len,
                                    exon_len % 3
                                ));
                                ui.label(format!(
                                    "Support {}",
                                    Self::format_support_fraction(support_count, transcript_total)
                                ));
                                ui.label(format!(
                                    "CDS flank phase: left={} right={} (0=blue, 1=amber, 2=rose)",
                                    left_phase
                                        .map(|phase| phase.to_string())
                                        .unwrap_or_else(|| "n/a".to_string()),
                                    right_phase
                                        .map(|phase| phase.to_string())
                                        .unwrap_or_else(|| "n/a".to_string()),
                                ));
                                ui.label(format!("CDS entry: {}", phase_entry_hint(entry_phase)));
                                if interactive {
                                    ui.label(
                                    "Click lane to focus this transcript feature in sequence view",
                                );
                                }
                            });
                        }
                    }
                }

                if interactive {
                    if let Some(pointer_pos) = response.hover_pos() {
                        if !has_boundary_hover && !has_exon_hover {
                            if let Some(lane_idx) = Self::splicing_lane_index_at_y(
                                pointer_pos.y,
                                lanes_top,
                                style.lane_height_px,
                                transcript_count,
                            ) {
                                let transcript = &view.transcripts[lane_idx];
                                response.clone().on_hover_ui_at_pointer(|ui| {
                                    ui.monospace(format!(
                                        "n-{} {}",
                                        transcript.transcript_feature_id, transcript.transcript_id
                                    ));
                                    ui.label(
                                    "Click to focus this transcript feature in the sequence view",
                                );
                                });
                            }
                        }
                        ui.output_mut(|o| o.cursor_icon = egui::CursorIcon::PointingHand);
                    }
                    if response.clicked() {
                        if let Some(pointer_pos) = response.interact_pointer_pos() {
                            if let Some((key, _, _)) = intron_at_pos(pointer_pos) {
                                let toggle = ui.input(|input| {
                                    input.modifiers.shift || input.modifiers.command
                                });
                                if toggle {
                                    if !self.splicing_expert_selected_intron_keys.remove(&key) {
                                        self.splicing_expert_selected_intron_keys
                                            .insert(key.clone());
                                    }
                                } else {
                                    self.splicing_expert_selected_intron_keys.clear();
                                    self.splicing_expert_selected_intron_keys.insert(key.clone());
                                }
                                self.splicing_expert_selected_intron_signal_key = Some(key);
                            } else if let Some(lane_idx) = Self::splicing_lane_index_at_y(
                                pointer_pos.y,
                                lanes_top,
                                style.lane_height_px,
                                transcript_count,
                            ) {
                                clicked_feature_id =
                                    Some(view.transcripts[lane_idx].transcript_feature_id);
                            }
                        }
                    }
                    let context_intron = response.interact_pointer_pos().and_then(intron_at_pos);
                    response.context_menu(|ui| {
                        if let Some((key, transcript_id, length_bp)) = context_intron.clone() {
                            ui.monospace(format!(
                                "n-{} {}",
                                key.transcript_feature_id, transcript_id
                            ));
                            ui.label(format!(
                                "Intron {}..{}  len={} bp",
                                key.donor_position_1based,
                                key.acceptor_position_1based,
                                length_bp
                            ));
                            if ui.button("Select only this intron").clicked() {
                                self.splicing_expert_selected_intron_keys.clear();
                                self.splicing_expert_selected_intron_keys.insert(key.clone());
                                self.splicing_expert_selected_intron_signal_key = Some(key.clone());
                                ui.close();
                            }
                            if ui.button("Toggle intron selection").clicked() {
                                if !self.splicing_expert_selected_intron_keys.remove(&key) {
                                    self.splicing_expert_selected_intron_keys.insert(key.clone());
                                }
                                self.splicing_expert_selected_intron_signal_key = Some(key.clone());
                                ui.close();
                            }
                            if ui.button("Clear selected introns").clicked() {
                                self.splicing_expert_selected_intron_keys.clear();
                                self.splicing_expert_selected_intron_signal_key = None;
                                ui.close();
                            }
                            ui.small(format!(
                                "{} intron(s) selected",
                                self.splicing_expert_selected_intron_keys.len()
                            ));
                        } else {
                            ui.label("Right-click an intron line for intron actions");
                        }
                    });
                }
            });
        clicked_feature_id
    }

    fn support_ratio_percent(support_count: usize, transcript_total: usize) -> f64 {
        if transcript_total == 0 {
            return 0.0;
        }
        support_count as f64 * 100.0 / transcript_total as f64
    }

    fn format_support_fraction(support_count: usize, transcript_total: usize) -> String {
        format!(
            "{}/{} ({:.1}%)",
            support_count,
            transcript_total,
            Self::support_ratio_percent(support_count, transcript_total)
        )
    }

    fn exon_skip_transcript_position_label(idx: usize, exon_count: usize) -> &'static str {
        match (idx, exon_count) {
            (_, 0) => "unknown",
            (_, 1) => "single",
            (0, _) => "first",
            (idx, count) if idx + 1 == count => "last",
            _ => "internal",
        }
    }

    fn splicing_matrix_should_default_collapsed(row_count: usize, exon_count: usize) -> bool {
        row_count.saturating_mul(exon_count) > SPLICING_MATRIX_EAGER_CELL_THRESHOLD
    }

    fn splicing_transition_should_default_collapsed(exon_count: usize) -> bool {
        exon_count.saturating_mul(exon_count) > SPLICING_TRANSITION_EAGER_CELL_THRESHOLD
    }

    fn splicing_attract_should_default_collapsed(view: &SplicingExpertView) -> bool {
        view.boundaries.len() > SPLICING_ATTRACT_EAGER_BOUNDARY_THRESHOLD
            || view.intron_signals.len() > SPLICING_ATTRACT_EAGER_INTRON_SIGNAL_THRESHOLD
    }

    fn mix_rgb(from: [u8; 3], to: [u8; 3], t: f32) -> [u8; 3] {
        let t = t.clamp(0.0, 1.0);
        let lerp = |a: u8, b: u8| -> u8 {
            ((a as f32) + ((b as f32) - (a as f32)) * t)
                .round()
                .clamp(0.0, 255.0) as u8
        };
        [
            lerp(from[0], to[0]),
            lerp(from[1], to[1]),
            lerp(from[2], to[2]),
        ]
    }

    fn splicing_matrix_cell_colors(
        present: bool,
        support_ratio: f32,
    ) -> (egui::Color32, egui::Color32) {
        let ratio = support_ratio.clamp(0.0, 1.0);
        if present {
            let rgb = Self::mix_rgb([191, 219, 254], [30, 64, 175], ratio);
            let bg = egui::Color32::from_rgb(rgb[0], rgb[1], rgb[2]);
            let fg = if ratio >= 0.42 {
                egui::Color32::WHITE
            } else {
                egui::Color32::from_rgb(15, 23, 42)
            };
            (bg, fg)
        } else {
            let rgb = Self::mix_rgb([248, 250, 252], [219, 234, 254], ratio);
            (
                egui::Color32::from_rgb(rgb[0], rgb[1], rgb[2]),
                egui::Color32::from_rgb(71, 85, 105),
            )
        }
    }

    fn splicing_transition_cell_colors(support_ratio: f32) -> (egui::Color32, egui::Color32) {
        let ratio = support_ratio.clamp(0.0, 1.0);
        if ratio > 0.0 {
            let rgb = Self::mix_rgb([220, 252, 231], [22, 101, 52], ratio);
            let bg = egui::Color32::from_rgb(rgb[0], rgb[1], rgb[2]);
            let fg = if ratio >= 0.42 {
                egui::Color32::WHITE
            } else {
                egui::Color32::from_rgb(20, 83, 45)
            };
            (bg, fg)
        } else {
            (
                egui::Color32::from_rgb(248, 250, 252),
                egui::Color32::from_rgb(100, 116, 139),
            )
        }
    }

    fn splicing_exon_length_bp(exon: &SplicingExonSummary) -> usize {
        exon.end_1based
            .max(exon.start_1based)
            .saturating_sub(exon.end_1based.min(exon.start_1based))
            + 1
    }

    fn splicing_exon_length_mod3(exon: &SplicingExonSummary) -> usize {
        Self::splicing_exon_length_bp(exon) % 3
    }

    fn splicing_exon_mod3_colors(mod3: usize) -> (egui::Color32, egui::Color32) {
        match mod3 % 3 {
            0 => (
                egui::Color32::from_rgb(219, 234, 254),
                egui::Color32::from_rgb(30, 64, 175),
            ),
            1 => (
                egui::Color32::from_rgb(254, 243, 199),
                egui::Color32::from_rgb(146, 64, 14),
            ),
            _ => (
                egui::Color32::from_rgb(255, 228, 230),
                egui::Color32::from_rgb(159, 18, 57),
            ),
        }
    }

    fn splicing_cds_phase_color(phase: u8) -> egui::Color32 {
        match phase % 3 {
            0 => egui::Color32::from_rgb(37, 99, 235),
            1 => egui::Color32::from_rgb(217, 119, 6),
            _ => egui::Color32::from_rgb(225, 29, 72),
        }
    }

    fn current_splicing_expert_view_for_primary_map(&mut self) -> Option<SplicingExpertView> {
        self.refresh_description_cache();
        if let Some(FeatureExpertView::Splicing(view)) = self.description_cache_expert_view.clone()
        {
            return Some(view);
        }
        self.get_selected_feature_id()
            .filter(|feature_id| self.feature_supports_splicing_expert(*feature_id))
            .and_then(|feature_id| self.splicing_expert_view_for_feature(feature_id).ok())
    }

    fn rna_read_mapping_button_hover_text(seed_view: Option<&SplicingExpertView>) -> String {
        if let Some(view) = seed_view {
            format!(
                "Open the dedicated RNA-read Mapping workspace for {} feature n-{}",
                view.group_label, view.target_feature_id
            )
        } else {
            "Select an mRNA, ncRNA, misc_RNA, transcript, exon, gene, or CDS feature first to seed the RNA-read Mapping workspace".to_string()
        }
    }

    fn open_current_rna_read_mapping_workspace(&mut self) -> Result<SplicingExpertView, String> {
        let Some(view) = self.current_splicing_expert_view_for_primary_map() else {
            return Err(
                "Select an mRNA, ncRNA, misc_RNA, transcript, exon, gene, or CDS feature first to seed RNA-read Mapping"
                    .to_string(),
            );
        };
        self.open_rna_read_mapping_workspace_for_view(&view);
        Ok(view)
    }

    fn focus_rna_read_mapping_workspace_view(
        &mut self,
        ctx: &egui::Context,
        view: &SplicingExpertView,
    ) {
        let viewport_id = Self::rna_read_mapping_viewport_id(&view.seq_id, view.target_feature_id);
        self.log_rna_read_mapping_status(
            view,
            "focus requested",
            self.rna_read_mapping_window_pending_initial_render,
        );
        if ctx.embed_viewports() {
            let embedded_window_id = Self::rna_read_mapping_embedded_window_id(view);
            ctx.move_to_top(egui::LayerId::new(
                egui::Order::Foreground,
                embedded_window_id,
            ));
            ctx.request_repaint();
            return;
        }
        ctx.send_viewport_cmd_to(viewport_id, egui::ViewportCommand::Visible(true));
        ctx.send_viewport_cmd_to(viewport_id, egui::ViewportCommand::Focus);
        ctx.request_repaint();
    }

    fn focus_dotplot_workspace_view(&self, ctx: &egui::Context) {
        let Some(viewport_seq_id) = self.dotplot_window_identity_seq_id() else {
            return;
        };
        let viewport_id = Self::dotplot_viewport_id(&viewport_seq_id);
        ctx.send_viewport_cmd_to(viewport_id, egui::ViewportCommand::Visible(true));
        ctx.send_viewport_cmd_to(viewport_id, egui::ViewportCommand::Focus);
    }

    fn rna_read_scope_selection_label(
        view: &SplicingExpertView,
        scope: SplicingScopePreset,
    ) -> String {
        let target = view.group_label.trim();
        match scope {
            SplicingScopePreset::AllOverlappingAnyStrand => {
                "All overlapping genes incl. antisense (any strand)".to_string()
            }
            SplicingScopePreset::TargetGroupAnyStrand => {
                format!("Target gene/group {target} (any strand)")
            }
            SplicingScopePreset::AllOverlappingTargetStrand => {
                "All overlapping genes (target-gene strand)".to_string()
            }
            SplicingScopePreset::TargetGroupTargetStrand => {
                format!("Target gene/group {target} (target-gene strand)")
            }
        }
    }

    fn rna_read_origin_mode_selection_label(
        view: &SplicingExpertView,
        mode: RnaReadOriginMode,
    ) -> String {
        let target = view.group_label.trim();
        match mode {
            RnaReadOriginMode::SingleGene => format!("single_gene ({target})"),
            RnaReadOriginMode::MultiGeneSparse => {
                "multi_gene_sparse (explicit gene list)".to_string()
            }
        }
    }

    fn rna_read_gene_scope_summary(
        view: &SplicingExpertView,
        scope: SplicingScopePreset,
        origin_mode: RnaReadOriginMode,
        target_gene_ids: &str,
    ) -> (String, egui::Color32) {
        let target = view.group_label.trim();
        let region = format!(
            "{}:{}..{}",
            view.seq_id, view.region_start_1based, view.region_end_1based
        );
        let strand_scope = match scope {
            SplicingScopePreset::AllOverlappingAnyStrand => {
                format!(
                    "all genes overlapping {region} on any strand, including antisense/opposite-strand genes relative to '{target}'"
                )
            }
            SplicingScopePreset::TargetGroupAnyStrand => {
                format!("target gene '{target}' on any annotated strand within {region}")
            }
            SplicingScopePreset::AllOverlappingTargetStrand => {
                format!("all genes overlapping {region} on the selected target gene/group strand")
            }
            SplicingScopePreset::TargetGroupTargetStrand => {
                format!(
                    "target gene '{target}' on the selected target gene/group strand within {region}"
                )
            }
        };
        match origin_mode {
            RnaReadOriginMode::SingleGene => (
                format!(
                    "Working set: {strand_scope}. Gene expansion mode is single_gene, so only the current target group '{target}' is used for transcript templates."
                ),
                egui::Color32::from_rgb(71, 85, 105),
            ),
            RnaReadOriginMode::MultiGeneSparse => {
                let genes = Self::parse_rna_target_gene_ids(target_gene_ids);
                if genes.is_empty() {
                    (
                        format!(
                            "Working set: {strand_scope}. Gene expansion mode is multi_gene_sparse, but no explicit Target genes are listed yet, so no additional gene-specific sparse expansion is configured."
                        ),
                        egui::Color32::from_rgb(180, 83, 9),
                    )
                } else {
                    (
                        format!(
                            "Working set: {strand_scope}. Gene expansion mode is multi_gene_sparse with explicit target genes: {}.",
                            genes.join(", ")
                        ),
                        egui::Color32::from_rgb(71, 85, 105),
                    )
                }
            }
        }
    }

    fn rna_read_scope_cell_included(
        scope: SplicingScopePreset,
        is_target_group: bool,
        is_target_strand: bool,
    ) -> bool {
        (!scope.restrict_to_target_group() || is_target_group)
            && (!scope.restrict_to_target_strand() || is_target_strand)
    }

    fn render_rna_read_scope_eligibility_sketch(
        &self,
        ui: &mut egui::Ui,
        view: &SplicingExpertView,
        scope: SplicingScopePreset,
        origin_mode: RnaReadOriginMode,
    ) {
        ui.small(
            egui::RichText::new(format!(
                "Eligibility sketch for transcript-like RNA features around '{}':",
                view.group_label
            ))
            .color(egui::Color32::from_rgb(71, 85, 105)),
        );
        egui::Grid::new(format!(
            "rna_scope_eligibility_grid_{}_{}",
            view.seq_id, view.target_feature_id
        ))
        .num_columns(3)
        .striped(true)
        .show(ui, |ui| {
            ui.small("");
            ui.small("Target-gene strand");
            ui.small("Antisense to target gene");
            ui.end_row();
            for (group_label, is_target_group) in [
                (format!("Target gene/group '{}'", view.group_label), true),
                (
                    "Other overlapping / antisense gene/group".to_string(),
                    false,
                ),
            ] {
                ui.small(group_label);
                for (strand_label, is_target_strand) in [("indexed", true), ("indexed", false)] {
                    let included = Self::rna_read_scope_cell_included(
                        scope,
                        is_target_group,
                        is_target_strand,
                    );
                    let (label, color) = if included {
                        (strand_label, egui::Color32::from_rgb(21, 128, 61))
                    } else {
                        ("excluded", egui::Color32::from_rgb(148, 163, 184))
                    };
                    ui.colored_label(color, label);
                }
                ui.end_row();
            }
        });
        ui.small(
            egui::RichText::new(
                "Overlap means any transcript-like RNA feature sharing at least one bp with the target ROI; full coverage is not required.",
            )
            .color(egui::Color32::from_rgb(100, 116, 139)),
        );
        ui.small(
            egui::RichText::new(
                "Only transcript-like RNA features (`mRNA`, `transcript`, `ncRNA`, `misc_RNA`) contribute templates. Multi-exon features contribute exon bodies plus exon-exon junction templates; single-span features contribute body sequence only.",
            )
            .color(egui::Color32::from_rgb(100, 116, 139)),
        );
        let expansion_note = match origin_mode {
            RnaReadOriginMode::SingleGene => {
                "Gene expansion mode `single_gene` is still one run: only the current target gene/group contributes transcript templates."
            }
            RnaReadOriginMode::MultiGeneSparse => {
                "Gene expansion mode `multi_gene_sparse` is still one run: it adds transcript templates from the explicit Target genes list on top of the current target gene/group."
            }
        };
        ui.small(egui::RichText::new(expansion_note).color(egui::Color32::from_rgb(100, 116, 139)));
    }

    fn render_splicing_expert_window(&mut self, ctx: &egui::Context) {
        if !self.show_splicing_expert_window {
            return;
        }
        let Some(view) = self.splicing_expert_window_view.clone() else {
            self.show_splicing_expert_window = false;
            return;
        };
        let pending_initial_render = self.splicing_expert_window_pending_initial_render;
        let focus_requested = self.splicing_expert_window_focus_requested;
        self.log_splicing_expert_status(&view, "render begin", pending_initial_render);
        let title = Self::splicing_expert_window_title(&view);
        let viewport_id = Self::splicing_expert_viewport_id(&view.seq_id, view.target_feature_id);
        let default_size = Self::splicing_expert_window_default_size();
        let min_size = Self::splicing_expert_window_min_size();
        let content_min_size = Self::splicing_expert_window_content_min_size();
        if ctx.embed_viewports() {
            self.render_splicing_expert_embedded_window_shell(
                ctx,
                title.as_str(),
                &view,
                default_size,
                content_min_size,
                pending_initial_render,
                focus_requested,
            );
            if self.splicing_expert_window_focus_requested {
                self.focus_splicing_expert_window_view(ctx, &view);
                self.splicing_expert_window_focus_requested = false;
            }
            return;
        }
        let builder = egui::ViewportBuilder::default()
            .with_title(title.clone())
            .with_inner_size([default_size.x, default_size.y])
            .with_min_inner_size([min_size.x, min_size.y]);
        ctx.show_viewport_immediate(viewport_id, builder, |ctx, class| {
            if class == egui::ViewportClass::EmbeddedWindow {
                self.render_splicing_expert_embedded_window_shell(
                    ctx,
                    title.as_str(),
                    &view,
                    default_size,
                    content_min_size,
                    pending_initial_render,
                    focus_requested,
                );
                return;
            }

            crate::egui_compat::show_central_panel(ctx, egui::CentralPanel::default(), |ui| {
                let backdrop_settings = current_window_backdrop_settings();
                paint_window_backdrop(ui, WindowBackdropKind::Splicing, &backdrop_settings);
                egui::ScrollArea::both()
                    .id_salt(format!(
                        "splicing_expert_scroll_viewport_{}_{}",
                        view.seq_id, view.target_feature_id
                    ))
                    .auto_shrink([false, false])
                    .show(ui, |ui| {
                        scroll_input_policy::apply_scrollarea_keyboard_navigation(
                            ui,
                            scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
                        );
                        ui.set_min_size(content_min_size);
                        self.render_splicing_expert_window_body(
                            ctx,
                            ui,
                            &view,
                            "splicing_window_viewport",
                            pending_initial_render,
                        );
                    });
            });

            if crate::app::GENtleApp::viewport_close_requested_or_shortcut(ctx) {
                self.show_splicing_expert_window = false;
            }
        });
        if self.splicing_expert_window_focus_requested {
            self.focus_splicing_expert_window_view(ctx, &view);
            self.splicing_expert_window_focus_requested = false;
        }
    }

    fn render_splicing_expert_window_body(
        &mut self,
        ctx: &egui::Context,
        ui: &mut egui::Ui,
        view: &SplicingExpertView,
        id_namespace: &str,
        pending_initial_render: bool,
    ) {
        self.render_splicing_expert_transcript_quick_actions(ui, view);
        if pending_initial_render {
            self.log_splicing_expert_status(view, "first frame deferred", true);
            ui.add_space(6.0);
            ui.label(
                egui::RichText::new(
                    "Preparing the Splicing Expert workspace. Detailed lane rendering will appear on the next repaint.",
                )
                .size(10.0)
                .color(egui::Color32::from_rgb(71, 85, 105)),
            );
            ctx.request_repaint();
            self.splicing_expert_window_pending_initial_render = false;
            self.log_splicing_expert_status(view, "first frame queued repaint", false);
            return;
        }
        self.log_splicing_expert_status(view, "rendering ATtRACT evidence", false);
        self.render_splicing_attract_evidence_section(ui, view);
        self.log_splicing_expert_status(view, "rendering RNA-read evidence", false);
        self.render_splicing_rna_read_evidence_section(ui, view);
        self.log_splicing_expert_status(view, "rendering detailed view", false);
        self.render_splicing_expert_view_ui(ui, view, id_namespace);
        self.log_splicing_expert_status(view, "render complete", false);
    }

    fn render_splicing_expert_transcript_quick_actions(
        &mut self,
        ui: &mut egui::Ui,
        view: &SplicingExpertView,
    ) {
        let transcript_rows: Vec<(usize, String)> = view
            .transcripts
            .iter()
            .map(|row| {
                (
                    row.transcript_feature_id,
                    format!("n-{} {}", row.transcript_feature_id, row.transcript_id),
                )
            })
            .collect();
        let _ = self.splicing_selected_transcript_feature_id(view);
        ui.horizontal_wrapped(|ui| {
            ui.label(
                egui::RichText::new("Window guide [?]")
                    .size(9.0)
                    .color(egui::Color32::from_rgb(71, 85, 105)),
            )
            .on_hover_text(Self::splicing_expert_window_help_text());
            ui.label(
                egui::RichText::new(
                    "Annotation structure and transcript quick actions stay here; RNA-read runs now live in a dedicated mapping workspace.",
                )
                .size(9.0)
                .color(egui::Color32::from_rgb(100, 116, 139)),
            );
        });
        ui.horizontal_wrapped(|ui| {
            ui.label("Transcript")
                .on_hover_text("Select the transcript lane used by transcript-level quick actions");
            egui::ComboBox::from_id_salt((
                "splicing_expert_transcript_selector",
                view.seq_id.as_str(),
                view.target_feature_id,
            ))
            .selected_text(
                self.splicing_expert_selected_transcript_feature_id
                    .and_then(|feature_id| {
                        transcript_rows
                            .iter()
                            .find(|row| row.0 == feature_id)
                            .map(|row| row.1.clone())
                    })
                    .unwrap_or_else(|| "<none>".to_string()),
            )
            .show_ui(ui, |ui| {
                for (feature_id, label) in &transcript_rows {
                    ui.selectable_value(
                        &mut self.splicing_expert_selected_transcript_feature_id,
                        Some(*feature_id),
                        label,
                    );
                }
            });
            if ui
                .button("Derive group transcripts")
                .on_hover_text(
                    "Derive cDNA transcript sequences for all transcript lanes in this splicing group",
                )
                .clicked()
            {
                let _ = self.derive_transcript_sequences_with_compact_feedback(
                    view.seq_id.clone(),
                    vec![view.target_feature_id],
                    Some(SplicingScopePreset::AllOverlappingAnyStrand),
                    &format!("splicing group '{}'", view.group_label),
                );
            }
            if ui
                .button("Derive all mRNA")
                .on_hover_text(
                    "Derive cDNA transcript sequences for every mRNA/transcript feature on this sequence",
                )
                .clicked()
            {
                let _ = self.derive_transcript_sequences_with_compact_feedback(
                    view.seq_id.clone(),
                    vec![],
                    None,
                    &format!("all transcript features on '{}'", view.seq_id),
                );
            }
            if ui
                .button("Derive + Dotplot")
                .on_hover_text(
                    "Derive selected transcript sequence, switch to transcript context, and open pairwise transcript-vs-genomic dotplot",
                )
                .clicked()
            {
                self.derive_selected_transcript_and_open_dotplot(view);
            }
        });
        ui.horizontal_wrapped(|ui| {
            let action = ui.button("Send Group ROI -> Primer/qPCR").on_hover_text(
                "Seed Primer/qPCR design ROI from current splicing-group genomic interval and open the dedicated PCR Designer",
            );
            if action.clicked() {
                if let Some((start, end_exclusive)) = Self::splicing_group_roi_range_0based(view) {
                    self.seed_primer_design_roi_0based(
                        start,
                        end_exclusive,
                        &format!("splicing group '{}'", view.group_label),
                    );
                } else {
                    self.op_status = "Could not derive a valid ROI from splicing group bounds"
                        .to_string();
                }
            }
            let shared_qpcr = ui
                .button("Design shared-transcript qPCR")
                .on_hover_text(
                    "Seed qPCR Designer from this splicing-group ROI and require exon or exon-chain context shared across the group's transcripts",
                );
            if shared_qpcr.clicked()
                && let Err(err) = self.seed_qpcr_from_splicing_view(
                    view,
                    QpcrTranscriptIntentUiMode::SharedAcrossTranscripts,
                )
            {
                self.op_status = err;
            }
            let specific_qpcr = ui
                .button("Design transcript-specific qPCR")
                .on_hover_text(
                    "Seed qPCR Designer from this splicing-group ROI and reuse the currently selected transcript lane for transcript-specific assay design",
                );
            if specific_qpcr.clicked()
                && let Err(err) = self.seed_qpcr_from_splicing_view(
                    view,
                    QpcrTranscriptIntentUiMode::SpecificTranscript,
                )
            {
                self.op_status = err;
            }
            ui.label(
                egui::RichText::new("Quick actions: keep the generic ROI handoff, or open PCR Designer directly in shared-transcript / transcript-specific qPCR mode using the current splicing context.")
                    .size(9.0)
                    .color(egui::Color32::from_rgb(100, 116, 139)),
            );
        });
        self.render_splicing_exon_skip_planning_panel(ui, view);
        ui.separator();
    }

    fn splicing_exon_skip_candidate_id(ordinal: usize) -> String {
        format!("exon_{ordinal}")
    }

    fn splicing_exon_skip_selected_ids_sorted(&self) -> Vec<String> {
        self.splicing_exon_skip_selected_candidate_ids
            .iter()
            .cloned()
            .collect::<Vec<_>>()
    }

    fn splicing_exon_skip_ui_criteria(
        &self,
        seq_id: &str,
        extra_selection: Option<SplicingRange>,
    ) -> Vec<ExonSkipSelectionCriterion> {
        let mut criteria = Vec::new();
        let manual_ids = self.splicing_exon_skip_selected_ids_sorted();
        if !manual_ids.is_empty() {
            criteria.push(ExonSkipSelectionCriterion::ManualExonIds {
                candidate_ids: manual_ids,
            });
        }
        if let Some(interval) = extra_selection {
            criteria.push(ExonSkipSelectionCriterion::CurrentMapSelection {
                start_1based: interval.start_1based,
                end_1based: interval.end_1based,
            });
        }
        let kind = self.splicing_exon_skip_overlap_kind.trim();
        let label = self.splicing_exon_skip_overlap_label.trim();
        if !kind.is_empty() || !label.is_empty() {
            criteria.push(ExonSkipSelectionCriterion::FeatureOverlap {
                query: SequenceFeatureQuery {
                    seq_id: seq_id.to_string(),
                    kind_in: if kind.is_empty() {
                        vec![]
                    } else {
                        kind.split(',')
                            .map(str::trim)
                            .filter(|value| !value.is_empty())
                            .map(|value| value.to_string())
                            .collect()
                    },
                    label_contains: (!label.is_empty()).then(|| label.to_string()),
                    ..SequenceFeatureQuery::default()
                },
            });
        }
        criteria
    }

    fn build_splicing_exon_skip_plan_from_ui(
        &mut self,
        view: &SplicingExpertView,
        transcript_feature_id: usize,
        extra_selection: Option<SplicingRange>,
    ) {
        let criteria = self.splicing_exon_skip_ui_criteria(&view.seq_id, extra_selection);
        let Some(result) =
            self.apply_operation_with_feedback_and_result(Operation::PlanExonSkippedIsoform {
                seq_id: view.seq_id.clone(),
                transcript_feature_id,
                criteria,
                plan_id: None,
            })
        else {
            return;
        };
        let Some(plan) = result.exon_skip_selection_plan else {
            self.op_status = "Exon-skip planning completed without a plan payload".to_string();
            return;
        };
        self.splicing_exon_skip_selected_candidate_ids =
            plan.selected_candidate_ids.iter().cloned().collect();
        self.op_status = format!(
            "Prepared exon-skip plan '{}' with {} selected exon(s).",
            plan.plan_id,
            plan.selected_candidate_ids.len()
        );
        self.splicing_exon_skip_plan = Some(plan);
    }

    fn materialize_splicing_exon_skip_plan_from_ui(&mut self) {
        let Some(plan) = self.splicing_exon_skip_plan.clone() else {
            self.op_status = "Build an exon-skip plan before materializing an isoform".to_string();
            return;
        };
        let selected_candidate_ids = self.splicing_exon_skip_selected_ids_sorted();
        let Some(result) = self.apply_operation_with_feedback_and_result(
            Operation::MaterializeExonSkippedIsoform {
                plan_id: plan.plan_id.clone(),
                selected_candidate_ids,
                output_prefix: Some(format!("{}__exon_skip", plan.seq_id)),
                return_kinds: vec![],
            },
        ) else {
            return;
        };
        self.last_created_seq_ids = result.created_seq_ids.clone();
        self.export_pool_inputs_text = self.last_created_seq_ids.join(", ");
        let created = if self.last_created_seq_ids.is_empty() {
            "no sequences".to_string()
        } else {
            Self::summarize_status_items(&self.last_created_seq_ids, 4, ", ")
        };
        self.op_status = format!(
            "Materialized exon-skip plan '{}' and created {}.",
            plan.plan_id, created
        );
        self.splicing_exon_skip_plan = None;
    }

    fn render_splicing_exon_skip_planning_panel(
        &mut self,
        ui: &mut egui::Ui,
        view: &SplicingExpertView,
    ) {
        let Some(transcript_feature_id) = self.splicing_selected_transcript_feature_id(view) else {
            return;
        };
        let Some(lane) = view
            .transcripts
            .iter()
            .find(|lane| lane.transcript_feature_id == transcript_feature_id)
        else {
            return;
        };
        ui.add_space(4.0);
        ui.group(|ui| {
            ui.horizontal_wrapped(|ui| {
                ui.label(
                    egui::RichText::new("Exon skip planning")
                        .strong()
                        .color(egui::Color32::from_rgb(51, 65, 85)),
                );
                ui.small(
                    "Phase 1 selects exon candidates; phase 2 creates genomic annotation + cDNA.",
                );
            });
            ui.horizontal_wrapped(|ui| {
                for (idx, exon) in lane.exons.iter().enumerate() {
                    let candidate_id = Self::splicing_exon_skip_candidate_id(idx + 1);
                    let exon_len = exon
                        .end_1based
                        .max(exon.start_1based)
                        .saturating_sub(exon.end_1based.min(exon.start_1based))
                        + 1;
                    let frame_cue = ExonLengthFrameCue::from_length(exon_len);
                    let phase_info = lane
                        .exon_cds_phases
                        .get(idx)
                        .filter(|phase| {
                            phase.start_1based == exon.start_1based
                                && phase.end_1based == exon.end_1based
                        })
                        .or_else(|| {
                            lane.exon_cds_phases.iter().find(|phase| {
                                phase.start_1based == exon.start_1based
                                    && phase.end_1based == exon.end_1based
                            })
                        });
                    let entry_phase = phase_info.and_then(|phase| {
                        transcript_entry_phase(
                            phase.left_cds_phase,
                            phase.right_cds_phase,
                            lane.strand.trim() == "-",
                        )
                    });
                    let mut selected = self
                        .splicing_exon_skip_selected_candidate_ids
                        .contains(&candidate_id);
                    let label = format!(
                        "{} {}..{}",
                        candidate_id, exon.start_1based, exon.end_1based
                    );
                    let plan_candidate = self.splicing_exon_skip_plan.as_ref().and_then(|plan| {
                        plan.candidate_exons
                            .iter()
                            .find(|candidate| candidate.candidate_id == candidate_id)
                    });
                    let support_count = plan_candidate
                        .map(|candidate| candidate.support_transcript_count)
                        .or_else(|| {
                            view.unique_exons
                                .iter()
                                .find(|unique| {
                                    unique.start_1based == exon.start_1based
                                        && unique.end_1based == exon.end_1based
                                })
                                .map(|unique| unique.support_transcript_count)
                        })
                        .unwrap_or(0);
                    let support_total = plan_candidate
                        .map(|candidate| candidate.support_transcript_total)
                        .unwrap_or(view.transcript_count.max(1));
                    let mut hover_lines = vec![
                        "Select this exon candidate to skip in the materialized isoform."
                            .to_string(),
                        format!(
                            "position: {} of {} ({})",
                            idx + 1,
                            lane.exons.len(),
                            plan_candidate
                                .map(|candidate| candidate.transcript_position.as_str())
                                .unwrap_or_else(|| {
                                    Self::exon_skip_transcript_position_label(idx, lane.exons.len())
                                })
                        ),
                        format!(
                            "support: {}",
                            Self::format_support_fraction(support_count, support_total)
                        ),
                        format!(
                            "length={} bp; len%3={} ({})",
                            exon_len,
                            frame_cue.length_mod3,
                            RenderDna::exon_length_mod3_color_label(frame_cue.length_mod3 as u8)
                        ),
                        frame_cue.skip_frame_hint(true).to_string(),
                    ];
                    if let Some(candidate) = plan_candidate {
                        hover_lines.push(format!(
                            "coding skip={} bp; coding%3={} ({})",
                            candidate.coding_skip_bp,
                            candidate.coding_skip_mod3,
                            candidate.coding_context
                        ));
                        hover_lines.push(if candidate.frame_neutral_coding_skip {
                            "coding skip is frame-neutral".to_string()
                        } else {
                            "coding skip changes the coding frame".to_string()
                        });
                        hover_lines.push(format!(
                            "introns: upstream={} downstream={}",
                            candidate
                                .upstream_intron_bp
                                .map(|value| format!("{value} bp"))
                                .unwrap_or_else(|| "n/a".to_string()),
                            candidate
                                .downstream_intron_bp
                                .map(|value| format!("{value} bp"))
                                .unwrap_or_else(|| "n/a".to_string())
                        ));
                        if let Some(note) = candidate.coding_frame_note.as_ref() {
                            hover_lines.push(note.clone());
                        }
                    } else {
                        hover_lines.push(
                            "Build a plan to compute CDS-only skip length and flanking intron lengths."
                                .to_string(),
                        );
                    }
                    hover_lines.push(format!(
                        "CDS entry phase: {} ({})",
                        entry_phase
                            .map(|phase| phase.to_string())
                            .unwrap_or_else(|| "n/a".to_string()),
                        phase_entry_hint(entry_phase)
                    ));
                    if ui
                        .checkbox(&mut selected, label)
                        .on_hover_text(hover_lines.join("\n"))
                        .changed()
                    {
                        if selected {
                            self.splicing_exon_skip_selected_candidate_ids
                                .insert(candidate_id);
                        } else {
                            self.splicing_exon_skip_selected_candidate_ids
                                .remove(&candidate_id);
                        }
                    }
                }
            });
            ui.horizontal_wrapped(|ui| {
                if ui
                    .button("Add len%3=0")
                    .on_hover_text("Add exon candidates whose length is a multiple of 3")
                    .clicked()
                {
                    for (idx, exon) in lane.exons.iter().enumerate() {
                        let len = exon
                            .end_1based
                            .max(exon.start_1based)
                            .saturating_sub(exon.end_1based.min(exon.start_1based))
                            + 1;
                        if ExonLengthFrameCue::from_length(len).frame_neutral_length {
                            self.splicing_exon_skip_selected_candidate_ids
                                .insert(Self::splicing_exon_skip_candidate_id(idx + 1));
                        }
                    }
                }
                if ui
                    .button("Add len%3=1")
                    .on_hover_text("Add exon candidates whose length leaves one extra base modulo 3")
                    .clicked()
                {
                    for (idx, exon) in lane.exons.iter().enumerate() {
                        let len = exon
                            .end_1based
                            .max(exon.start_1based)
                            .saturating_sub(exon.end_1based.min(exon.start_1based))
                            + 1;
                        if ExonLengthFrameCue::from_length(len).length_mod3 == 1 {
                            self.splicing_exon_skip_selected_candidate_ids
                                .insert(Self::splicing_exon_skip_candidate_id(idx + 1));
                        }
                    }
                }
                if ui
                    .button("Add len%3=2")
                    .on_hover_text("Add exon candidates whose length leaves two extra bases modulo 3")
                    .clicked()
                {
                    for (idx, exon) in lane.exons.iter().enumerate() {
                        let len = exon
                            .end_1based
                            .max(exon.start_1based)
                            .saturating_sub(exon.end_1based.min(exon.start_1based))
                            + 1;
                        if ExonLengthFrameCue::from_length(len).length_mod3 == 2 {
                            self.splicing_exon_skip_selected_candidate_ids
                                .insert(Self::splicing_exon_skip_candidate_id(idx + 1));
                        }
                    }
                }
            });
            ui.horizontal_wrapped(|ui| {
                for value in 0usize..=2 {
                    if ui
                        .button(format!("Add coding%3={value}"))
                        .on_hover_text(format!(
                            "Add planned exon candidates whose CDS-overlap skip length modulo 3 is {value}"
                        ))
                        .clicked()
                    {
                        if let Some(plan) = self.splicing_exon_skip_plan.as_ref() {
                            for candidate in &plan.candidate_exons {
                                if candidate.coding_skip_bp > 0
                                    && candidate.coding_skip_mod3 == value
                                {
                                    self.splicing_exon_skip_selected_candidate_ids
                                        .insert(candidate.candidate_id.clone());
                                }
                            }
                        } else {
                            self.op_status =
                                "Build an exon-skip plan before selecting by coding%3".to_string();
                        }
                    }
                }
                if ui
                    .button("Add CDS-only")
                    .on_hover_text("Add planned exon candidates that are fully CDS-overlapping")
                    .clicked()
                {
                    if let Some(plan) = self.splicing_exon_skip_plan.as_ref() {
                        for candidate in &plan.candidate_exons {
                            if candidate.coding_context == "cds_only" {
                                self.splicing_exon_skip_selected_candidate_ids
                                    .insert(candidate.candidate_id.clone());
                            }
                        }
                    } else {
                        self.op_status =
                            "Build an exon-skip plan before selecting by coding context".to_string();
                    }
                }
                if ui
                    .button("Add UTR-only")
                    .on_hover_text("Add planned exon candidates with no CDS-overlapping bases")
                    .clicked()
                {
                    if let Some(plan) = self.splicing_exon_skip_plan.as_ref() {
                        for candidate in &plan.candidate_exons {
                            if candidate.coding_context == "utr_only" {
                                self.splicing_exon_skip_selected_candidate_ids
                                    .insert(candidate.candidate_id.clone());
                            }
                        }
                    } else {
                        self.op_status =
                            "Build an exon-skip plan before selecting by coding context".to_string();
                    }
                }
            });
            ui.horizontal_wrapped(|ui| {
                if ui
                    .button("Add phase 0 starts")
                    .on_hover_text(
                        "Add exon candidates whose CDS entry phase is 0: they start at a codon boundary/new amino acid in this transcript",
                    )
                    .clicked()
                {
                    for (idx, exon) in lane.exons.iter().enumerate() {
                        let phase_info = lane
                            .exon_cds_phases
                            .get(idx)
                            .filter(|phase| {
                                phase.start_1based == exon.start_1based
                                    && phase.end_1based == exon.end_1based
                            })
                            .or_else(|| {
                                lane.exon_cds_phases.iter().find(|phase| {
                                    phase.start_1based == exon.start_1based
                                        && phase.end_1based == exon.end_1based
                                })
                            });
                        let entry_phase = phase_info.and_then(|phase| {
                            transcript_entry_phase(
                                phase.left_cds_phase,
                                phase.right_cds_phase,
                                lane.strand.trim() == "-",
                            )
                        });
                        if entry_phase.map(|phase| phase % 3) == Some(0) {
                            self.splicing_exon_skip_selected_candidate_ids
                                .insert(Self::splicing_exon_skip_candidate_id(idx + 1));
                        }
                    }
                }
                if ui
                    .button("Add split-codon starts")
                    .on_hover_text(
                        "Add exon candidates whose CDS entry phase is 1 or 2: they enter within a split codon in this transcript",
                    )
                    .clicked()
                {
                    for (idx, exon) in lane.exons.iter().enumerate() {
                        let phase_info = lane
                            .exon_cds_phases
                            .get(idx)
                            .filter(|phase| {
                                phase.start_1based == exon.start_1based
                                    && phase.end_1based == exon.end_1based
                            })
                            .or_else(|| {
                                lane.exon_cds_phases.iter().find(|phase| {
                                    phase.start_1based == exon.start_1based
                                        && phase.end_1based == exon.end_1based
                                })
                            });
                        let entry_phase = phase_info.and_then(|phase| {
                            transcript_entry_phase(
                                phase.left_cds_phase,
                                phase.right_cds_phase,
                                lane.strand.trim() == "-",
                            )
                        });
                        if matches!(entry_phase.map(|phase| phase % 3), Some(1 | 2)) {
                            self.splicing_exon_skip_selected_candidate_ids
                                .insert(Self::splicing_exon_skip_candidate_id(idx + 1));
                        }
                    }
                }
            });
            ui.horizontal_wrapped(|ui| {
                if ui
                    .button("Add current selection")
                    .on_hover_text("Select any exon candidate that overlaps the active map/text selection")
                    .clicked()
                {
                    if let Some((start, end_exclusive)) = self.current_selection_range_0based() {
                        let start_1based = start.saturating_add(1);
                        let end_1based = end_exclusive;
                        for (idx, exon) in lane.exons.iter().enumerate() {
                            if exon.end_1based >= start_1based && exon.start_1based <= end_1based {
                                self.splicing_exon_skip_selected_candidate_ids
                                    .insert(Self::splicing_exon_skip_candidate_id(idx + 1));
                            }
                        }
                    } else {
                        self.op_status =
                            "No active selection to add to exon-skip planning".to_string();
                    }
                }
                if ui
                    .button("Clear selected exons")
                    .on_hover_text("Clear the currently checked exon-skip candidates")
                    .clicked()
                {
                    self.splicing_exon_skip_selected_candidate_ids.clear();
                    self.splicing_exon_skip_plan = None;
                }
            });
            ui.horizontal_wrapped(|ui| {
                ui.label("Overlap feature kind");
                ui.text_edit_singleline(&mut self.splicing_exon_skip_overlap_kind)
                    .on_hover_text("Optional comma-separated feature kinds, e.g. variation,ncRNA,repeat_region");
                ui.label("label contains");
                ui.text_edit_singleline(&mut self.splicing_exon_skip_overlap_label)
                    .on_hover_text("Optional label text for selecting exons that overlap matching features");
            });
            ui.horizontal_wrapped(|ui| {
                if ui
                    .button("Build / Refresh selection plan")
                    .on_hover_text("Create a stored, inspectable exon-skip plan from the selected exons and overlap criteria")
                    .clicked()
                {
                    self.build_splicing_exon_skip_plan_from_ui(view, transcript_feature_id, None);
                }
                let selected_count = self.splicing_exon_skip_selected_candidate_ids.len();
                let materialize_enabled = self.splicing_exon_skip_plan.is_some() && selected_count > 0;
                if ui
                    .add_enabled(
                        materialize_enabled,
                        egui::Button::new("Materialize skipped isoform"),
                    )
                    .on_hover_text("Consume the stored plan and create both genomic annotation and cDNA products")
                    .clicked()
                {
                    self.materialize_splicing_exon_skip_plan_from_ui();
                }
                ui.small(format!("{selected_count} exon(s) selected"));
            });
            if let Some(plan) = self.splicing_exon_skip_plan.as_ref() {
                ui.small(format!(
                    "Plan '{}': {} candidate exon(s), {} selected.",
                    plan.plan_id,
                    plan.candidate_exons.len(),
                    plan.selected_candidate_ids.len()
                ));
                if let Some(warning) = plan.warnings.first() {
                    ui.small(
                        egui::RichText::new(warning)
                            .color(egui::Color32::from_rgb(180, 83, 9)),
                    );
                }
            }
        });
    }

    fn attract_region_filter_label(filter: AttractRegionFilter) -> &'static str {
        match filter {
            AttractRegionFilter::All => "all regions",
            AttractRegionFilter::ExonBody => "exon body",
            AttractRegionFilter::DonorFlank => "donor flank",
            AttractRegionFilter::AcceptorFlank => "acceptor flank",
            AttractRegionFilter::IntronBody => "intron body",
        }
    }

    fn attract_summary_key(gene_name: &str, organism: &str, matrix_id: &str) -> String {
        format!(
            "{}|{}|{}",
            gene_name.to_ascii_uppercase(),
            organism.to_ascii_uppercase(),
            matrix_id.to_ascii_uppercase()
        )
    }

    fn current_splicing_attract_settings_for_view(
        &self,
        view: &SplicingExpertView,
    ) -> AttractSplicingEvidenceSettings {
        AttractSplicingEvidenceSettings {
            scope: view.scope,
            transcript_strand_only: self.attract_evidence_ui.transcript_strand_only,
            boundary_flank_bp: self
                .attract_evidence_ui
                .boundary_flank_bp
                .trim()
                .parse::<usize>()
                .unwrap_or_else(|_| AttractSplicingEvidenceSettings::default().boundary_flank_bp),
            requested_organism: {
                let trimmed = self.attract_evidence_ui.requested_organism.trim();
                (!trimmed.is_empty()).then_some(trimmed.to_string())
            },
            allow_species_fallback: self.attract_evidence_ui.allow_species_fallback,
            minimum_quality_score: self
                .attract_evidence_ui
                .minimum_quality_score
                .trim()
                .replace(',', ".")
                .parse::<f64>()
                .unwrap_or(0.0),
            minimum_match_quantile: self
                .attract_evidence_ui
                .minimum_match_quantile
                .trim()
                .replace(',', ".")
                .parse::<f64>()
                .unwrap_or_else(|_| {
                    AttractSplicingEvidenceSettings::default().minimum_match_quantile
                }),
            pwm_mapping_policy: self.attract_evidence_ui.pwm_mapping_policy,
            compare_alternate_policy: self.attract_evidence_ui.compare_alternate_policy,
        }
    }

    fn cached_splicing_attract_evidence_for_view(
        &mut self,
        view: &SplicingExpertView,
    ) -> Result<Arc<AttractSplicingEvidenceView>, String> {
        let settings = self.current_splicing_attract_settings_for_view(view);
        let active_fingerprint = crate::attract_motifs::active_snapshot_fingerprint();
        if let Some(cached) = self.cached_splicing_attract_evidence.as_ref()
            && cached.seq_id == view.seq_id
            && cached.target_feature_id == view.target_feature_id
            && cached.settings == settings
            && cached.active_fingerprint == active_fingerprint
        {
            return Ok(cached.view.clone());
        }
        let Some(engine) = self.engine.clone() else {
            return Err("No engine attached".to_string());
        };
        self.log_splicing_expert_status(view, "ATtRACT inspect begin", false);
        let inspect_started = std::time::Instant::now();
        let inspected = match engine.read() {
            Ok(guard) => guard.inspect_splicing_attract_evidence(
                view.seq_id.as_str(),
                view.target_feature_id,
                &settings,
            ),
            Err(_) => Err(EngineError {
                code: ErrorCode::Internal,
                message: "Engine lock poisoned while inspecting ATtRACT evidence".to_string(),
            }),
        }
        .map_err(|e| e.message)?;
        self.log_splicing_expert_status(
            view,
            &format!(
                "ATtRACT inspect finished in {} ms",
                inspect_started.elapsed().as_millis()
            ),
            false,
        );
        let cached = Arc::new(inspected);
        self.cached_splicing_attract_evidence = Some(CachedSplicingAttractEvidence {
            seq_id: view.seq_id.clone(),
            target_feature_id: view.target_feature_id,
            settings,
            active_fingerprint,
            view: cached.clone(),
        });
        Ok(cached)
    }

    fn render_splicing_attract_evidence_section(
        &mut self,
        ui: &mut egui::Ui,
        view: &SplicingExpertView,
    ) {
        egui::CollapsingHeader::new("ATtRACT / RBP evidence")
            .default_open(!Self::splicing_attract_should_default_collapsed(view))
            .show(ui, |ui| {
                ui.horizontal_wrapped(|ui| {
                    ui.label(
                        egui::RichText::new(
                            "Splice-aware ATtRACT evidence is generated from the normalized ZIP snapshot and scanned against the selected splicing geometry on the engine side.",
                        )
                        .size(9.0)
                        .color(egui::Color32::from_rgb(100, 116, 139)),
                    );
                });
                if Self::splicing_attract_should_default_collapsed(view) {
                    ui.small(
                        egui::RichText::new(
                            "Large loci keep this section collapsed by default so opening the Splicing Expert window stays responsive.",
                        )
                        .color(egui::Color32::from_rgb(100, 116, 139)),
                    );
                }
                ui.horizontal_wrapped(|ui| {
                    ui.label("Organism");
                    ui.text_edit_singleline(&mut self.attract_evidence_ui.requested_organism);
                    ui.label("Min quality");
                    ui.add(
                        egui::TextEdit::singleline(
                            &mut self.attract_evidence_ui.minimum_quality_score,
                        )
                        .desired_width(52.0),
                    );
                    ui.label("Min match q");
                    ui.add(
                        egui::TextEdit::singleline(
                            &mut self.attract_evidence_ui.minimum_match_quantile,
                        )
                        .desired_width(52.0),
                    );
                    egui::ComboBox::from_id_salt((
                        "attract_pwm_mapping_policy",
                        view.seq_id.as_str(),
                        view.target_feature_id,
                    ))
                    .selected_text(match self.attract_evidence_ui.pwm_mapping_policy {
                        AttractPwmMappingPolicy::StrictSameLength => "PWM: strict",
                        AttractPwmMappingPolicy::WindowedSubmatrix => "PWM: windowed",
                    })
                    .show_ui(ui, |ui| {
                        ui.selectable_value(
                            &mut self.attract_evidence_ui.pwm_mapping_policy,
                            AttractPwmMappingPolicy::StrictSameLength,
                            "PWM: strict same-length",
                        );
                        ui.selectable_value(
                            &mut self.attract_evidence_ui.pwm_mapping_policy,
                            AttractPwmMappingPolicy::WindowedSubmatrix,
                            "PWM: windowed submatrix",
                        );
                    });
                    ui.label("Flank bp");
                    ui.add(
                        egui::TextEdit::singleline(&mut self.attract_evidence_ui.boundary_flank_bp)
                            .desired_width(48.0),
                    );
                    ui.checkbox(
                        &mut self.attract_evidence_ui.transcript_strand_only,
                        "Target strand only",
                    );
                    ui.checkbox(
                        &mut self.attract_evidence_ui.allow_species_fallback,
                        "Fallback when no exact species match",
                    );
                    ui.checkbox(
                        &mut self.attract_evidence_ui.compare_alternate_policy,
                        "Compare strict/windowed counts",
                    );
                });

                let evidence = match self.cached_splicing_attract_evidence_for_view(view) {
                    Ok(view) => view,
                    Err(err) => {
                        ui.small(
                            egui::RichText::new(format!(
                                "ATtRACT evidence unavailable: {err}"
                            ))
                            .color(egui::Color32::from_rgb(180, 83, 9)),
                        );
                        ui.separator();
                        return;
                    }
                };
                ui.small(format!(
                    "Snapshot={} motifs={} (pwm={} consensus={}){} | scanned transcripts={} windows={} | hits={} (exact={} windowed={} consensus={}) unique RBPs={} | species={} | mode={} | pwm-map={} | min-match-q={:.2}",
                    evidence.active_resource_source,
                    evidence.active_resource_item_count,
                    evidence.active_resource_pwm_row_count,
                    evidence.active_resource_consensus_only_row_count,
                    evidence
                        .active_resource_fingerprint
                        .as_deref()
                        .map(|fingerprint| format!(
                            " | fp={}",
                            fingerprint.chars().take(17).collect::<String>()
                        ))
                        .unwrap_or_default(),
                    evidence.scanned_transcript_count,
                    evidence.scanned_window_count,
                    evidence.hit_count,
                    evidence.exact_length_pwm_hit_count,
                    evidence.windowed_pwm_hit_count,
                    evidence.consensus_hit_count,
                    evidence.unique_rbp_count,
                    evidence
                        .resolved_organism
                        .as_deref()
                        .unwrap_or("unspecified"),
                    evidence.species_match_mode.as_str(),
                    evidence.settings.pwm_mapping_policy.as_str(),
                    evidence.settings.minimum_match_quantile
                ));
                for warning in evidence.warnings.iter().take(2) {
                    ui.small(
                        egui::RichText::new(warning)
                            .color(egui::Color32::from_rgb(180, 83, 9)),
                    );
                }
                if let Some(alternate) = evidence.alternate_policy_summary.as_ref() {
                    let hit_delta = alternate.hit_count as isize - evidence.hit_count as isize;
                    let rbp_delta =
                        alternate.unique_rbp_count as isize - evidence.unique_rbp_count as isize;
                    ui.small(format!(
                        "Alt {}: hits={} ({:+}) unique RBPs={} ({:+}) | pwm={} (exact={} windowed={} consensus={})",
                        alternate.pwm_mapping_policy.as_str(),
                        alternate.hit_count,
                        hit_delta,
                        alternate.unique_rbp_count,
                        rbp_delta,
                        alternate.pwm_scored_hit_count,
                        alternate.exact_length_pwm_hit_count,
                        alternate.windowed_pwm_hit_count,
                        alternate.consensus_hit_count
                    ));
                }
                ui.horizontal_wrapped(|ui| {
                    ui.label("Factor filter");
                    ui.text_edit_singleline(&mut self.attract_evidence_ui.factor_filter);
                    ui.label("Transcript filter");
                    ui.text_edit_singleline(&mut self.attract_evidence_ui.transcript_filter);
                    egui::ComboBox::from_id_salt((
                        "attract_region_filter",
                        view.seq_id.as_str(),
                        view.target_feature_id,
                    ))
                    .selected_text(Self::attract_region_filter_label(
                        self.attract_evidence_ui.region_filter,
                    ))
                    .show_ui(ui, |ui| {
                        for filter in [
                            AttractRegionFilter::All,
                            AttractRegionFilter::ExonBody,
                            AttractRegionFilter::DonorFlank,
                            AttractRegionFilter::AcceptorFlank,
                            AttractRegionFilter::IntronBody,
                        ] {
                            ui.selectable_value(
                                &mut self.attract_evidence_ui.region_filter,
                                filter,
                                Self::attract_region_filter_label(filter),
                            );
                        }
                    });
                    if ui.button("Clear factor selection").clicked() {
                        self.attract_evidence_ui.selected_summary_key = None;
                    }
                });

                let factor_filter = self.attract_evidence_ui.factor_filter.trim().to_ascii_lowercase();
                let transcript_filter =
                    self.attract_evidence_ui.transcript_filter.trim().to_ascii_lowercase();
                let min_quality = self
                    .attract_evidence_ui
                    .minimum_quality_score
                    .trim()
                    .replace(',', ".")
                    .parse::<f64>()
                    .unwrap_or(0.0);
                let filtered_summaries = evidence
                    .summary_rows
                    .iter()
                    .filter(|row| {
                        factor_filter.is_empty()
                            || row.gene_name.to_ascii_lowercase().contains(&factor_filter)
                            || row.matrix_id.to_ascii_lowercase().contains(&factor_filter)
                            || row.motif_iupac.to_ascii_lowercase().contains(&factor_filter)
                    })
                    .filter(|row| row.max_quality_score >= min_quality)
                    .collect::<Vec<_>>();
                ui.separator();
                ui.label(egui::RichText::new("RBP summary").strong());
                egui::ScrollArea::vertical()
                    .id_salt(format!(
                        "attract_summary_rows_{}_{}",
                        view.seq_id, view.target_feature_id
                    ))
                    .max_height(140.0)
                    .show(ui, |ui| {
                        egui::Grid::new(format!(
                            "attract_summary_grid_{}_{}",
                            view.seq_id, view.target_feature_id
                        ))
                        .striped(true)
                        .show(ui, |ui| {
                            ui.small("Factor");
                            ui.small("Organism");
                            ui.small("Model");
                            ui.small("Hits");
                            ui.small("Best match");
                            ui.small("PWM prov");
                            ui.small("Regions");
                            ui.small("Transcripts");
                            ui.end_row();
                            for row in filtered_summaries.iter() {
                                let key = Self::attract_summary_key(
                                    &row.gene_name,
                                    &row.organism,
                                    &row.matrix_id,
                                );
                                let selected = self
                                    .attract_evidence_ui
                                    .selected_summary_key
                                    .as_deref()
                                    .map(|probe| probe == key)
                                    .unwrap_or(false);
                                if ui
                                    .selectable_label(selected, row.gene_name.as_str())
                                    .clicked()
                                {
                                    self.attract_evidence_ui.selected_summary_key =
                                        Some(key.clone());
                                }
                                ui.small(&row.organism);
                                ui.small(format!("{} ({})", row.matrix_id, row.motif_iupac));
                                ui.small(row.hit_count.to_string());
                                ui.small(match row.strongest_score_quantile {
                                    Some(quantile) => format!(
                                        "{:.2} {} q{:.3}",
                                        row.strongest_score,
                                        row.strongest_score_kind,
                                        quantile
                                    ),
                                    None => format!(
                                        "{:.2} {}",
                                        row.strongest_score, row.strongest_score_kind
                                    ),
                                });
                                ui.small(format!(
                                    "E{} W{} C{}",
                                    row.exact_length_pwm_hits,
                                    row.windowed_pwm_hits,
                                    row.consensus_only_hits
                                ));
                                ui.small(format!(
                                    "E{} D{} A{} I{}",
                                    row.exon_body_hits,
                                    row.donor_flank_hits,
                                    row.acceptor_flank_hits,
                                    row.intron_body_hits
                                ));
                                ui.small(row.supporting_transcript_ids.join(", "));
                                ui.end_row();
                            }
                        });
                    });

                let filtered_hits = evidence
                    .hit_rows
                    .iter()
                    .filter(|row| {
                        factor_filter.is_empty()
                            || row.gene_name.to_ascii_lowercase().contains(&factor_filter)
                            || row.matrix_id.to_ascii_lowercase().contains(&factor_filter)
                            || row.motif_iupac.to_ascii_lowercase().contains(&factor_filter)
                    })
                    .filter(|row| {
                        transcript_filter.is_empty()
                            || row.transcript_id.to_ascii_lowercase().contains(&transcript_filter)
                            || row.transcript_label.to_ascii_lowercase().contains(&transcript_filter)
                    })
                    .filter(|row| row.quality_score >= min_quality)
                    .filter(|row| match self.attract_evidence_ui.region_filter {
                        AttractRegionFilter::All => true,
                        AttractRegionFilter::ExonBody => {
                            row.region_class == AttractRegionClass::ExonBody
                        }
                        AttractRegionFilter::DonorFlank => {
                            row.region_class == AttractRegionClass::DonorFlank
                        }
                        AttractRegionFilter::AcceptorFlank => {
                            row.region_class == AttractRegionClass::AcceptorFlank
                        }
                        AttractRegionFilter::IntronBody => {
                            row.region_class == AttractRegionClass::IntronBody
                        }
                    })
                    .filter(|row| {
                        self.attract_evidence_ui
                            .selected_summary_key
                            .as_deref()
                            .map(|probe| {
                                probe
                                    == Self::attract_summary_key(
                                        &row.gene_name,
                                        &row.organism,
                                        &row.matrix_id,
                                    )
                            })
                            .unwrap_or(true)
                    })
                    .collect::<Vec<_>>();
                ui.label(egui::RichText::new("Hit rows").strong());
                egui::ScrollArea::vertical()
                    .id_salt(format!(
                        "attract_hit_rows_{}_{}",
                        view.seq_id, view.target_feature_id
                    ))
                    .max_height(180.0)
                    .show(ui, |ui| {
                        egui::Grid::new(format!(
                            "attract_hits_grid_{}_{}",
                            view.seq_id, view.target_feature_id
                        ))
                        .striped(true)
                        .show(ui, |ui| {
                            ui.small("Transcript");
                            ui.small("Factor");
                            ui.small("Region");
                            ui.small("Coords");
                            ui.small("Motif");
                            ui.small("Match");
                            ui.small("Prov");
                            ui.small("Quality");
                            ui.end_row();
                            for row in filtered_hits {
                                ui.small(&row.transcript_id);
                                ui.small(format!("{} ({})", row.gene_name, row.matrix_id));
                                ui.small(row.region_class.as_str());
                                ui.small(format!(
                                    "{}..{} [local {}..{}]",
                                    row.region_start_1based,
                                    row.region_end_1based,
                                    row.region_local_start_1based,
                                    row.region_local_end_1based
                                ));
                                ui.small(format!(
                                    "{} -> {}",
                                    row.motif_iupac, row.matched_sequence
                                ));
                                ui.small(match row.match_score_quantile {
                                    Some(quantile) => format!(
                                        "{:.2} {} q{:.3}",
                                        row.match_score, row.match_score_kind, quantile
                                    ),
                                    None => format!(
                                        "{:.2} {}",
                                        row.match_score, row.match_score_kind
                                    ),
                                });
                                ui.small(match (
                                    row.pfm_subwindow_start_1based,
                                    row.pfm_subwindow_end_1based,
                                ) {
                                    (Some(start), Some(end)) => format!(
                                        "{} / {} [{}..{}]",
                                        row.mapping_policy_used,
                                        row.pwm_mapping_status,
                                        start,
                                        end
                                    ),
                                    _ => format!(
                                        "{} / {}",
                                        row.mapping_policy_used, row.pwm_mapping_status
                                    ),
                                });
                                ui.small(format!("{:.2}", row.quality_score));
                                ui.end_row();
                            }
                        });
                    });
                ui.separator();
            });
    }

    fn isoform_expert_viewport_id(seq_id: &str, panel_id: &str) -> egui::ViewportId {
        egui::ViewportId::from_hash_of(("isoform_expert_viewport", seq_id, panel_id))
    }

    fn render_isoform_expert_window(&mut self, ctx: &egui::Context) {
        if !self.show_isoform_expert_window {
            return;
        }
        let Some(view) = self.isoform_expert_window_view.clone() else {
            self.show_isoform_expert_window = false;
            return;
        };
        let panel_id = self
            .isoform_expert_window_panel_id
            .clone()
            .unwrap_or_else(|| view.panel_id.clone());
        let title = Self::isoform_expert_window_title(&panel_id, &view.seq_id, &view);
        let viewport_id = Self::isoform_expert_viewport_id(&view.seq_id, &panel_id);
        let default_size = Vec2::new(1120.0, 700.0);
        let min_size = Vec2::new(840.0, 460.0);
        if ctx.embed_viewports() {
            let mut open = self.show_isoform_expert_window;
            let spec = crate::egui_compat::HostedWindowSpec::new(
                title.clone(),
                egui::Id::new(format!(
                    "isoform_expert_window_embedded_{}_{}",
                    view.seq_id, panel_id
                )),
                default_size,
                min_size,
            );
            crate::egui_compat::show_hosted_window(ctx, &spec, &mut open, |ui| {
                let backdrop_settings = current_window_backdrop_settings();
                paint_window_backdrop(ui, WindowBackdropKind::Splicing, &backdrop_settings);
                egui::ScrollArea::both()
                    .id_salt(format!(
                        "isoform_expert_window_scroll_embedded_{}_{}",
                        view.seq_id, panel_id
                    ))
                    .auto_shrink([false, false])
                    .show(ui, |ui| {
                        scroll_input_policy::apply_scrollarea_keyboard_navigation(
                            ui,
                            scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
                        );
                        ui.set_min_size(Vec2::new(1040.0, 620.0));
                        self.render_isoform_architecture_expert_view_ui(ui, &view);
                    });
            });
            self.show_isoform_expert_window = open;
            return;
        }
        let builder = egui::ViewportBuilder::default()
            .with_title(title.clone())
            .with_inner_size([default_size.x, default_size.y])
            .with_min_inner_size([min_size.x, min_size.y]);
        ctx.show_viewport_immediate(viewport_id, builder, |ctx, class| {
            if class == egui::ViewportClass::EmbeddedWindow {
                let mut open = self.show_isoform_expert_window;
                let spec = crate::egui_compat::HostedWindowSpec::new(
                    title.clone(),
                    egui::Id::new(format!(
                        "isoform_expert_window_embedded_{}_{}",
                        view.seq_id, panel_id
                    )),
                    default_size,
                    min_size,
                );
                crate::egui_compat::show_hosted_window(ctx, &spec, &mut open, |ui| {
                    let backdrop_settings = current_window_backdrop_settings();
                    paint_window_backdrop(ui, WindowBackdropKind::Splicing, &backdrop_settings);
                    egui::ScrollArea::both()
                        .id_salt(format!(
                            "isoform_expert_window_scroll_embedded_{}_{}",
                            view.seq_id, panel_id
                        ))
                        .auto_shrink([false, false])
                        .show(ui, |ui| {
                            scroll_input_policy::apply_scrollarea_keyboard_navigation(
                                ui,
                                scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
                            );
                            ui.set_min_size(Vec2::new(1040.0, 620.0));
                            self.render_isoform_architecture_expert_view_ui(ui, &view);
                        });
                });
                self.show_isoform_expert_window = open;
                return;
            }

            crate::egui_compat::show_central_panel(ctx, egui::CentralPanel::default(), |ui| {
                let backdrop_settings = current_window_backdrop_settings();
                paint_window_backdrop(ui, WindowBackdropKind::Splicing, &backdrop_settings);
                egui::ScrollArea::both()
                    .id_salt(format!(
                        "isoform_expert_window_scroll_viewport_{}_{}",
                        view.seq_id, panel_id
                    ))
                    .auto_shrink([false, false])
                    .show(ui, |ui| {
                        scroll_input_policy::apply_scrollarea_keyboard_navigation(
                            ui,
                            scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
                        );
                        ui.set_min_size(Vec2::new(1040.0, 620.0));
                        self.render_isoform_architecture_expert_view_ui(ui, &view);
                    });
            });

            if crate::app::GENtleApp::viewport_close_requested_or_shortcut(ctx) {
                self.show_isoform_expert_window = false;
            }
        });
    }

    fn apply_sequence_derivation(&mut self, op: Operation) {
        let Some(engine) = self.engine.clone() else {
            return;
        };
        let Ok(result) = ({
            let Ok(mut guard) = engine.write() else {
                self.op_status =
                    "Engine lock poisoned while deriving sequence; restart recommended".to_string();
                return;
            };
            guard.apply(op)
        }) else {
            return;
        };
        let Some(new_seq_id) = result.created_seq_ids.first() else {
            return;
        };
        let Some(new_dna) = ({
            let Ok(guard) = engine.read() else {
                self.op_status =
                    "Engine lock poisoned while reading derived sequence; restart recommended"
                        .to_string();
                return;
            };
            guard.state().sequences.get(new_seq_id).cloned()
        }) else {
            self.op_status = format!("Derived sequence '{new_seq_id}' was not found in engine");
            return;
        };

        self.seq_id = Some(new_seq_id.clone());
        self.replace_active_dna(new_dna, true);
    }

    fn apply_operation_with_feedback(&mut self, op: Operation) {
        let _ = self.apply_operation_with_feedback_and_result(op);
    }

    fn apply_operation_with_feedback_and_result(&mut self, op: Operation) -> Option<OpResult> {
        let Some(engine) = self.engine.clone() else {
            self.op_status = "No engine attached".to_string();
            return None;
        };
        let started = Instant::now();
        let apply_result = {
            let Ok(mut guard) = engine.write() else {
                self.op_status =
                    "Engine lock poisoned while applying operation; restart recommended"
                        .to_string();
                return None;
            };
            guard.apply(op)
        };
        match apply_result {
            Ok(result) => {
                let out = result.clone();
                self.handle_operation_success(result, started);
                Some(out)
            }
            Err(e) => {
                self.handle_operation_error(e, started);
                None
            }
        }
    }

    fn maybe_prompt_prepared_genome_choice(&mut self, action: PendingGenomeAnchorAction) -> bool {
        let requested_seq_id = match &action {
            PendingGenomeAnchorAction::Extend { seq_id, .. } => seq_id,
            PendingGenomeAnchorAction::Verify { seq_id } => seq_id,
        };
        let Some(engine) = self.engine.clone() else {
            return false;
        };
        let guard = match engine.read() {
            Ok(guard) => guard,
            Err(_) => {
                self.op_status =
                    "Engine lock poisoned while resolving prepared genomes".to_string();
                return false;
            }
        };
        let inspection =
            match guard.sequence_anchor_prepared_genome_options(requested_seq_id, None, None) {
                Ok(v) => v,
                Err(_) => return false,
            };
        let fallback_policy = guard
            .state()
            .parameters
            .genome_anchor_prepared_fallback_policy;
        if inspection.exact_prepared || inspection.compatible_prepared_options.is_empty() {
            return false;
        }
        let requires_explicit_choice = matches!(
            fallback_policy,
            GenomeAnchorPreparedFallbackPolicy::AlwaysExplicit
        );
        if !requires_explicit_choice && inspection.compatible_prepared_options.len() <= 1 {
            return false;
        }
        self.anchor_prepared_choice_dialog = Some(GenomeAnchorPreparedChoiceDialog {
            requested_genome_id: inspection.requested_genome_id.clone(),
            options: inspection.compatible_prepared_options,
            selected_index: 0,
            action,
        });
        self.op_status = format!(
            "Select prepared genome for anchored operation (requested='{}')",
            inspection.requested_genome_id
        );
        true
    }

    fn run_pending_genome_anchor_action(
        &mut self,
        action: PendingGenomeAnchorAction,
        prepared_genome_id: Option<String>,
    ) {
        match action {
            PendingGenomeAnchorAction::Extend {
                seq_id,
                side,
                length_bp,
                output_id,
            } => {
                self.apply_operation_with_feedback(Operation::ExtendGenomeAnchor {
                    seq_id,
                    side,
                    length_bp,
                    output_id,
                    catalog_path: None,
                    cache_dir: None,
                    prepared_genome_id,
                });
            }
            PendingGenomeAnchorAction::Verify { seq_id } => {
                self.apply_operation_with_feedback(Operation::VerifyGenomeAnchor {
                    seq_id,
                    catalog_path: None,
                    cache_dir: None,
                    prepared_genome_id,
                });
            }
        }
    }

    fn extend_active_genome_anchor(&mut self, side: GenomeAnchorSide) {
        let Some(seq_id) = self.seq_id.clone() else {
            self.op_status = "No active sequence selected".to_string();
            return;
        };
        let length_bp = match Self::parse_positive_usize_text(
            &self.genome_anchor_extend_length_bp,
            "extension length (bp)",
        ) {
            Ok(value) => value,
            Err(message) => {
                self.op_status = message.clone();
                self.op_error_popup = Some(message);
                return;
            }
        };
        let output_id = if self.genome_anchor_extend_output_id.trim().is_empty() {
            None
        } else {
            Some(self.genome_anchor_extend_output_id.trim().to_string())
        };
        let action = PendingGenomeAnchorAction::Extend {
            seq_id,
            side,
            length_bp,
            output_id,
        };
        if self.maybe_prompt_prepared_genome_choice(action.clone()) {
            return;
        }
        self.run_pending_genome_anchor_action(action, None);
    }

    fn verify_active_genome_anchor(&mut self) {
        let Some(seq_id) = self.seq_id.clone() else {
            self.op_status = "No active sequence selected".to_string();
            return;
        };
        let action = PendingGenomeAnchorAction::Verify { seq_id };
        if self.maybe_prompt_prepared_genome_choice(action.clone()) {
            return;
        }
        self.run_pending_genome_anchor_action(action, None);
    }

    fn materialize_active_repeat_features(&mut self) {
        let Some(seq_id) = self.seq_id.clone() else {
            self.op_status = "No active sequence selected".to_string();
            return;
        };
        let rmsk_index_path = self.rmsk_index_path.trim().to_string();
        if rmsk_index_path.is_empty() {
            self.op_status = "Provide a prepared UCSC rmsk interval-index path".to_string();
            return;
        }
        let max_features = match self.rmsk_max_features.trim() {
            "" => None,
            value => match Self::parse_positive_usize_text(value, "rmsk max features") {
                Ok(parsed) => Some(parsed),
                Err(message) => {
                    self.op_status = message.clone();
                    self.op_error_popup = Some(message);
                    return;
                }
            },
        };
        self.apply_operation_with_feedback(Operation::MaterializeRepeatFeatures {
            seq_id,
            rmsk_index_path,
            max_features,
            clear_existing: Some(!self.rmsk_append_features),
            path: None,
        });
    }

    fn handle_operation_success(&mut self, result: OpResult, started: Instant) {
        self.invalidate_rna_read_report_display_cache();
        if let Some(preview) = result.protocol_cartoon_preview.as_ref() {
            self.last_protocol_cartoon_preview = Some(preview.clone());
            self.last_protocol_cartoon_preview_op_id = result.op_id.clone();
        }
        if let Some(report) = result.cutrun_regulatory_support.as_ref() {
            self.cached_cutrun_regulatory_support = Some(report.clone());
        }
        if !result.created_seq_ids.is_empty() {
            self.last_created_seq_ids = result.created_seq_ids.clone();
            self.export_pool_inputs_text = self.last_created_seq_ids.join(", ");
        }
        if let Some(engine) = self.engine.clone() {
            // Only auto-switch current view if exactly one sequence is produced.
            // Multi-product ops (digest/ligation/merge) can trigger heavy redraw paths;
            // keep the current view stable and let the user select products explicitly.
            if result.created_seq_ids.len() == 1 {
                if let Some(new_seq_id) = result.created_seq_ids.first() {
                    let new_dna = {
                        let guard = engine.read().expect("Engine lock poisoned");
                        guard.state().sequences.get(new_seq_id).cloned()
                    };
                    if let Some(new_dna) = new_dna {
                        self.seq_id = Some(new_seq_id.clone());
                        self.replace_active_dna(new_dna, true);
                    }
                }
            } else if let Some(current_seq_id) = self.seq_id.clone() {
                if result
                    .changed_seq_ids
                    .iter()
                    .any(|id| id == &current_seq_id)
                {
                    let updated_dna = {
                        let guard = engine.read().expect("Engine lock poisoned");
                        guard.state().sequences.get(&current_seq_id).cloned()
                    };
                    if let Some(updated_dna) = updated_dna {
                        self.replace_active_dna(updated_dna, true);
                    }
                }
            }
        }
        let elapsed_ms = started.elapsed().as_millis();
        let created = if result.created_seq_ids.is_empty() {
            "-".to_string()
        } else {
            result.created_seq_ids.join(", ")
        };
        let warnings = if result.warnings.is_empty() {
            "-".to_string()
        } else {
            result.warnings.join(" | ")
        };
        let messages = if result.messages.is_empty() {
            "-".to_string()
        } else {
            result.messages.join(" | ")
        };
        let changed_note =
            if result.created_seq_ids.is_empty() && !result.changed_seq_ids.is_empty() {
                " (in-place update)"
            } else {
                ""
            };
        self.op_status = format!(
            "ok in {} ms\ncreated: {}\ncounts: {} created, {} changed{}\nwarnings: {}\nmessages: {}",
            elapsed_ms,
            created,
            result.created_seq_ids.len(),
            result.changed_seq_ids.len(),
            changed_note,
            warnings,
            messages
        );
        self.op_error_popup = None;
    }

    fn handle_operation_error(&mut self, e: EngineError, started: Instant) {
        self.last_created_seq_ids.clear();
        let elapsed_ms = started.elapsed().as_millis();
        self.op_status = format!("error after {} ms: {}", elapsed_ms, e.message);
        self.op_error_popup = Some(e.message);
    }

    fn start_primer_design_operation(&mut self, op: Operation, operation_label: &str) {
        let Some(engine) = self.engine.clone() else {
            self.op_status = "No engine attached".to_string();
            return;
        };
        if self.primer_design_task.is_some() {
            self.op_status = "Primer design is already running".to_string();
            return;
        }
        let (template_id, report_id_hint) = match &op {
            Operation::DesignPrimerPairs {
                template,
                report_id,
                ..
            } => (Some(template.clone()), report_id.clone()),
            Operation::DesignQpcrAssays {
                template,
                report_id,
                ..
            } => (Some(template.clone()), report_id.clone()),
            _ => (None, None),
        };
        let started = Instant::now();
        let (tx, rx) = mpsc::channel::<PrimerDesignTaskMessage>();
        self.op_status = if let Some(report_id) = report_id_hint
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty())
        {
            format!("{operation_label} started (report_id='{report_id}')...")
        } else {
            format!("{operation_label} started...")
        };
        self.primer_design_task = Some(PrimerDesignTask {
            started,
            operation_label: operation_label.to_string(),
            template_id,
            report_id_hint,
            progress: None,
            batch_progress: None,
            receiver: Arc::new(Mutex::new(rx)),
        });
        std::thread::spawn(move || {
            let outcome = match engine.write() {
                Ok(mut guard) => {
                    let tx_progress = tx.clone();
                    guard
                        .apply_with_progress(op, move |progress| {
                            if let OperationProgress::PrimerDesign(progress) = progress {
                                let _ =
                                    tx_progress.send(PrimerDesignTaskMessage::Progress(progress));
                            }
                            true
                        })
                        .map(PrimerDesignTaskCompletion::Single)
                }
                Err(_) => Err(EngineError {
                    code: ErrorCode::Internal,
                    message: "Engine lock poisoned while running primer design".to_string(),
                }),
            };
            let _ = tx.send(PrimerDesignTaskMessage::Done(outcome));
        });
    }

    fn start_queued_primer_pair_design_batch(&mut self) {
        if self.primer_design_task.is_some() {
            self.op_status = "Primer design is already running".to_string();
            return;
        }
        let Some(engine) = self.engine.clone() else {
            self.op_status = "No engine attached".to_string();
            return;
        };
        let prepared = match self.prepare_primer_pair_design_batch_inputs() {
            Ok(value) => value,
            Err(err) => {
                self.op_status = err;
                return;
            }
        };
        let queued_count = prepared.queued_regions.len();
        let started = Instant::now();
        let (tx, rx) = mpsc::channel::<PrimerDesignTaskMessage>();
        self.op_status = format!("PCR primer batch started for {queued_count} queued region(s)...");
        self.primer_design_task = Some(PrimerDesignTask {
            started,
            operation_label: "PCR primer batch".to_string(),
            template_id: None,
            report_id_hint: None,
            progress: None,
            batch_progress: None,
            receiver: Arc::new(Mutex::new(rx)),
        });
        std::thread::spawn(move || {
            let tx_progress = tx.clone();
            let outcome = match engine.write() {
                Ok(mut guard) => Ok(PrimerDesignTaskCompletion::Batch(
                    Self::execute_primer_pair_design_batch(
                        &mut guard,
                        &prepared.queued_regions,
                        &prepared.spec,
                        &prepared.report_base,
                        prepared.create_copies,
                        move |progress| {
                            let _ =
                                tx_progress.send(PrimerDesignTaskMessage::BatchProgress(progress));
                        },
                    ),
                )),
                Err(_) => Err(EngineError {
                    code: ErrorCode::Internal,
                    message: "Engine lock poisoned while running queued PCR primer design"
                        .to_string(),
                }),
            };
            let _ = tx.send(PrimerDesignTaskMessage::Done(outcome));
        });
    }

    fn poll_primer_design_task(&mut self, ctx: &egui::Context) {
        if self.primer_design_task.is_none() {
            return;
        }
        let mut done: Option<Result<PrimerDesignTaskCompletion, EngineError>> = None;
        let mut task_still_running = false;
        if let Some(task) = self.primer_design_task.as_mut() {
            match task.receiver.lock() {
                Ok(rx) => loop {
                    match rx.try_recv() {
                        Ok(PrimerDesignTaskMessage::Progress(progress)) => {
                            task.progress = Some(progress);
                        }
                        Ok(PrimerDesignTaskMessage::BatchProgress(progress)) => {
                            task.batch_progress = Some(progress);
                        }
                        Ok(PrimerDesignTaskMessage::Done(res)) => {
                            done = Some(res);
                            break;
                        }
                        Err(TryRecvError::Disconnected) => {
                            done = Some(Err(EngineError {
                                code: ErrorCode::Internal,
                                message: "Primer-design worker disconnected unexpectedly"
                                    .to_string(),
                            }));
                            break;
                        }
                        Err(TryRecvError::Empty) => {
                            let elapsed = task.started.elapsed().as_secs_f32();
                            if let Some(progress) = &task.progress {
                                self.op_status = format!(
                                    "{} running: {}... {:.1}s elapsed",
                                    task.operation_label,
                                    Self::primer_design_progress_summary(progress),
                                    elapsed
                                );
                            } else if let Some(progress) = &task.batch_progress {
                                self.op_status = format!(
                                    "{} running: region {}/{} ({}:{}..{} {})... {:.1}s elapsed",
                                    task.operation_label,
                                    progress.region_index_1based,
                                    progress.region_count,
                                    progress.template,
                                    progress.start_0based,
                                    progress.end_0based_exclusive,
                                    progress.source_label,
                                    elapsed
                                );
                            } else {
                                self.op_status = format!(
                                    "{} running... {:.1}s elapsed",
                                    task.operation_label, elapsed
                                );
                            }
                            task_still_running = true;
                            break;
                        }
                    }
                },
                Err(_) => {
                    done = Some(Err(EngineError {
                        code: ErrorCode::Internal,
                        message: "Primer-design channel lock poisoned".to_string(),
                    }));
                }
            }
        }

        if done.is_none() && task_still_running {
            ctx.request_repaint_after(Duration::from_millis(160));
            return;
        }

        if let Some(done) = done {
            let (started, template_id, report_id_hint) = self
                .primer_design_task
                .as_ref()
                .map(|task| {
                    (
                        task.started,
                        task.template_id.clone(),
                        task.report_id_hint.clone(),
                    )
                })
                .unwrap_or_else(|| (Instant::now(), None, None));
            self.primer_design_task = None;
            match done {
                Ok(PrimerDesignTaskCompletion::Single(result)) => {
                    self.handle_operation_success(result, started);
                    let resolved_report_id = report_id_hint
                        .as_deref()
                        .map(str::trim)
                        .filter(|value| !value.is_empty())
                        .map(ToOwned::to_owned)
                        .or_else(|| {
                            template_id.as_deref().and_then(|template| {
                                self.latest_primer_report_id_for_template(template)
                            })
                        });
                    if let Some(report_id) = resolved_report_id {
                        self.primer_design_ui.report_id = report_id.clone();
                        self.show_primer_design_report(&report_id);
                    } else if template_id.is_some() {
                        self.list_primer_design_reports();
                    }
                }
                Ok(PrimerDesignTaskCompletion::Batch(outcome)) => {
                    self.apply_primer_pair_design_batch_outcome(
                        outcome,
                        started.elapsed().as_millis(),
                    );
                }
                Err(err) => self.handle_operation_error(err, started),
            }
        }
    }

    fn primer_design_progress_summary(progress: &PrimerDesignProgress) -> String {
        let backend = progress.backend_used.trim();
        let backend_prefix = if backend.is_empty() {
            String::new()
        } else {
            format!("{backend} ")
        };
        match (progress.design_kind.as_str(), progress.stage.as_str()) {
            ("primer_pairs", "forward_candidates") => format!(
                "{}pair-PCR: enumerated {} forward primer candidates",
                backend_prefix,
                progress.forward_candidate_count.unwrap_or(0)
            ),
            ("primer_pairs", "reverse_candidates") => format!(
                "{}pair-PCR: enumerated {} forward and {} reverse primer candidates",
                backend_prefix,
                progress.forward_candidate_count.unwrap_or(0),
                progress.reverse_candidate_count.unwrap_or(0)
            ),
            ("primer_pairs", "pair_search") => {
                format!(
                    "{}pair-PCR: checked {}/{} pair combinations, accepted {} candidate pairs",
                    backend_prefix,
                    progress.pair_evaluated.unwrap_or(0),
                    progress.pair_evaluation_limit.unwrap_or(0),
                    progress.accepted_pair_count.unwrap_or(0)
                )
            }
            ("primer_pairs", "pair_search_complete") | ("primer_pairs", "complete") => {
                format!(
                    "{}pair-PCR complete: accepted {} primer pairs after checking {}/{} combinations",
                    backend_prefix,
                    progress.accepted_pair_count.unwrap_or(0),
                    progress.pair_evaluated.unwrap_or(0),
                    progress.pair_evaluation_limit.unwrap_or(0)
                )
            }
            ("qpcr_assays", "forward_candidates") => format!(
                "{}qPCR: enumerated {} forward primer candidates",
                backend_prefix,
                progress.forward_candidate_count.unwrap_or(0)
            ),
            ("qpcr_assays", "reverse_candidates") => format!(
                "{}qPCR: enumerated {} forward and {} reverse primer candidates",
                backend_prefix,
                progress.forward_candidate_count.unwrap_or(0),
                progress.reverse_candidate_count.unwrap_or(0)
            ),
            ("qpcr_assays", "pair_search") | ("qpcr_assays", "pair_search_complete") => format!(
                "{}qPCR: checked {}/{} primer-pair combinations, retained {} primer pairs",
                backend_prefix,
                progress.pair_evaluated.unwrap_or(0),
                progress.pair_evaluation_limit.unwrap_or(0),
                progress.accepted_pair_count.unwrap_or(0)
            ),
            ("qpcr_assays", "probe_candidates") => format!(
                "{}qPCR: generated {} probe candidates across {} retained primer pairs",
                backend_prefix,
                progress.probe_candidate_count.unwrap_or(0),
                progress.accepted_pair_count.unwrap_or(0)
            ),
            ("qpcr_assays", "assay_search") => {
                format!(
                    "{}qPCR: screened {}/{} probe placements across {} retained primer pairs, accepted {} assays",
                    backend_prefix,
                    progress.assays_evaluated.unwrap_or(0),
                    progress.assay_candidate_combinations.unwrap_or(0),
                    progress.accepted_pair_count.unwrap_or(0),
                    progress.accepted_assay_count.unwrap_or(0)
                )
            }
            ("qpcr_assays", "assay_search_complete") | ("qpcr_assays", "complete") => format!(
                "{}qPCR complete: accepted {} assays after screening {}/{} probe placements",
                backend_prefix,
                progress.accepted_assay_count.unwrap_or(0),
                progress.assays_evaluated.unwrap_or(0),
                progress.assay_candidate_combinations.unwrap_or(0)
            ),
            _ => format!(
                "{}{}: {}",
                backend_prefix,
                progress.design_kind.replace('_', "-"),
                progress.detail
            ),
        }
    }

    fn active_primer_design_progress_summary_for_kind(&self, kind: &str) -> Option<String> {
        self.primer_design_task
            .as_ref()?
            .progress
            .as_ref()
            .filter(|progress| progress.design_kind == kind)
            .map(Self::primer_design_progress_summary)
    }

    fn tfbs_task_summary_label(task_kind: &TfbsTaskKind) -> &'static str {
        match task_kind {
            TfbsTaskKind::Annotation => "TFBS annotation",
            TfbsTaskKind::ActiveSequenceScoreTracks { .. } => "TFBS score tracks",
            TfbsTaskKind::ActiveSequenceTrackSimilarity { .. } => "TFBS similarity ranking",
            TfbsTaskKind::VariantFollowupScoreTracks => "Promoter TF score tracks",
            TfbsTaskKind::VariantFollowupTrackSimilarity => "Promoter TFBS similarity ranking",
        }
    }

    fn tfbs_progress_detail_label(progress: &TfbsProgress) -> String {
        match progress
            .stage_label
            .as_deref()
            .map(str::trim)
            .unwrap_or_default()
        {
            "" => progress.motif_id.clone(),
            stage => match progress
                .detail
                .as_deref()
                .map(str::trim)
                .unwrap_or_default()
            {
                "" => format!("{stage}: {}", progress.motif_id),
                detail => format!("{stage}: {} ({detail})", progress.motif_id),
            },
        }
    }

    fn summarize_tfbs_task_status(task: &TfbsTask, progress: Option<&TfbsProgress>) -> String {
        let activity = task.operation_label.as_str();
        let cancel_suffix = if task.cancel_requested.load(AtomicOrdering::Relaxed) {
            " | cancellation requested"
        } else {
            ""
        };
        match progress {
            Some(progress) => {
                let stage_percent = progress.stage_percent.unwrap_or(progress.motif_percent);
                format!(
                    "{activity} running: motif {}/{} ({}) {:.1}% | total {:.1}% | {:.1}s elapsed{}",
                    progress.motif_index,
                    progress.motif_count,
                    Self::tfbs_progress_detail_label(progress),
                    stage_percent,
                    progress.total_percent,
                    task.started.elapsed().as_secs_f32(),
                    cancel_suffix
                )
            }
            None => format!(
                "{activity} running... {} motif(s), {:.1}s elapsed{}",
                task.motif_count,
                task.started.elapsed().as_secs_f32(),
                cancel_suffix
            ),
        }
    }

    fn start_tfbs_operation(
        &mut self,
        op: Operation,
        task_kind: TfbsTaskKind,
        operation_label: &str,
    ) {
        let Some(engine) = self.engine.clone() else {
            self.op_status = "No engine attached".to_string();
            return;
        };
        if self.tfbs_task.is_some() {
            self.op_status = format!(
                "{} is already running",
                Self::tfbs_task_summary_label(
                    &self
                        .tfbs_task
                        .as_ref()
                        .map(|task| task.task_kind.clone())
                        .unwrap_or(TfbsTaskKind::Annotation)
                )
            );
            return;
        }
        let motif_count = match &op {
            Operation::AnnotateTfbs { motifs, .. } => motifs.len(),
            Operation::SummarizeTfbsScoreTracks { motifs, .. } => motifs.len(),
            Operation::SummarizeTfbsTrackSimilarity {
                candidate_motifs, ..
            } => candidate_motifs.len().saturating_add(1).max(1),
            _ => 0,
        };
        let (tx, rx) = mpsc::channel::<TfbsTaskMessage>();
        let started = Instant::now();
        let cancel_requested = Arc::new(AtomicBool::new(false));
        self.tfbs_progress = None;
        self.op_status = format!("{operation_label} started for {motif_count} motif(s)");
        self.tfbs_task = Some(TfbsTask {
            started,
            task_kind,
            operation_label: operation_label.to_string(),
            motif_count,
            cancel_requested: cancel_requested.clone(),
            receiver: Arc::new(Mutex::new(rx)),
        });
        std::thread::spawn(move || {
            let tx_progress = tx.clone();
            let cancel_for_worker = cancel_requested.clone();
            let outcome = match engine.write() {
                Ok(mut guard) => {
                    let mut last_motif_index: Option<usize> = None;
                    let mut last_total_tenths: Option<i64> = None;
                    guard.apply_with_progress(op, move |progress| {
                        if cancel_for_worker.load(AtomicOrdering::Relaxed) {
                            return false;
                        }
                        let OperationProgress::Tfbs(p) = progress else {
                            return true;
                        };
                        let total_tenths = (p.total_percent * 10.0).floor() as i64;
                        let motif_changed = last_motif_index != Some(p.motif_index);
                        let progressed = last_total_tenths
                            .map(|prev| total_tenths > prev)
                            .unwrap_or(true);
                        let done = (p.total_percent - 100.0).abs() < f64::EPSILON;
                        if motif_changed || progressed || done {
                            last_motif_index = Some(p.motif_index);
                            last_total_tenths = Some(total_tenths);
                            let _ = tx_progress.send(TfbsTaskMessage::Progress(p));
                        }
                        !cancel_for_worker.load(AtomicOrdering::Relaxed)
                    })
                }
                Err(_) => Err(EngineError {
                    code: ErrorCode::Internal,
                    message: "Engine lock poisoned while running TFBS work".to_string(),
                }),
            };
            let _ = tx.send(TfbsTaskMessage::Done(outcome));
        });
    }

    fn start_tfbs_annotation(&mut self, op: Operation) {
        self.start_tfbs_operation(op, TfbsTaskKind::Annotation, "TFBS annotation");
    }

    fn handle_completed_tfbs_task_result(
        &mut self,
        task_kind: TfbsTaskKind,
        result: OpResult,
        started: Instant,
    ) {
        if let Some(report) = result.tfbs_track_similarity.clone() {
            if let TfbsTaskKind::ActiveSequenceTrackSimilarity { source_label } = task_kind {
                self.cached_tfbs_track_similarity = Some(report.clone());
                self.op_status =
                    Self::summarize_tfbs_track_similarity_report_status(&report, &source_label);
                self.op_error_popup = None;
                return;
            }
        }
        if let Some(report) = result.tfbs_score_tracks.clone() {
            match task_kind {
                TfbsTaskKind::Annotation => {}
                TfbsTaskKind::ActiveSequenceScoreTracks { source_label } => {
                    self.cached_tfbs_score_tracks = Some(report.clone());
                    self.op_status =
                        Self::summarize_tfbs_score_track_report_status(&report, &source_label);
                    self.op_error_popup = None;
                    return;
                }
                TfbsTaskKind::VariantFollowupScoreTracks => {
                    self.variant_followup_ui.cached_score_tracks = Some(report.clone());
                    self.op_status = format!(
                        "Promoter TF score tracks updated for '{}' across {}..{} [{}]",
                        report.target_label,
                        report.view_start_0based,
                        report.view_end_0based_exclusive,
                        report.score_kind.as_str()
                    );
                    self.op_error_popup = None;
                    return;
                }
                TfbsTaskKind::VariantFollowupTrackSimilarity => {}
                TfbsTaskKind::ActiveSequenceTrackSimilarity { .. } => {}
            }
        }
        if let Some(report) = result.tfbs_track_similarity.clone() {
            if matches!(task_kind, TfbsTaskKind::VariantFollowupTrackSimilarity) {
                self.variant_followup_ui.cached_tfbs_track_similarity = Some(report.clone());
                self.op_status = format!(
                    "Promoter TFBS similarity updated for '{}' across {}..{} [{}]",
                    report.target_label,
                    report.view_start_0based,
                    report.view_end_0based_exclusive,
                    report.ranking_metric.as_str()
                );
                self.op_error_popup = None;
                return;
            }
        }
        self.handle_operation_success(result, started);
    }

    fn poll_tfbs_task(&mut self, ctx: &egui::Context) {
        if self.tfbs_task.is_none() {
            return;
        }

        let mut done: Option<Result<OpResult, EngineError>> = None;
        let mut processed_progress_messages = 0usize;
        let mut hit_progress_cap = false;
        let mut task_still_running = false;
        if let Some(task) = &self.tfbs_task {
            match task.receiver.lock() {
                Ok(rx) => {
                    const MAX_PROGRESS_MESSAGES_PER_TICK: usize = 512;
                    let mut processed_progress = 0usize;
                    loop {
                        match rx.try_recv() {
                            Ok(TfbsTaskMessage::Progress(progress)) => {
                                self.tfbs_progress = Some(progress);
                                processed_progress = processed_progress.saturating_add(1);
                                if processed_progress >= MAX_PROGRESS_MESSAGES_PER_TICK {
                                    hit_progress_cap = true;
                                    break;
                                }
                            }
                            Ok(TfbsTaskMessage::Done(res)) => {
                                done = Some(res);
                                break;
                            }
                            Err(TryRecvError::Disconnected) => {
                                done = Some(Err(EngineError {
                                    code: ErrorCode::Internal,
                                    message: "TFBS worker disconnected unexpectedly".to_string(),
                                }));
                                break;
                            }
                            Err(TryRecvError::Empty) => {
                                break;
                            }
                        }
                    }
                    if done.is_none() {
                        self.op_status =
                            Self::summarize_tfbs_task_status(task, self.tfbs_progress.as_ref());
                    }
                    processed_progress_messages = processed_progress;
                    task_still_running = done.is_none();
                }
                Err(_) => {
                    done = Some(Err(EngineError {
                        code: ErrorCode::Internal,
                        message: "TFBS progress channel lock poisoned".to_string(),
                    }));
                }
            }
        }

        if done.is_none() && task_still_running {
            ctx.request_repaint_after(Self::async_task_repaint_delay(
                processed_progress_messages,
                hit_progress_cap,
            ));
        }

        if let Some(done) = done {
            let started = self
                .tfbs_task
                .as_ref()
                .map(|t| t.started)
                .unwrap_or_else(Instant::now);
            let cancellation_requested = self
                .tfbs_task
                .as_ref()
                .map(|t| t.cancel_requested.load(AtomicOrdering::Relaxed))
                .unwrap_or(false);
            let operation_label = self
                .tfbs_task
                .as_ref()
                .map(|t| t.operation_label.clone())
                .unwrap_or_else(|| "TFBS task".to_string());
            let task_kind = self
                .tfbs_task
                .as_ref()
                .map(|t| t.task_kind.clone())
                .unwrap_or(TfbsTaskKind::Annotation);
            self.tfbs_task = None;
            self.tfbs_progress = None;
            match done {
                Ok(result) => {
                    self.handle_completed_tfbs_task_result(task_kind, result, started);
                    if cancellation_requested {
                        self.op_status = format!(
                            "{} finished after cancellation request in {:.1}s",
                            operation_label,
                            started.elapsed().as_secs_f32()
                        );
                    }
                }
                Err(e) => {
                    let cancelled =
                        cancellation_requested && e.message.to_ascii_lowercase().contains("cancel");
                    if cancelled {
                        self.op_status = format!(
                            "{} cancelled after {:.1}s",
                            operation_label,
                            started.elapsed().as_secs_f32()
                        );
                        self.op_error_popup = None;
                    } else {
                        self.handle_operation_error(e, started);
                    }
                }
            }
        }
    }

    fn run_preset_digest_merge_ligate(&mut self) {
        let Some(engine) = self.engine.clone() else {
            self.op_status = "No engine attached".to_string();
            return;
        };
        let template = self.seq_id.clone().unwrap_or_default();
        if template.is_empty() {
            self.op_status = "No active template sequence".to_string();
            return;
        }
        let enzymes = self
            .digest_enzymes_text
            .split(',')
            .map(|s| s.trim())
            .filter(|s| !s.is_empty())
            .map(|s| s.to_string())
            .collect::<Vec<_>>();
        if enzymes.is_empty() {
            self.op_status = "Provide at least one enzyme".to_string();
            return;
        }

        let started = Instant::now();
        let mut guard = engine.write().expect("Engine lock poisoned");
        let digest = match guard.apply(Operation::Digest {
            input: template,
            enzymes,
            output_prefix: Some(self.digest_prefix_text.clone()),
        }) {
            Ok(v) => v,
            Err(e) => {
                self.op_status = format!("Preset failed at Digest: {}", e.message);
                self.op_error_popup = Some(e.message);
                return;
            }
        };
        let merge = match guard.apply(Operation::MergeContainers {
            inputs: digest.created_seq_ids.clone(),
            output_prefix: Some("preset_merged".to_string()),
        }) {
            Ok(v) => v,
            Err(e) => {
                self.op_status = format!("Preset failed at Merge: {}", e.message);
                self.op_error_popup = Some(e.message);
                return;
            }
        };
        let ligate = match guard.apply(Operation::Ligation {
            inputs: merge.created_seq_ids.clone(),
            circularize_if_possible: false,
            output_id: None,
            protocol: LigationProtocol::Sticky,
            output_prefix: Some(self.ligation_output_prefix.clone()),
            unique: Some(false),
        }) {
            Ok(v) => v,
            Err(e) => {
                self.op_status = format!("Preset failed at Ligation: {}", e.message);
                self.op_error_popup = Some(e.message);
                return;
            }
        };
        let new_seq = ligate.created_seq_ids.first().cloned();
        drop(guard);

        if let Some(new_seq_id) = new_seq {
            let new_dna = {
                let guard = engine.read().expect("Engine lock poisoned");
                guard.state().sequences.get(&new_seq_id).cloned()
            };
            if let Some(new_dna) = new_dna {
                self.seq_id = Some(new_seq_id);
                self.replace_active_dna(new_dna, true);
            }
        }
        self.op_status = format!(
            "preset ok in {} ms: digest {} -> merge {} -> ligate {}",
            started.elapsed().as_millis(),
            digest.created_seq_ids.len(),
            merge.created_seq_ids.len(),
            ligate.created_seq_ids.len()
        );
        self.op_error_popup = None;
    }

    fn run_workflow_with_feedback(&mut self, workflow: Workflow) {
        let Some(engine) = self.engine.clone() else {
            self.op_status = "No engine attached".to_string();
            return;
        };
        let started = Instant::now();
        let workflow_run_id = workflow.run_id.clone();
        let apply_result = {
            let mut guard = engine.write().expect("Engine lock poisoned");
            guard.apply_workflow(workflow)
        };
        match apply_result {
            Ok(results) => {
                if results.is_empty() {
                    self.last_created_seq_ids.clear();
                    self.op_status = format!(
                        "workflow '{}' completed in {} ms with 0 operations",
                        workflow_run_id,
                        started.elapsed().as_millis()
                    );
                    self.op_error_popup = None;
                    return;
                }
                let op_count = results.len();
                let total_created: usize = results.iter().map(|r| r.created_seq_ids.len()).sum();
                let last_result = results.last().cloned().expect("non-empty workflow results");
                self.handle_operation_success(last_result, started);
                self.op_status = format!(
                    "workflow '{}' ok: {} op(s), {} created sequence(s)\n{}",
                    workflow_run_id, op_count, total_created, self.op_status
                );
            }
            Err(e) => self.handle_operation_error(e, started),
        }
    }

    fn infer_export_format(path: &str) -> ExportFormat {
        let lower = path.to_ascii_lowercase();
        if lower.ends_with(".fa") || lower.ends_with(".fasta") {
            ExportFormat::Fasta
        } else {
            ExportFormat::GenBank
        }
    }

    fn export_active_sequence(&mut self) {
        let Some(seq_id) = self.seq_id.clone() else {
            self.op_status = "No active sequence to export".to_string();
            return;
        };
        if self.engine.is_none() {
            self.op_status = "No engine attached".to_string();
            return;
        }

        let default_name = format!("{seq_id}.gb");
        let path = rfd::FileDialog::new()
            .set_file_name(&default_name)
            .add_filter("GenBank", &["gb", "gbk", "genbank"])
            .add_filter("FASTA", &["fa", "fasta"])
            .save_file();
        let Some(path) = path else {
            self.op_status = "Export canceled".to_string();
            return;
        };
        let path = path.display().to_string();
        let format = Self::infer_export_format(&path);
        self.apply_operation_with_feedback(Operation::SaveFile {
            seq_id,
            path,
            format,
        });
    }

    fn export_active_sequence_svg(&mut self) {
        let Some(seq_id) = self.seq_id.clone() else {
            self.op_status = "No active sequence to export".to_string();
            return;
        };
        if self.engine.is_none() {
            self.op_status = "No engine attached".to_string();
            return;
        }
        let default_name = format!("{seq_id}.svg");
        let path = rfd::FileDialog::new()
            .set_file_name(&default_name)
            .add_filter("SVG", &["svg"])
            .save_file();
        let Some(path) = path else {
            self.op_status = "Export canceled".to_string();
            return;
        };
        let path = path.display().to_string();
        let mode = if self.is_circular() {
            RenderSvgMode::Circular
        } else {
            RenderSvgMode::Linear
        };
        self.apply_operation_with_feedback(Operation::RenderSequenceSvg { seq_id, mode, path });
    }

    fn sanitize_export_name_component(raw: &str, fallback: &str) -> String {
        let mut out = String::with_capacity(raw.len());
        let mut previous_separator = false;
        for ch in raw.chars() {
            let mapped = if ch.is_ascii_alphanumeric() {
                previous_separator = false;
                Some(ch.to_ascii_lowercase())
            } else if ch == '_' || ch == '-' || ch == '.' || ch == ':' {
                if previous_separator {
                    None
                } else {
                    previous_separator = true;
                    Some('_')
                }
            } else if previous_separator {
                None
            } else {
                previous_separator = true;
                Some('_')
            };
            if let Some(mapped) = mapped {
                out.push(mapped);
            }
        }
        let mut cleaned = out.trim_matches('_').to_string();
        if cleaned.is_empty() {
            cleaned = fallback.to_string();
        }
        if cleaned.len() > 48 {
            cleaned.truncate(48);
        }
        cleaned
    }

    fn format_dotplot_filename_float_component(value: f32, scale: f32) -> String {
        if !value.is_finite() {
            return "na".to_string();
        }
        let scaled = ((value.max(0.0) as f64) * (scale.max(1.0) as f64)).round() as i64;
        scaled.max(0).to_string()
    }

    fn default_dotplot_svg_file_name(
        &self,
        view: &DotplotView,
        flex_track: Option<&FlexibilityTrack>,
        density_threshold: f32,
        intensity_gain: f32,
        overlay_x_axis_mode: DotplotOverlayXAxisMode,
        overlay_anchor_exon: Option<&DotplotOverlayAnchorExonRef>,
    ) -> String {
        let overlay_mode = Self::dotplot_view_is_overlay(view);
        let owner_id = Self::sanitize_export_name_component(
            if view.owner_seq_id.trim().is_empty() {
                view.seq_id.as_str()
            } else {
                view.owner_seq_id.as_str()
            },
            "owner",
        );
        let query_id = if overlay_mode {
            format!(
                "overlay{}_series",
                view.series_count.max(view.query_series.len())
            )
        } else {
            Self::sanitize_export_name_component(&view.seq_id, "query")
        };
        let reference_id = Self::sanitize_export_name_component(
            view.reference_seq_id
                .as_deref()
                .unwrap_or(view.seq_id.as_str()),
            "reference",
        );
        let dotplot_id = Self::sanitize_export_name_component(&view.dotplot_id, "dotplot");
        let mode = Self::sanitize_export_name_component(view.mode.as_str(), "mode");
        let tile = view
            .tile_bp
            .map(|value| value.to_string())
            .unwrap_or_else(|| "auto".to_string());
        let mut stem = if overlay_mode {
            format!(
                "dotplot_{dotplot_id}_owner-{owner_id}_q-{query_id}_r-{reference_id}_{mode}_x-{}_r{}-{}_w{}_s{}_mm{}_tile{}_th{}_gain{}",
                Self::sanitize_export_name_component(overlay_x_axis_mode.as_str(), "overlayx"),
                view.reference_span_start_0based.saturating_add(1),
                view.reference_span_end_0based,
                view.word_size,
                view.step_bp,
                view.max_mismatches,
                tile,
                Self::format_dotplot_filename_float_component(density_threshold, 100.0),
                Self::format_dotplot_filename_float_component(intensity_gain, 100.0),
            )
        } else {
            format!(
                "dotplot_{dotplot_id}_owner-{owner_id}_q-{query_id}_r-{reference_id}_{mode}_q{}-{}_r{}-{}_w{}_s{}_mm{}_tile{}_th{}_gain{}",
                view.span_start_0based.saturating_add(1),
                view.span_end_0based,
                view.reference_span_start_0based.saturating_add(1),
                view.reference_span_end_0based,
                view.word_size,
                view.step_bp,
                view.max_mismatches,
                tile,
                Self::format_dotplot_filename_float_component(density_threshold, 100.0),
                Self::format_dotplot_filename_float_component(intensity_gain, 100.0),
            )
        };
        if let Some(track) = flex_track {
            let track_id = Self::sanitize_export_name_component(&track.track_id, "flex");
            let model = Self::sanitize_export_name_component(track.model.as_str(), "model");
            let smoothing = track.smoothing_bp.unwrap_or(0);
            stem.push_str(&format!(
                "_fx-{track_id}_{model}_b{}_sm{}",
                track.bin_bp, smoothing
            ));
        }
        if overlay_mode
            && overlay_x_axis_mode == DotplotOverlayXAxisMode::SharedExonAnchor
            && let Some(exon) = overlay_anchor_exon
        {
            let exon_token = Self::sanitize_export_name_component(&exon.token(), "anchor");
            stem.push_str(&format!("_anchor-{exon_token}"));
        } else if overlay_mode
            && overlay_x_axis_mode == DotplotOverlayXAxisMode::QueryAnchorBp
            && let Some(anchor_label) = view.query_anchor_label()
        {
            let anchor_token = Self::sanitize_export_name_component(anchor_label, "anchor");
            stem.push_str(&format!("_anchor-{anchor_token}"));
        }
        if stem.len() > 220 {
            stem.truncate(220);
        }
        format!("{stem}.svg")
    }

    #[allow(dead_code)]
    fn build_dotplot_svg_document(
        view: &DotplotView,
        flex_track: Option<&FlexibilityTrack>,
        density_threshold: f32,
        intensity_gain: f32,
        crosshair_bp: Option<(usize, usize)>,
    ) -> String {
        let canvas_width = 1400.0f32;
        let canvas_height = if flex_track.is_some() { 980.0 } else { 840.0 };
        let outer_margin = 22.0f32;
        let header_height = 62.0f32;
        let top_margin = 30.0f32;
        let left_margin = 72.0f32;
        let right_margin = 20.0f32;
        let bottom_margin = 26.0f32;
        let flex_height = if flex_track.is_some() { 120.0 } else { 0.0 };
        let gap = if flex_track.is_some() { 14.0 } else { 0.0 };
        let content_top = outer_margin + header_height;
        let dotplot_left = outer_margin + left_margin;
        let dotplot_top = content_top + top_margin;
        let dotplot_right = canvas_width - (outer_margin + right_margin);
        let dotplot_bottom = canvas_height - (outer_margin + bottom_margin + flex_height + gap);
        let dotplot_width = (dotplot_right - dotplot_left).max(2.0);
        let dotplot_height = (dotplot_bottom - dotplot_top).max(2.0);
        let cols = dotplot_width.round() as i32;
        let rows = dotplot_height.round() as i32;
        let query_span = view
            .span_end_0based
            .saturating_sub(view.span_start_0based)
            .max(1);
        let query_span_max = query_span.saturating_sub(1).max(1);
        let reference_span = view
            .reference_span_end_0based
            .saturating_sub(view.reference_span_start_0based)
            .max(1);
        let reference_span_max = reference_span.saturating_sub(1).max(1);
        let reference_seq_label = view
            .reference_seq_id
            .as_deref()
            .unwrap_or(view.seq_id.as_str());
        let sample_stride = (view.points.len() / DOTPLOT_RENDER_MAX_POINTS).max(1);
        let mut cells: HashMap<(i32, i32), (usize, usize)> = HashMap::new();
        for point in view.points.iter().step_by(sample_stride) {
            let x_local = point
                .x_0based
                .saturating_sub(view.span_start_0based)
                .min(query_span_max);
            let y_local = point
                .y_0based
                .saturating_sub(view.reference_span_start_0based)
                .min(reference_span_max);
            let x_frac = (x_local as f32 / query_span_max as f32).clamp(0.0, 1.0);
            let y_frac = (y_local as f32 / reference_span_max as f32).clamp(0.0, 1.0);
            let x_cell = ((x_frac * (cols - 1) as f32).round() as i32).clamp(0, cols - 1);
            let y_cell = ((y_frac * (rows - 1) as f32).round() as i32).clamp(0, rows - 1);
            let entry = cells
                .entry((x_cell, y_cell))
                .or_insert((0usize, point.mismatches));
            entry.0 = entry.0.saturating_add(1);
            entry.1 = entry.1.min(point.mismatches);
        }
        let max_cell_count = cells.values().map(|(count, _)| *count).max().unwrap_or(1) as f32;
        let density_threshold = density_threshold.clamp(0.0, 0.99);
        let intensity_gain = intensity_gain.clamp(0.1, 16.0);
        let mut cell_entries: Vec<((i32, i32), (usize, usize))> = cells.into_iter().collect();
        cell_entries.sort_by_key(|((x_cell, y_cell), _)| (*y_cell, *x_cell));
        let mut rendered_cells = 0usize;
        let mut visible_cells: HashMap<(i32, i32), ([u8; 3], f32)> = HashMap::new();

        let mut svg = String::new();
        svg.push_str(&format!(
            "<svg xmlns=\"http://www.w3.org/2000/svg\" width=\"{:.0}\" height=\"{:.0}\" viewBox=\"0 0 {:.0} {:.0}\">",
            canvas_width, canvas_height, canvas_width, canvas_height
        ));
        svg.push_str(&format!(
            "<rect x=\"0\" y=\"0\" width=\"{:.0}\" height=\"{:.0}\" fill=\"#ffffff\"/>",
            canvas_width, canvas_height
        ));
        svg.push_str(&format!(
            "<rect x=\"{:.1}\" y=\"{:.1}\" width=\"{:.1}\" height=\"{:.1}\" fill=\"#f8fafc\" stroke=\"#cbd5e1\" stroke-width=\"1\" rx=\"6\" ry=\"6\"/>",
            outer_margin,
            content_top,
            canvas_width - 2.0 * outer_margin,
            canvas_height - content_top - outer_margin
        ));
        svg.push_str(&format!(
            "<text x=\"{:.1}\" y=\"{:.1}\" font-family=\"monospace\" font-size=\"18\" fill=\"#111827\">{}</text>",
            outer_margin,
            outer_margin + 22.0,
            Self::xml_escape(&format!("Dotplot workspace export: {}", view.dotplot_id))
        ));
        svg.push_str(&format!(
            "<text x=\"{:.1}\" y=\"{:.1}\" text-anchor=\"end\" font-family=\"monospace\" font-size=\"12\" fill=\"#334155\">{}</text>",
            canvas_width - outer_margin,
            outer_margin + 22.0,
            Self::xml_escape(&format!("query={} | reference={}", view.seq_id, reference_seq_label))
        ));
        let tile_label = view
            .tile_bp
            .map(|tile| tile.to_string())
            .unwrap_or_else(|| "auto".to_string());
        let overlap_summary =
            Self::describe_ordered_window_overlap(view.word_size.max(1), view.step_bp.max(1));
        let parameter_line = format!(
            "mode={} | q={}..{} | r={}..{} | word={} step={} mismatches={} tile={} | {} | threshold={:.2} gain={:.2} | points={} sampled_stride={}",
            view.mode.as_str(),
            view.span_start_0based.saturating_add(1),
            view.span_end_0based,
            view.reference_span_start_0based.saturating_add(1),
            view.reference_span_end_0based,
            view.word_size,
            view.step_bp,
            view.max_mismatches,
            tile_label,
            overlap_summary,
            density_threshold,
            intensity_gain,
            view.point_count,
            sample_stride
        );
        svg.push_str(&format!(
            "<text x=\"{:.1}\" y=\"{:.1}\" font-family=\"monospace\" font-size=\"11\" fill=\"#475569\">{}</text>",
            outer_margin,
            outer_margin + 42.0,
            Self::xml_escape(&parameter_line)
        ));
        svg.push_str(&format!(
            "<rect x=\"{:.1}\" y=\"{:.1}\" width=\"{:.1}\" height=\"{:.1}\" fill=\"#ffffff\" stroke=\"#cbd5e1\" stroke-width=\"1\" rx=\"4\" ry=\"4\"/>",
            dotplot_left, dotplot_top, dotplot_width, dotplot_height
        ));

        for tick_idx in 1..10 {
            let fraction = tick_idx as f32 / 10.0;
            let x = dotplot_left + fraction * dotplot_width;
            let y = dotplot_top + fraction * dotplot_height;
            svg.push_str(&format!(
                "<line x1=\"{:.2}\" y1=\"{:.2}\" x2=\"{:.2}\" y2=\"{:.2}\" stroke=\"#f1f5f9\" stroke-width=\"0.5\"/>",
                x, dotplot_top, x, dotplot_bottom
            ));
            svg.push_str(&format!(
                "<line x1=\"{:.2}\" y1=\"{:.2}\" x2=\"{:.2}\" y2=\"{:.2}\" stroke=\"#f1f5f9\" stroke-width=\"0.5\"/>",
                dotplot_left, y, dotplot_right, y
            ));
        }

        for ((x_cell, y_cell), (count, min_mismatch)) in &cell_entries {
            let density_raw = (*count as f32 / max_cell_count).clamp(0.0, 1.0);
            if density_raw < density_threshold {
                continue;
            }
            let normalized = if density_threshold <= 0.0 {
                density_raw
            } else {
                ((density_raw - density_threshold) / (1.0 - density_threshold)).clamp(0.0, 1.0)
            };
            let density = (normalized * intensity_gain).clamp(0.0, 1.0).sqrt();
            let mismatch_fraction = if view.max_mismatches == 0 {
                0.0
            } else {
                (*min_mismatch as f32 / view.max_mismatches as f32).clamp(0.0, 1.0)
            };
            let rgb = Self::mix_rgb([29, 78, 216], [180, 83, 9], mismatch_fraction);
            let alpha = (90.0 + 165.0 * density).round() as u8;
            let opacity = (alpha as f32 / 255.0).clamp(0.0, 1.0);
            let x0 = dotplot_left + (*x_cell as f32 / cols as f32) * dotplot_width;
            let x1 = dotplot_left + ((*x_cell + 1) as f32 / cols as f32) * dotplot_width;
            let y0 = dotplot_top + (*y_cell as f32 / rows as f32) * dotplot_height;
            let y1 = dotplot_top + ((*y_cell + 1) as f32 / rows as f32) * dotplot_height;
            svg.push_str(&format!(
                "<rect x=\"{:.2}\" y=\"{:.2}\" width=\"{:.2}\" height=\"{:.2}\" fill=\"rgb({},{},{})\" fill-opacity=\"{:.3}\"/>",
                x0,
                y0,
                (x1 - x0).max(0.2),
                (y1 - y0).max(0.2),
                rgb[0],
                rgb[1],
                rgb[2],
                opacity
            ));
            visible_cells.insert((*x_cell, *y_cell), (rgb, opacity));
            rendered_cells = rendered_cells.saturating_add(1);
        }

        if !visible_cells.is_empty() && visible_cells.len() <= DOTPLOT_CONNECT_DIAGONALS_MAX_CELLS {
            let cell_width = dotplot_width / cols as f32;
            let cell_height = dotplot_height / rows as f32;
            let stroke_width = (cell_width.min(cell_height) * 0.45).clamp(0.8, 2.0);
            let mut sorted_keys: Vec<(i32, i32)> = visible_cells.keys().copied().collect();
            sorted_keys.sort_by_key(|(x_cell, y_cell)| (*y_cell, *x_cell));
            for (x_cell, y_cell) in sorted_keys {
                let Some((rgb, opacity)) = visible_cells.get(&(x_cell, y_cell)).copied() else {
                    continue;
                };
                for dy in [-1, 0, 1] {
                    let neighbor = (x_cell + 1, y_cell + dy);
                    if !visible_cells.contains_key(&neighbor) {
                        continue;
                    }
                    let x0 = dotplot_left + (x_cell as f32 + 0.5) * cell_width;
                    let y0 = dotplot_top + (y_cell as f32 + 0.5) * cell_height;
                    let x1 = dotplot_left + (neighbor.0 as f32 + 0.5) * cell_width;
                    let y1 = dotplot_top + (neighbor.1 as f32 + 0.5) * cell_height;
                    let r = ((rgb[0] as f32) * 0.55).round() as u8;
                    let g = ((rgb[1] as f32) * 0.55).round() as u8;
                    let b = ((rgb[2] as f32) * 0.55).round() as u8;
                    svg.push_str(&format!(
                        "<line x1=\"{:.2}\" y1=\"{:.2}\" x2=\"{:.2}\" y2=\"{:.2}\" stroke=\"rgb({},{},{})\" stroke-opacity=\"{:.3}\" stroke-width=\"{:.2}\"/>",
                        x0,
                        y0,
                        x1,
                        y1,
                        r,
                        g,
                        b,
                        opacity.max(0.30),
                        stroke_width
                    ));
                }
            }
        }

        if rendered_cells == 0 {
            svg.push_str(&format!(
                "<text x=\"{:.1}\" y=\"{:.1}\" text-anchor=\"middle\" font-family=\"monospace\" font-size=\"11\" fill=\"#64748b\">{}</text>",
                dotplot_left + dotplot_width * 0.5,
                dotplot_top + dotplot_height * 0.5,
                Self::xml_escape(&format!(
                    "No visible cells (threshold={:.2}, points={})",
                    density_threshold, view.point_count
                ))
            ));
        }

        svg.push_str(&format!(
            "<text x=\"{:.1}\" y=\"{:.1}\" font-family=\"monospace\" font-size=\"10\" fill=\"#334155\">{}</text>",
            dotplot_left,
            content_top + 14.0,
            Self::xml_escape(&format!("x: {}", view.seq_id))
        ));
        svg.push_str(&format!(
            "<text x=\"{:.1}\" y=\"{:.1}\" text-anchor=\"end\" font-family=\"monospace\" font-size=\"10\" fill=\"#334155\">{}</text>",
            dotplot_right,
            content_top + 14.0,
            Self::xml_escape(&format!("y: {reference_seq_label}"))
        ));
        svg.push_str(&format!(
            "<text x=\"{:.1}\" y=\"{:.1}\" font-family=\"monospace\" font-size=\"10\" fill=\"#475569\">{}</text>",
            dotplot_left,
            dotplot_bottom + 14.0,
            view.span_start_0based.saturating_add(1)
        ));
        svg.push_str(&format!(
            "<text x=\"{:.1}\" y=\"{:.1}\" text-anchor=\"end\" font-family=\"monospace\" font-size=\"10\" fill=\"#475569\">{}</text>",
            dotplot_right,
            dotplot_bottom + 14.0,
            view.span_end_0based
        ));
        svg.push_str(&format!(
            "<text x=\"{:.1}\" y=\"{:.1}\" text-anchor=\"end\" font-family=\"monospace\" font-size=\"10\" fill=\"#475569\">{}</text>",
            dotplot_left - 6.0,
            dotplot_top + 10.0,
            view.reference_span_start_0based.saturating_add(1)
        ));
        svg.push_str(&format!(
            "<text x=\"{:.1}\" y=\"{:.1}\" text-anchor=\"end\" font-family=\"monospace\" font-size=\"10\" fill=\"#475569\">{}</text>",
            dotplot_left - 6.0,
            dotplot_bottom,
            view.reference_span_end_0based
        ));

        if let Some((x_bp, y_bp)) = crosshair_bp {
            let x_local = x_bp
                .saturating_sub(view.span_start_0based)
                .min(query_span_max) as f32;
            let y_local = y_bp
                .saturating_sub(view.reference_span_start_0based)
                .min(reference_span_max) as f32;
            let x = dotplot_left + (x_local / query_span_max as f32) * dotplot_width;
            let y = dotplot_top + (y_local / reference_span_max as f32) * dotplot_height;
            svg.push_str(&format!(
                "<line x1=\"{:.2}\" y1=\"{:.2}\" x2=\"{:.2}\" y2=\"{:.2}\" stroke=\"#be185d\" stroke-width=\"1.4\"/>",
                x, dotplot_top, x, dotplot_bottom
            ));
            svg.push_str(&format!(
                "<line x1=\"{:.2}\" y1=\"{:.2}\" x2=\"{:.2}\" y2=\"{:.2}\" stroke=\"#be185d\" stroke-width=\"1.4\"/>",
                dotplot_left, y, dotplot_right, y
            ));
            svg.push_str(&format!(
                "<circle cx=\"{:.2}\" cy=\"{:.2}\" r=\"2.8\" fill=\"#be185d\"/>",
                x, y
            ));
        }

        if let Some(track) = flex_track {
            let flex_top = dotplot_bottom + gap;
            let flex_bottom = canvas_height - (outer_margin + bottom_margin);
            let flex_height_px = (flex_bottom - flex_top).max(10.0);
            svg.push_str(&format!(
                "<rect x=\"{:.1}\" y=\"{:.1}\" width=\"{:.1}\" height=\"{:.1}\" fill=\"#ffffff\" stroke=\"#cbd5e1\" stroke-width=\"1\" rx=\"4\" ry=\"4\"/>",
                dotplot_left, flex_top, dotplot_width, flex_height_px
            ));
            let score_span = (track.max_score - track.min_score).abs().max(1e-12);
            let span_bp = track
                .span_end_0based
                .saturating_sub(track.span_start_0based)
                .max(1) as f32;
            let mut bins: Vec<&_> = track.bins.iter().collect();
            bins.sort_by_key(|bin| bin.start_0based);
            let mut points: Vec<(f32, f32)> = Vec::with_capacity(bins.len());
            for bin in bins {
                let x_fraction = (bin.start_0based.saturating_sub(track.span_start_0based) as f32
                    / span_bp)
                    .clamp(0.0, 1.0);
                let y_fraction =
                    ((bin.score - track.min_score) / score_span).clamp(0.0, 1.0) as f32;
                let x = dotplot_left + x_fraction * dotplot_width;
                let y = flex_bottom - y_fraction * flex_height_px;
                points.push((x, y));
            }
            for pair in points.windows(2) {
                let (left_x, left_y) = pair[0];
                let (right_x, right_y) = pair[1];
                svg.push_str(&format!(
                    "<line x1=\"{:.2}\" y1=\"{:.2}\" x2=\"{:.2}\" y2=\"{:.2}\" stroke=\"#166534\" stroke-width=\"1.5\"/>",
                    left_x, left_y, right_x, right_y
                ));
            }
            svg.push_str(&format!(
                "<text x=\"{:.1}\" y=\"{:.1}\" font-family=\"monospace\" font-size=\"10\" fill=\"#0f172a\">{}</text>",
                dotplot_left + 6.0,
                flex_top + 14.0,
                Self::xml_escape(&format!(
                    "{} [{}..{}] min={:.3} max={:.3}",
                    track.model.as_str(),
                    track.span_start_0based.saturating_add(1),
                    track.span_end_0based,
                    track.min_score,
                    track.max_score
                ))
            ));
        }

        svg.push_str(&format!(
            "<text x=\"{:.1}\" y=\"{:.1}\" text-anchor=\"end\" font-family=\"monospace\" font-size=\"10\" fill=\"#64748b\">GENtle dotplot SVG export</text>",
            canvas_width - outer_margin,
            canvas_height - 6.0
        ));
        svg.push_str("</svg>");
        svg
    }

    fn export_active_dotplot_svg(&mut self) {
        self.ensure_dotplot_cache_current();
        let Some(view) = self.dotplot_cached_view.clone() else {
            self.op_status = "No loaded dotplot payload to export".to_string();
            return;
        };
        let overlay_mode = Self::dotplot_view_is_overlay(&view);
        let selected_flex_track = if self.dotplot_ui.show_flexibility_track && !overlay_mode {
            self.dotplot_cached_flex_track.clone()
        } else {
            None
        };
        let density_threshold = self.dotplot_ui.display_density_threshold;
        let intensity_gain = self.dotplot_ui.display_intensity_gain;
        let default_name = self.default_dotplot_svg_file_name(
            &view,
            selected_flex_track.as_ref(),
            density_threshold,
            intensity_gain,
            self.dotplot_ui.overlay_x_axis_mode,
            if self.dotplot_ui.overlay_x_axis_mode == DotplotOverlayXAxisMode::SharedExonAnchor {
                self.dotplot_ui.overlay_anchor_exon.as_ref()
            } else {
                None
            },
        );
        let path = rfd::FileDialog::new()
            .set_file_name(&default_name)
            .add_filter("SVG", &["svg"])
            .save_file();
        let Some(path) = path else {
            self.op_status = "Dotplot SVG export canceled".to_string();
            return;
        };
        let path_text = path.display().to_string();
        let flex_track_id = selected_flex_track
            .as_ref()
            .map(|track| track.track_id.clone());
        self.apply_operation_with_feedback(Operation::RenderDotplotSvg {
            seq_id: view.owner_seq_id.clone(),
            dotplot_id: view.dotplot_id.clone(),
            path: path_text.clone(),
            flex_track_id,
            display_density_threshold: Some(density_threshold),
            display_intensity_gain: Some(intensity_gain),
            overlay_x_axis_mode: self.dotplot_ui.overlay_x_axis_mode,
            overlay_anchor_exon: if self.dotplot_ui.overlay_x_axis_mode
                == DotplotOverlayXAxisMode::SharedExonAnchor
            {
                self.dotplot_ui.overlay_anchor_exon.clone()
            } else {
                None
            },
        });
    }

    fn xml_escape(text: &str) -> String {
        text.replace('&', "&amp;")
            .replace('<', "&lt;")
            .replace('>', "&gt;")
            .replace('"', "&quot;")
            .replace('\'', "&apos;")
    }

    fn extract_svg_inner(svg: &str) -> Option<&str> {
        let open_end = svg.find('>')?;
        let close_start = svg.rfind("</svg>")?;
        if close_start <= open_end {
            return None;
        }
        Some(&svg[(open_end + 1)..close_start])
    }

    fn format_grouped_bases(bytes: &[u8]) -> String {
        let mut out = String::with_capacity(bytes.len() + (bytes.len() / 10));
        for (idx, base) in bytes.iter().enumerate() {
            out.push((*base as char).to_ascii_uppercase());
            if (idx + 1) % 10 == 0 && (idx + 1) < bytes.len() {
                out.push(' ');
            }
        }
        out
    }

    fn extract_svg_attribute<'a>(open_tag: &'a str, name: &str) -> Option<&'a str> {
        let needle = format!("{name}=\"");
        let start = open_tag.find(&needle)? + needle.len();
        let rest = &open_tag[start..];
        let end = rest.find('"')?;
        Some(&rest[..end])
    }

    fn parse_svg_scalar(value: &str) -> Option<f32> {
        let numeric: String = value
            .trim()
            .chars()
            .take_while(|ch| ch.is_ascii_digit() || matches!(*ch, '.' | '-' | '+' | 'e' | 'E'))
            .collect();
        if numeric.is_empty() {
            return None;
        }
        numeric.parse::<f32>().ok()
    }

    fn extract_svg_canvas_size(svg: &str) -> Option<(f32, f32)> {
        let open_end = svg.find('>')?;
        let open_tag = &svg[..open_end];
        if let Some(view_box) = Self::extract_svg_attribute(open_tag, "viewBox") {
            let values: Vec<f32> = view_box
                .split_whitespace()
                .filter_map(|v| v.parse::<f32>().ok())
                .collect();
            if values.len() == 4
                && values[2].is_finite()
                && values[3].is_finite()
                && values[2] > 1.0
                && values[3] > 1.0
            {
                return Some((values[2], values[3]));
            }
        }
        let width = Self::extract_svg_attribute(open_tag, "width").and_then(Self::parse_svg_scalar);
        let height =
            Self::extract_svg_attribute(open_tag, "height").and_then(Self::parse_svg_scalar);
        match (width, height) {
            (Some(w), Some(h)) if w > 1.0 && h > 1.0 => Some((w, h)),
            _ => None,
        }
    }

    fn render_splicing_map_placeholder_svg(seq_id: &str) -> String {
        let title = format!("Splicing map (read-only) | {seq_id}");
        let subtitle = "No splicing-seed feature is selected";
        let hint = "Select an mRNA, ncRNA, misc_RNA, transcript, exon, gene, or CDS feature in the feature tree to render transcript/exon lanes.";
        format!(
            concat!(
                "<svg xmlns=\"http://www.w3.org/2000/svg\" width=\"1200\" height=\"700\" viewBox=\"0 0 1200 700\">",
                "<rect x=\"0\" y=\"0\" width=\"1200\" height=\"700\" fill=\"#ffffff\"/>",
                "<rect x=\"36\" y=\"56\" width=\"1128\" height=\"588\" fill=\"#f9fafb\" stroke=\"#d1d5db\" stroke-width=\"1\"/>",
                "<text x=\"68\" y=\"104\" font-family=\"monospace\" font-size=\"22\" fill=\"#111827\">{}</text>",
                "<text x=\"68\" y=\"146\" font-family=\"monospace\" font-size=\"16\" fill=\"#374151\">{}</text>",
                "<text x=\"68\" y=\"184\" font-family=\"monospace\" font-size=\"14\" fill=\"#4b5563\">{}</text>",
                "</svg>"
            ),
            Self::xml_escape(&title),
            Self::xml_escape(subtitle),
            Self::xml_escape(hint)
        )
    }

    fn view_svg_export_layout(
        profile: ViewSvgExportProfile,
        observed_map_width_px: f32,
        show_map: bool,
        show_sequence: bool,
    ) -> ViewSvgExportLayout {
        let observed_map_width_px = if observed_map_width_px.is_finite() {
            observed_map_width_px.clamp(320.0, 8192.0)
        } else {
            1200.0
        };
        match profile {
            ViewSvgExportProfile::Screen => ViewSvgExportLayout {
                canvas_width_px: (observed_map_width_px + 56.0).clamp(1200.0, 2400.0),
                margin_px: 28.0,
                map_panel_height_px: if show_map && show_sequence {
                    520.0
                } else {
                    700.0
                },
                sequence_panel_height_px: 380.0,
                header_height_px: 78.0,
                footer_height_px: 20.0,
                sequence_font_size_px: 16.0,
                sequence_line_height_px: 22.0,
                max_text_lines: 24,
                viewport_span_multiplier: 1.0,
                print_size_mm: None,
            },
            ViewSvgExportProfile::WideContext => ViewSvgExportLayout {
                canvas_width_px: (observed_map_width_px * 1.8).clamp(1800.0, 3600.0),
                margin_px: 32.0,
                map_panel_height_px: if show_map && show_sequence {
                    760.0
                } else {
                    1040.0
                },
                sequence_panel_height_px: 680.0,
                header_height_px: 90.0,
                footer_height_px: 28.0,
                sequence_font_size_px: 14.0,
                sequence_line_height_px: 19.0,
                max_text_lines: 56,
                viewport_span_multiplier: 2.0,
                print_size_mm: None,
            },
            ViewSvgExportProfile::PrintA3Landscape => ViewSvgExportLayout {
                canvas_width_px: 4960.0,
                margin_px: 40.0,
                map_panel_height_px: if show_map && show_sequence {
                    1750.0
                } else {
                    2900.0
                },
                sequence_panel_height_px: 1450.0,
                header_height_px: 120.0,
                footer_height_px: 60.0,
                sequence_font_size_px: 13.0,
                sequence_line_height_px: 17.0,
                max_text_lines: 130,
                viewport_span_multiplier: 4.0,
                print_size_mm: Some((420.0, 297.0)),
            },
        }
    }

    fn expand_linear_export_window(
        start_bp: usize,
        span_bp: usize,
        sequence_len_bp: usize,
        multiplier: f32,
    ) -> (usize, usize) {
        if sequence_len_bp == 0 {
            return (0, 0);
        }
        let base_span = span_bp.max(1).min(sequence_len_bp);
        let multiplier = if multiplier.is_finite() {
            multiplier.max(1.0)
        } else {
            1.0
        };
        let expanded_span = ((base_span as f64) * (multiplier as f64)).round() as usize;
        let expanded_span = expanded_span.clamp(base_span, sequence_len_bp);
        let center = start_bp
            .saturating_add(base_span / 2)
            .min(sequence_len_bp.saturating_sub(1));
        let mut expanded_start = center.saturating_sub(expanded_span / 2);
        if expanded_start.saturating_add(expanded_span) > sequence_len_bp {
            expanded_start = sequence_len_bp.saturating_sub(expanded_span);
        }
        (expanded_start, expanded_span)
    }

    fn export_active_view_svg(&mut self, profile: ViewSvgExportProfile) {
        let Some(seq_id) = self.seq_id.clone() else {
            self.op_status = "No active sequence to export".to_string();
            return;
        };
        let Some(engine) = self.engine.clone() else {
            self.op_status = "No engine attached".to_string();
            return;
        };
        let default_name = format!("{seq_id}.{}.svg", profile.file_stem_suffix());
        let path = rfd::FileDialog::new()
            .set_file_name(&default_name)
            .add_filter("SVG", &["svg"])
            .save_file();
        let Some(path) = path else {
            self.op_status = "Export canceled".to_string();
            return;
        };

        let primary_splicing_map_export =
            !self.is_circular() && matches!(self.primary_map_mode, PrimaryMapMode::Splicing);
        let splicing_export_view = if primary_splicing_map_export {
            self.current_splicing_expert_view_for_primary_map()
        } else {
            None
        };

        let (map_svg, map_mode_label) = {
            let guard = engine.read().expect("Engine lock poisoned");
            let state = guard.state();
            let Some(dna) = state.sequences.get(&seq_id) else {
                self.op_status = format!("Active sequence '{seq_id}' not found in engine state");
                return;
            };
            if self.is_circular() {
                (
                    export_circular_svg(dna, &state.display),
                    "circular".to_string(),
                )
            } else if primary_splicing_map_export {
                let map_svg = if let Some(view) = &splicing_export_view {
                    let expert = FeatureExpertView::Splicing(view.clone());
                    render_feature_expert_svg(&expert)
                } else {
                    Self::render_splicing_map_placeholder_svg(&seq_id)
                };
                (map_svg, "linear-splicing".to_string())
            } else {
                (export_linear_svg(dna, &state.display), "linear".to_string())
            }
        };

        let dna_guard = match self.dna.read() {
            Ok(guard) => guard,
            Err(_) => {
                self.op_status = "Could not read active DNA sequence for export".to_string();
                return;
            }
        };
        let display_guard = match self.dna_display.read() {
            Ok(guard) => guard,
            Err(_) => {
                self.op_status = "Could not read display settings for export".to_string();
                return;
            }
        };

        let layout = Self::view_svg_export_layout(
            profile,
            self.last_linear_map_width_px,
            self.show_map,
            self.show_sequence,
        );
        let width_px = layout.canvas_width_px.max(1200.0);
        let margin = layout.margin_px;
        let map_panel_h = layout.map_panel_height_px;
        let sequence_panel_h = if self.show_sequence {
            layout.sequence_panel_height_px
        } else {
            0.0
        };
        let header_h = layout.header_height_px;
        let footer_h = layout.footer_height_px;
        let mut y = (header_h * 0.34).max(24.0);
        let mut total_h = header_h + footer_h;
        if self.show_map {
            total_h += map_panel_h + 14.0;
        }
        if self.show_sequence {
            total_h += sequence_panel_h + 14.0;
        }

        let mut svg = String::new();
        if let Some((print_w_mm, print_h_mm)) = layout.print_size_mm {
            svg.push_str(&format!(
                "<svg xmlns=\"http://www.w3.org/2000/svg\" width=\"{:.1}mm\" height=\"{:.1}mm\" viewBox=\"0 0 {:.0} {:.0}\">",
                print_w_mm, print_h_mm, width_px, total_h
            ));
        } else {
            svg.push_str(&format!(
                "<svg xmlns=\"http://www.w3.org/2000/svg\" width=\"{:.0}\" height=\"{:.0}\" viewBox=\"0 0 {:.0} {:.0}\">",
                width_px, total_h, width_px, total_h
            ));
        }
        svg.push_str(&format!(
            "<rect x=\"0\" y=\"0\" width=\"{:.0}\" height=\"{:.0}\" fill=\"#ffffff\"/>",
            width_px, total_h
        ));

        let seq_name = dna_guard
            .name()
            .as_ref()
            .cloned()
            .filter(|name| !name.trim().is_empty())
            .unwrap_or_else(|| seq_id.clone());
        let header_left = format!("{} ({})", seq_name, seq_id);
        svg.push_str(&format!(
            "<text x=\"{:.1}\" y=\"{:.1}\" font-family=\"monospace\" font-size=\"18\" fill=\"#111111\">{}</text>",
            margin,
            y,
            Self::xml_escape(&header_left)
        ));
        let status_right = format!(
            "map={} | profile={} | show-map={} | show-sequence={}",
            map_mode_label,
            profile.label(),
            self.show_map,
            self.show_sequence
        );
        svg.push_str(&format!(
            "<text x=\"{:.1}\" y=\"{:.1}\" text-anchor=\"end\" font-family=\"monospace\" font-size=\"13\" fill=\"#444444\">{}</text>",
            width_px - margin,
            y,
            Self::xml_escape(&status_right)
        ));
        y += 24.0;

        let routing = self.linear_base_routing_decision();
        let (linear_start, linear_span, sequence_length) = self.current_linear_viewport();
        let viewport_text = if self.is_circular() {
            format!("circular view | {} bp", dna_guard.len())
        } else if primary_splicing_map_export {
            if let Some(view) = &splicing_export_view {
                format!(
                    "linear splicing view {}..{} ({} bp) of {} bp | transcripts={} | unique exons={} | strand={}",
                    view.region_start_1based,
                    view.region_end_1based,
                    view.region_end_1based
                        .saturating_sub(view.region_start_1based)
                        .saturating_add(1),
                    dna_guard.len(),
                    view.transcript_count,
                    view.unique_exon_count,
                    view.strand
                )
            } else {
                format!(
                    "linear splicing view | {} bp | no selected transcript-like RNA/exon feature",
                    dna_guard.len()
                )
            }
        } else {
            format!(
                "linear view {}..{} ({} bp) of {} bp | density {:.2} | cols-fit {:.0} | glyph {:.2}px | export-span x{:.1}",
                linear_start.saturating_add(1),
                linear_start
                    .saturating_add(linear_span)
                    .min(sequence_length),
                linear_span,
                sequence_length,
                routing.density_ratio,
                routing.columns_fit,
                routing.glyph_width_px,
                layout.viewport_span_multiplier
            )
        };
        svg.push_str(&format!(
            "<text x=\"{:.1}\" y=\"{:.1}\" font-family=\"monospace\" font-size=\"12\" fill=\"#555555\">{}</text>",
            margin,
            y,
            Self::xml_escape(&viewport_text)
        ));
        y += 18.0;
        if cfg!(debug_assertions) && !self.is_circular() && !primary_splicing_map_export {
            let threshold_text = format!(
                "debug tiers: standard<= {:.2}, helical<= {:.2}, condensed<= {:.2}",
                routing.tier_standard_max_density,
                routing.tier_helical_max_density,
                routing.tier_condensed_max_density
            );
            svg.push_str(&format!(
                "<text x=\"{:.1}\" y=\"{:.1}\" font-family=\"monospace\" font-size=\"11\" fill=\"#666666\">{}</text>",
                margin,
                y,
                Self::xml_escape(&threshold_text)
            ));
            y += 18.0;
        }

        if self.show_map {
            let panel_w = width_px - 2.0 * margin;
            let panel_h = map_panel_h;
            svg.push_str(&format!(
                "<rect x=\"{:.1}\" y=\"{:.1}\" width=\"{:.1}\" height=\"{:.1}\" fill=\"#fafafa\" stroke=\"#dddddd\" stroke-width=\"1\"/>",
                margin, y, panel_w, panel_h
            ));
            if let Some(inner) = Self::extract_svg_inner(&map_svg) {
                let (map_native_w, map_native_h) =
                    Self::extract_svg_canvas_size(&map_svg).unwrap_or((1200.0, 700.0));
                let scale = (panel_w / map_native_w)
                    .min(panel_h / map_native_h)
                    .max(0.1);
                let map_x = margin + (panel_w - map_native_w * scale) * 0.5;
                let map_y = y + (panel_h - map_native_h * scale) * 0.5;
                svg.push_str(&format!(
                    "<g transform=\"translate({:.2} {:.2}) scale({:.5})\">",
                    map_x, map_y, scale
                ));
                svg.push_str(inner);
                svg.push_str("</g>");
            } else {
                svg.push_str(&format!(
                    "<text x=\"{:.1}\" y=\"{:.1}\" font-family=\"monospace\" font-size=\"13\" fill=\"#a00000\">Could not embed map SVG content</text>",
                    margin + 10.0,
                    y + 22.0
                ));
            }
            y += panel_h + 14.0;
        }

        if self.show_sequence {
            let panel_w = width_px - 2.0 * margin;
            let panel_h = sequence_panel_h;
            svg.push_str(&format!(
                "<rect x=\"{:.1}\" y=\"{:.1}\" width=\"{:.1}\" height=\"{:.1}\" fill=\"#fcfcfc\" stroke=\"#dddddd\" stroke-width=\"1\"/>",
                margin, y, panel_w, panel_h
            ));
            let y0 = y + 22.0;
            let digits = dna_guard.len().max(1).to_string().len();
            let show_rc = display_guard.show_reverse_complement();
            let estimated_bpl = ((panel_w / (layout.sequence_font_size_px * 0.62)).floor()
                as usize)
                .saturating_div(11)
                .saturating_mul(10)
                .clamp(40, 1200);
            let (window_start, window_span) = if self.is_circular() {
                let base_line_budget = if show_rc {
                    layout.max_text_lines.saturating_div(2).max(1)
                } else {
                    layout.max_text_lines.max(1)
                };
                (
                    0usize,
                    dna_guard
                        .len()
                        .min(estimated_bpl.saturating_mul(base_line_budget)),
                )
            } else {
                Self::expand_linear_export_window(
                    linear_start,
                    linear_span,
                    dna_guard.len(),
                    layout.viewport_span_multiplier,
                )
            };
            let window_end = window_start
                .saturating_add(window_span)
                .min(dna_guard.len());
            let mut line_idx = 0usize;
            let mut bp = window_start;
            let max_text_lines = layout.max_text_lines;
            while bp < window_end && line_idx < max_text_lines {
                let end = (bp + estimated_bpl).min(window_end);
                let Some(segment) = dna_guard.get_inclusive_range_safe(bp..=end.saturating_sub(1))
                else {
                    break;
                };
                let grouped = Self::format_grouped_bases(&segment);
                let text = format!(
                    "{:>width$} {}",
                    bp.saturating_add(1),
                    grouped,
                    width = digits
                );
                svg.push_str(&format!(
                    "<text x=\"{:.1}\" y=\"{:.1}\" font-family=\"monospace\" font-size=\"{:.1}\" fill=\"#111111\">{}</text>",
                    margin + 10.0,
                    y0 + line_idx as f32 * layout.sequence_line_height_px,
                    layout.sequence_font_size_px,
                    Self::xml_escape(&text)
                ));
                line_idx += 1;
                if show_rc && line_idx < max_text_lines {
                    let mut rc = Vec::with_capacity(segment.len());
                    for base in segment.iter().rev() {
                        rc.push(IupacCode::letter_complement(*base));
                    }
                    let rc_grouped = Self::format_grouped_bases(&rc);
                    let rc_text = format!("{:>width$} {}", "", rc_grouped, width = digits);
                    svg.push_str(&format!(
                        "<text x=\"{:.1}\" y=\"{:.1}\" font-family=\"monospace\" font-size=\"{:.1}\" fill=\"#666666\">{}</text>",
                        margin + 10.0,
                        y0 + line_idx as f32 * layout.sequence_line_height_px,
                        layout.sequence_font_size_px,
                        Self::xml_escape(&rc_text)
                    ));
                    line_idx += 1;
                }
                bp = end;
            }
            if bp < window_end {
                let remaining = window_end.saturating_sub(bp);
                svg.push_str(&format!(
                    "<text x=\"{:.1}\" y=\"{:.1}\" font-family=\"monospace\" font-size=\"12\" fill=\"#777777\">... {} bp not shown in this SVG panel extract</text>",
                    margin + 10.0,
                    y + panel_h - 12.0,
                    remaining
                ));
            }
        }

        svg.push_str(&format!(
            "<text x=\"{:.1}\" y=\"{:.1}\" text-anchor=\"end\" font-family=\"monospace\" font-size=\"11\" fill=\"#666666\">GENtle view export ({})</text>",
            width_px - margin,
            total_h - 8.0,
            profile.label()
        ));
        svg.push_str("</svg>");

        let path_text = path.display().to_string();
        match fs::write(&path, svg) {
            Ok(()) => {
                self.op_status = format!(
                    "Exported sequence window view SVG ({}) to '{}'",
                    profile.label(),
                    path_text
                );
            }
            Err(e) => {
                self.op_status = format!("Could not write view SVG '{}': {e}", path_text);
            }
        }
    }

    fn is_single_stranded_rna(&self) -> bool {
        self.dna
            .read()
            .ok()
            .and_then(|dna| dna.molecule_type().map(ToString::to_string))
            .map(|v| v.eq_ignore_ascii_case("RNA") || v.eq_ignore_ascii_case("ssRNA"))
            .unwrap_or(false)
    }

    fn refresh_rna_structure(&mut self) {
        if !self.is_single_stranded_rna() {
            self.rna_status = "RNA structure is only available for single-stranded RNA".to_string();
            return;
        }
        let Some(seq_id) = self.seq_id.clone() else {
            self.rna_status = "No active sequence id for RNA structure".to_string();
            return;
        };
        let Some(engine) = self.engine.clone() else {
            self.rna_status = "No engine attached".to_string();
            return;
        };

        let sanitized_seq_id: String = seq_id
            .chars()
            .map(|c| {
                if c.is_ascii_alphanumeric() || matches!(c, '-' | '_') {
                    c
                } else {
                    '_'
                }
            })
            .collect();
        let preview_path =
            std::env::temp_dir().join(format!("gentle_rna_preview_{sanitized_seq_id}.svg"));
        let preview_path_text = preview_path.display().to_string();

        let outcome = {
            let guard = engine.read().expect("Engine lock poisoned");
            let text_report = guard.inspect_rna_structure(&seq_id);
            let svg_report = guard.render_rna_structure_svg_to_path(&seq_id, &preview_path_text);
            (text_report, svg_report)
        };

        match outcome {
            (Ok(text_report), Ok(_svg_report)) => {
                let mut text = format!(
                    "Tool: {}\nExecutable: {}\nSequence length: {}\nCommand: {} {}\n",
                    text_report.tool,
                    text_report.executable,
                    text_report.sequence_length,
                    text_report.executable,
                    text_report.command.join(" ")
                );
                if !text_report.structure.is_empty() {
                    text.push_str(&format!("Structure: {}\n", text_report.structure));
                }
                if let Some(mfe) = text_report.mfe_kcal_per_mol {
                    text.push_str(&format!("MFE: {mfe:.2} kcal/mol\n"));
                }
                if !text_report.stdout.trim().is_empty() {
                    text.push_str("\nstdout:\n");
                    text.push_str(&text_report.stdout);
                    if !text.ends_with('\n') {
                        text.push('\n');
                    }
                }
                if !text_report.stderr.trim().is_empty() {
                    text.push_str("\nstderr:\n");
                    text.push_str(&text_report.stderr);
                    if !text.ends_with('\n') {
                        text.push('\n');
                    }
                }
                self.rna_info_text = text;
                self.rna_preview_path = Some(preview_path.clone());
                self.rna_svg_uri = format!("file://{}", preview_path.display());
                self.rna_status = "RNA structure refreshed from RNAfold/rnapkin".to_string();
            }
            (Err(e), _) | (_, Err(e)) => {
                self.rna_status = format!("RNA structure error: {}", e);
                self.rna_info_text.clear();
                self.rna_svg_uri.clear();
                self.rna_preview_path = None;
            }
        }
    }

    fn export_rna_structure_svg(&mut self) {
        if !self.is_single_stranded_rna() {
            self.op_status =
                "RNA structure export is only available for single-stranded RNA".to_string();
            return;
        }
        let Some(seq_id) = self.seq_id.clone() else {
            self.op_status = "No active sequence to export".to_string();
            return;
        };
        if self.engine.is_none() {
            self.op_status = "No engine attached".to_string();
            return;
        }
        let default_name = format!("{seq_id}.rna.svg");
        let path = rfd::FileDialog::new()
            .set_file_name(&default_name)
            .add_filter("SVG", &["svg"])
            .save_file();
        let Some(path) = path else {
            self.op_status = "Export canceled".to_string();
            return;
        };
        let path = path.display().to_string();
        self.apply_operation_with_feedback(Operation::RenderRnaStructureSvg { seq_id, path });
    }

    fn render_rna_structure_panel(&mut self, ui: &mut egui::Ui) {
        if !self.is_single_stranded_rna() {
            return;
        }
        if self.rna_info_text.trim().is_empty()
            && self.rna_svg_uri.trim().is_empty()
            && self.rna_status.trim().is_empty()
        {
            self.refresh_rna_structure();
        }

        ui.collapsing("RNA Structure (rnapkin)", |ui| {
            ui.horizontal(|ui| {
                if ui
                    .button("Refresh RNA Structure")
                    .on_hover_text("Run RNAfold for the structure and rnapkin for the SVG preview")
                    .clicked()
                {
                    self.refresh_rna_structure();
                }
                if ui
                    .button("Export RNA SVG")
                    .on_hover_text("Export current RNA structure image as SVG via shared engine")
                    .clicked()
                {
                    self.export_rna_structure_svg();
                }
            });

            if !self.rna_status.trim().is_empty() {
                ui.monospace(self.rna_status.clone());
            }

            if !self.rna_svg_uri.trim().is_empty() {
                ui.add(
                    egui::Image::from_uri(self.rna_svg_uri.clone())
                        .max_width(ui.available_width())
                        .max_height(360.0)
                        .shrink_to_fit(),
                );
            }

            if !self.rna_info_text.trim().is_empty() {
                ui.label("Textual report");
                ui.add(
                    egui::TextEdit::multiline(&mut self.rna_info_text)
                        .desired_rows(10)
                        .code_editor()
                        .interactive(false),
                );
            }
        });
    }

    fn export_pool_to_file(&mut self) {
        if self.engine.is_none() {
            self.op_status = "No engine attached".to_string();
            return;
        }
        let inputs = Self::parse_ids(&self.export_pool_inputs_text);
        if inputs.is_empty() {
            self.op_status = "Provide at least one sequence id for ExportPool".to_string();
            return;
        }
        let path = rfd::FileDialog::new()
            .set_file_name("pool.json")
            .add_filter("JSON", &["json"])
            .save_file();
        let Some(path) = path else {
            self.op_status = "Export canceled".to_string();
            return;
        };
        let path = path.display().to_string();
        self.apply_operation_with_feedback(Operation::ExportPool {
            inputs,
            path,
            pool_id: if self.export_pool_id.trim().is_empty() {
                None
            } else {
                Some(self.export_pool_id.trim().to_string())
            },
            human_id: if self.export_pool_human_id.trim().is_empty() {
                None
            } else {
                Some(self.export_pool_human_id.trim().to_string())
            },
        });
    }

    fn export_pool_gel_svg(&mut self) {
        if self.engine.is_none() {
            self.op_status = "No engine attached".to_string();
            return;
        }
        let inputs = Self::parse_ids(&self.export_pool_inputs_text);
        if inputs.is_empty() {
            self.op_status =
                "Provide at least one sequence id in 'inputs' for pool gel export".to_string();
            return;
        }
        let path = rfd::FileDialog::new()
            .set_file_name("pool.gel.svg")
            .add_filter("SVG", &["svg"])
            .save_file();
        let Some(path) = path else {
            self.op_status = "Export canceled".to_string();
            return;
        };
        let path = path.display().to_string();
        let ladders = Self::parse_ids(&self.pool_gel_ladders);
        self.apply_operation_with_feedback(Operation::RenderPoolGelSvg {
            inputs,
            path,
            ladders: if ladders.is_empty() {
                None
            } else {
                Some(ladders)
            },
            container_ids: None,
            arrangement_id: None,
            conditions: None,
        });
    }

    fn parse_candidate_local_anchor(
        mode_position: bool,
        position: &str,
        feature_kind: &str,
        feature_label: &str,
        boundary: &AnchorBoundary,
        occurrence: &str,
        anchor_name: &str,
    ) -> Result<AnchoredRegionAnchor, String> {
        if mode_position {
            let zero_based = position.trim().parse::<usize>().map_err(|_| {
                format!("Invalid {anchor_name} anchor position (expected 0-based integer)")
            })?;
            Ok(AnchoredRegionAnchor::Position { zero_based })
        } else {
            let occurrence = if occurrence.trim().is_empty() {
                None
            } else {
                Some(occurrence.trim().parse::<usize>().map_err(|_| {
                    format!("Invalid {anchor_name} anchor occurrence (expected integer)")
                })?)
            };
            Ok(AnchoredRegionAnchor::FeatureBoundary {
                feature_kind: if feature_kind.trim().is_empty() {
                    None
                } else {
                    Some(feature_kind.trim().to_string())
                },
                feature_label: if feature_label.trim().is_empty() {
                    None
                } else {
                    Some(feature_label.trim().to_string())
                },
                boundary: boundary.clone(),
                occurrence,
            })
        }
    }

    fn candidate_metric_lookup(record: &CandidateRecord, key: &str) -> Option<f64> {
        if let Some(value) = record.metrics.get(key).copied() {
            return Some(value);
        }
        let lower = key.to_ascii_lowercase();
        if lower == key {
            None
        } else {
            record.metrics.get(&lower).copied()
        }
    }

    fn compare_candidate_records(
        a: &CandidateRecord,
        b: &CandidateRecord,
        sort_key: &str,
    ) -> Ordering {
        let key = sort_key.trim().to_ascii_lowercase();
        match key.as_str() {
            "seq_id" => a
                .seq_id
                .cmp(&b.seq_id)
                .then(a.start_0based.cmp(&b.start_0based))
                .then(a.end_0based.cmp(&b.end_0based)),
            "start" | "start_0based" => a
                .start_0based
                .cmp(&b.start_0based)
                .then(a.end_0based.cmp(&b.end_0based))
                .then(a.seq_id.cmp(&b.seq_id)),
            "end" | "end_0based" => a
                .end_0based
                .cmp(&b.end_0based)
                .then(a.start_0based.cmp(&b.start_0based))
                .then(a.seq_id.cmp(&b.seq_id)),
            "length" | "length_bp" => a
                .end_0based
                .saturating_sub(a.start_0based)
                .cmp(&b.end_0based.saturating_sub(b.start_0based))
                .then(a.start_0based.cmp(&b.start_0based))
                .then(a.seq_id.cmp(&b.seq_id)),
            "sequence" => a
                .sequence
                .cmp(&b.sequence)
                .then(a.seq_id.cmp(&b.seq_id))
                .then(a.start_0based.cmp(&b.start_0based)),
            _ => {
                let a_value =
                    Self::candidate_metric_lookup(a, sort_key).unwrap_or(f64::NEG_INFINITY);
                let b_value =
                    Self::candidate_metric_lookup(b, sort_key).unwrap_or(f64::NEG_INFINITY);
                a_value
                    .partial_cmp(&b_value)
                    .unwrap_or(Ordering::Equal)
                    .then(a.seq_id.cmp(&b.seq_id))
                    .then(a.start_0based.cmp(&b.start_0based))
                    .then(a.end_0based.cmp(&b.end_0based))
            }
        }
    }

    fn sort_candidate_records(rows: &mut [CandidateRecord], sort_key: &str, descending: bool) {
        rows.sort_by(|a, b| Self::compare_candidate_records(a, b, sort_key));
        if descending {
            rows.reverse();
        }
    }

    fn render_candidate_sets_ops(&mut self, ui: &mut egui::Ui) {
        let Some(engine) = self.engine.clone() else {
            ui.label("No engine attached.");
            return;
        };
        if self.candidate_source_seq_id.trim().is_empty() {
            self.candidate_source_seq_id = self.seq_id.clone().unwrap_or_default();
        }
        if self.candidate_between_seq_id.trim().is_empty() {
            self.candidate_between_seq_id = self.seq_id.clone().unwrap_or_default();
        }

        let (set_summaries, sequence_ids) = {
            let guard = engine.read().expect("Engine lock poisoned");
            let mut set_summaries = guard.list_candidate_sets();
            set_summaries.sort_by(|a, b| a.name.cmp(&b.name));
            let mut sequence_ids = guard.state().sequences.keys().cloned().collect::<Vec<_>>();
            sequence_ids.sort_unstable();
            (set_summaries, sequence_ids)
        };
        let set_names: Vec<String> = set_summaries.iter().map(|s| s.name.clone()).collect();

        if !set_names.is_empty() {
            if self.candidate_selected_set.trim().is_empty()
                || !set_names.iter().any(|n| n == &self.candidate_selected_set)
            {
                self.candidate_selected_set = set_names[0].clone();
            }
        } else {
            self.candidate_selected_set.clear();
        }
        if self.candidate_filter_input_set.trim().is_empty()
            && !self.candidate_selected_set.is_empty()
        {
            self.candidate_filter_input_set = self.candidate_selected_set.clone();
        }

        ui.small(
            "Generate, score, filter, combine, inspect, export, and macro-run candidate sets.",
        );

        ui.separator();
        ui.label("Generate set");
        ui.horizontal(|ui| {
            ui.label("set");
            ui.text_edit_singleline(&mut self.candidate_set_name);
            ui.label("seq");
            ui.text_edit_singleline(&mut self.candidate_source_seq_id);
            if ui
                .small_button("Use active")
                .on_hover_text("Use currently active sequence ID as candidate source")
                .clicked()
            {
                self.candidate_source_seq_id = self.seq_id.clone().unwrap_or_default();
            }
        });
        if !sequence_ids.is_empty() {
            egui::ComboBox::from_id_salt(format!(
                "candidate_source_seq_combo_{}",
                self.seq_id.as_deref().unwrap_or("_global")
            ))
            .selected_text(if self.candidate_source_seq_id.trim().is_empty() {
                "choose source sequence"
            } else {
                self.candidate_source_seq_id.as_str()
            })
            .show_ui(ui, |ui| {
                for seq_id in &sequence_ids {
                    if ui
                        .selectable_label(self.candidate_source_seq_id == *seq_id, seq_id)
                        .clicked()
                    {
                        self.candidate_source_seq_id = seq_id.clone();
                    }
                }
            });
        }
        ui.horizontal(|ui| {
            ui.label("length");
            ui.add(egui::TextEdit::singleline(&mut self.candidate_length_bp).desired_width(64.0));
            ui.label("step");
            ui.add(egui::TextEdit::singleline(&mut self.candidate_step_bp).desired_width(64.0));
            ui.label("limit");
            ui.add(egui::TextEdit::singleline(&mut self.candidate_limit).desired_width(96.0));
            ui.label("max dist");
            ui.add(
                egui::TextEdit::singleline(&mut self.candidate_max_distance_bp).desired_width(96.0),
            );
        });
        ui.horizontal(|ui| {
            ui.label("feature kinds");
            ui.text_edit_singleline(&mut self.candidate_feature_kinds);
        });
        ui.horizontal(|ui| {
            ui.label("feature label regex");
            ui.text_edit_singleline(&mut self.candidate_feature_label_regex);
            ui.label("strand");
            egui::ComboBox::from_id_salt(format!(
                "candidate_generate_strand_relation_{}",
                self.seq_id.as_deref().unwrap_or("_global")
            ))
            .selected_text(self.candidate_feature_strand_relation.as_str())
            .show_ui(ui, |ui| {
                ui.selectable_value(
                    &mut self.candidate_feature_strand_relation,
                    CandidateFeatureStrandRelation::Any,
                    "any",
                );
                ui.selectable_value(
                    &mut self.candidate_feature_strand_relation,
                    CandidateFeatureStrandRelation::Same,
                    "same (+)",
                );
                ui.selectable_value(
                    &mut self.candidate_feature_strand_relation,
                    CandidateFeatureStrandRelation::Opposite,
                    "opposite (-)",
                );
            });
            if ui
                .button("Generate")
                .on_hover_text("Run GenerateCandidateSet")
                .clicked()
            {
                let set_name = self.candidate_set_name.trim().to_string();
                let seq_id = self.candidate_source_seq_id.trim().to_string();
                let length = self.candidate_length_bp.trim().parse::<usize>();
                let step = self.candidate_step_bp.trim().parse::<usize>();
                let limit =
                    Self::parse_optional_usize_text(&self.candidate_limit, "candidate limit");
                let max_distance = Self::parse_optional_usize_text(
                    &self.candidate_max_distance_bp,
                    "candidate max distance",
                );
                if set_name.is_empty() {
                    self.op_status = "Candidate set name cannot be empty".to_string();
                } else if seq_id.is_empty() {
                    self.op_status = "Candidate source sequence ID cannot be empty".to_string();
                } else if let (Ok(length_bp), Ok(step_bp), Ok(limit), Ok(max_distance_bp)) =
                    (length, step, limit, max_distance)
                {
                    self.apply_operation_with_feedback(Operation::GenerateCandidateSet {
                        set_name: set_name.clone(),
                        seq_id,
                        length_bp,
                        step_bp,
                        feature_kinds: Self::parse_ids(&self.candidate_feature_kinds),
                        feature_label_regex: if self.candidate_feature_label_regex.trim().is_empty()
                        {
                            None
                        } else {
                            Some(self.candidate_feature_label_regex.trim().to_string())
                        },
                        max_distance_bp,
                        feature_geometry_mode: None,
                        feature_boundary_mode: None,
                        feature_strand_relation: Some(self.candidate_feature_strand_relation),
                        limit,
                    });
                    self.candidate_selected_set = set_name.clone();
                    self.candidate_filter_input_set = set_name.clone();
                    if self.candidate_setop_left.trim().is_empty() {
                        self.candidate_setop_left = set_name;
                    }
                } else {
                    self.op_status = "Invalid candidate generation parameters".to_string();
                }
            }
        });

        ui.separator();
        ui.label("Generate set between anchors");
        ui.horizontal(|ui| {
            ui.label("set");
            ui.text_edit_singleline(&mut self.candidate_between_set_name);
            ui.label("seq");
            ui.text_edit_singleline(&mut self.candidate_between_seq_id);
            if ui
                .small_button("Use active")
                .on_hover_text("Use currently active sequence ID for between-anchor generation")
                .clicked()
            {
                self.candidate_between_seq_id = self.seq_id.clone().unwrap_or_default();
            }
        });
        if !sequence_ids.is_empty() {
            egui::ComboBox::from_id_salt(format!(
                "candidate_between_seq_combo_{}",
                self.seq_id.as_deref().unwrap_or("_global")
            ))
            .selected_text(if self.candidate_between_seq_id.trim().is_empty() {
                "choose source sequence"
            } else {
                self.candidate_between_seq_id.as_str()
            })
            .show_ui(ui, |ui| {
                for seq_id in &sequence_ids {
                    if ui
                        .selectable_label(self.candidate_between_seq_id == *seq_id, seq_id)
                        .clicked()
                    {
                        self.candidate_between_seq_id = seq_id.clone();
                    }
                }
            });
        }
        ui.horizontal(|ui| {
            ui.label("length");
            ui.add(
                egui::TextEdit::singleline(&mut self.candidate_between_length_bp)
                    .desired_width(64.0),
            );
            ui.label("step");
            ui.add(
                egui::TextEdit::singleline(&mut self.candidate_between_step_bp).desired_width(64.0),
            );
            ui.label("limit");
            ui.add(
                egui::TextEdit::singleline(&mut self.candidate_between_limit).desired_width(96.0),
            );
        });
        ui.label("Anchor A");
        ui.horizontal(|ui| {
            ui.checkbox(
                &mut self.candidate_between_anchor_a_mode_position,
                "position (off = feature boundary)",
            );
            if self.candidate_between_anchor_a_mode_position {
                ui.label("pos");
                ui.add(
                    egui::TextEdit::singleline(&mut self.candidate_between_anchor_a_position)
                        .desired_width(96.0),
                );
            } else {
                ui.label("kind");
                ui.add(
                    egui::TextEdit::singleline(&mut self.candidate_between_anchor_a_feature_kind)
                        .desired_width(96.0),
                );
                ui.label("label");
                ui.add(
                    egui::TextEdit::singleline(&mut self.candidate_between_anchor_a_feature_label)
                        .desired_width(120.0),
                );
                ui.label("boundary");
                egui::ComboBox::from_id_salt(format!(
                    "candidate_between_anchor_a_boundary_{}",
                    self.seq_id.as_deref().unwrap_or("_global")
                ))
                .selected_text(match self.candidate_between_anchor_a_boundary {
                    AnchorBoundary::Start => "start",
                    AnchorBoundary::End => "end",
                    AnchorBoundary::Middle => "middle",
                })
                .show_ui(ui, |ui| {
                    ui.selectable_value(
                        &mut self.candidate_between_anchor_a_boundary,
                        AnchorBoundary::Start,
                        "start",
                    );
                    ui.selectable_value(
                        &mut self.candidate_between_anchor_a_boundary,
                        AnchorBoundary::End,
                        "end",
                    );
                    ui.selectable_value(
                        &mut self.candidate_between_anchor_a_boundary,
                        AnchorBoundary::Middle,
                        "middle",
                    );
                });
                ui.label("occ");
                ui.add(
                    egui::TextEdit::singleline(&mut self.candidate_between_anchor_a_occurrence)
                        .desired_width(64.0),
                );
            }
        });
        ui.label("Anchor B");
        ui.horizontal(|ui| {
            ui.checkbox(
                &mut self.candidate_between_anchor_b_mode_position,
                "position (off = feature boundary)",
            );
            if self.candidate_between_anchor_b_mode_position {
                ui.label("pos");
                ui.add(
                    egui::TextEdit::singleline(&mut self.candidate_between_anchor_b_position)
                        .desired_width(96.0),
                );
            } else {
                ui.label("kind");
                ui.add(
                    egui::TextEdit::singleline(&mut self.candidate_between_anchor_b_feature_kind)
                        .desired_width(96.0),
                );
                ui.label("label");
                ui.add(
                    egui::TextEdit::singleline(&mut self.candidate_between_anchor_b_feature_label)
                        .desired_width(120.0),
                );
                ui.label("boundary");
                egui::ComboBox::from_id_salt(format!(
                    "candidate_between_anchor_b_boundary_{}",
                    self.seq_id.as_deref().unwrap_or("_global")
                ))
                .selected_text(match self.candidate_between_anchor_b_boundary {
                    AnchorBoundary::Start => "start",
                    AnchorBoundary::End => "end",
                    AnchorBoundary::Middle => "middle",
                })
                .show_ui(ui, |ui| {
                    ui.selectable_value(
                        &mut self.candidate_between_anchor_b_boundary,
                        AnchorBoundary::Start,
                        "start",
                    );
                    ui.selectable_value(
                        &mut self.candidate_between_anchor_b_boundary,
                        AnchorBoundary::End,
                        "end",
                    );
                    ui.selectable_value(
                        &mut self.candidate_between_anchor_b_boundary,
                        AnchorBoundary::Middle,
                        "middle",
                    );
                });
                ui.label("occ");
                ui.add(
                    egui::TextEdit::singleline(&mut self.candidate_between_anchor_b_occurrence)
                        .desired_width(64.0),
                );
            }
        });
        if ui
            .button("Generate Between Anchors")
            .on_hover_text("Run GenerateCandidateSetBetweenAnchors")
            .clicked()
        {
            let set_name = self.candidate_between_set_name.trim().to_string();
            let seq_id = self.candidate_between_seq_id.trim().to_string();
            let length_bp = self.candidate_between_length_bp.trim().parse::<usize>();
            let step_bp = self.candidate_between_step_bp.trim().parse::<usize>();
            let limit =
                Self::parse_optional_usize_text(&self.candidate_between_limit, "candidate limit");
            let anchor_a = Self::parse_candidate_local_anchor(
                self.candidate_between_anchor_a_mode_position,
                &self.candidate_between_anchor_a_position,
                &self.candidate_between_anchor_a_feature_kind,
                &self.candidate_between_anchor_a_feature_label,
                &self.candidate_between_anchor_a_boundary,
                &self.candidate_between_anchor_a_occurrence,
                "anchor A",
            );
            let anchor_b = Self::parse_candidate_local_anchor(
                self.candidate_between_anchor_b_mode_position,
                &self.candidate_between_anchor_b_position,
                &self.candidate_between_anchor_b_feature_kind,
                &self.candidate_between_anchor_b_feature_label,
                &self.candidate_between_anchor_b_boundary,
                &self.candidate_between_anchor_b_occurrence,
                "anchor B",
            );
            if set_name.is_empty() {
                self.op_status = "Candidate set name cannot be empty".to_string();
            } else if seq_id.is_empty() {
                self.op_status = "Candidate source sequence ID cannot be empty".to_string();
            } else if let (Ok(length_bp), Ok(step_bp), Ok(limit), Ok(anchor_a), Ok(anchor_b)) =
                (length_bp, step_bp, limit, anchor_a, anchor_b)
            {
                self.apply_operation_with_feedback(Operation::GenerateCandidateSetBetweenAnchors {
                    set_name: set_name.clone(),
                    seq_id,
                    anchor_a,
                    anchor_b,
                    length_bp,
                    step_bp,
                    limit,
                });
                self.candidate_selected_set = set_name.clone();
                self.candidate_filter_input_set = set_name.clone();
                if self.candidate_setop_left.trim().is_empty() {
                    self.candidate_setop_left = set_name;
                }
            } else {
                self.op_status =
                    "Invalid between-anchor candidate generation parameters".to_string();
            }
        }

        ui.separator();
        ui.label("Score and transform sets");
        ui.horizontal(|ui| {
            ui.label("selected set");
            egui::ComboBox::from_id_salt(format!(
                "candidate_selected_set_combo_{}",
                self.seq_id.as_deref().unwrap_or("_global")
            ))
            .selected_text(if self.candidate_selected_set.trim().is_empty() {
                "none"
            } else {
                self.candidate_selected_set.as_str()
            })
            .show_ui(ui, |ui| {
                for name in &set_names {
                    if ui
                        .selectable_label(self.candidate_selected_set == *name, name)
                        .clicked()
                    {
                        self.candidate_selected_set = name.clone();
                    }
                }
            });
            if ui
                .button("Delete selected")
                .on_hover_text("Run DeleteCandidateSet for selected set")
                .clicked()
            {
                if self.candidate_selected_set.trim().is_empty() {
                    self.op_status = "Select a candidate set to delete".to_string();
                } else {
                    self.apply_operation_with_feedback(Operation::DeleteCandidateSet {
                        set_name: self.candidate_selected_set.trim().to_string(),
                    });
                }
            }
        });

        ui.horizontal(|ui| {
            ui.label("metric");
            ui.text_edit_singleline(&mut self.candidate_score_metric);
            ui.label("expr");
            ui.text_edit_singleline(&mut self.candidate_score_expression);
            if ui
                .button("Score expr")
                .on_hover_text("Run ScoreCandidateSetExpression on selected set")
                .clicked()
            {
                if self.candidate_selected_set.trim().is_empty() {
                    self.op_status = "Select a candidate set first".to_string();
                } else if self.candidate_score_metric.trim().is_empty() {
                    self.op_status = "Metric name cannot be empty".to_string();
                } else if self.candidate_score_expression.trim().is_empty() {
                    self.op_status = "Expression cannot be empty".to_string();
                } else {
                    self.apply_operation_with_feedback(Operation::ScoreCandidateSetExpression {
                        set_name: self.candidate_selected_set.trim().to_string(),
                        metric: self.candidate_score_metric.trim().to_string(),
                        expression: self.candidate_score_expression.trim().to_string(),
                    });
                }
            }
        });

        ui.horizontal(|ui| {
            ui.label("distance metric");
            ui.text_edit_singleline(&mut self.candidate_distance_metric);
            ui.label("feature kinds");
            ui.text_edit_singleline(&mut self.candidate_distance_feature_kinds);
        });
        ui.horizontal(|ui| {
            ui.label("feature label regex");
            ui.text_edit_singleline(&mut self.candidate_distance_feature_label_regex);
            ui.label("strand");
            egui::ComboBox::from_id_salt(format!(
                "candidate_distance_strand_relation_{}",
                self.seq_id.as_deref().unwrap_or("_global")
            ))
            .selected_text(self.candidate_distance_feature_strand_relation.as_str())
            .show_ui(ui, |ui| {
                ui.selectable_value(
                    &mut self.candidate_distance_feature_strand_relation,
                    CandidateFeatureStrandRelation::Any,
                    "any",
                );
                ui.selectable_value(
                    &mut self.candidate_distance_feature_strand_relation,
                    CandidateFeatureStrandRelation::Same,
                    "same (+)",
                );
                ui.selectable_value(
                    &mut self.candidate_distance_feature_strand_relation,
                    CandidateFeatureStrandRelation::Opposite,
                    "opposite (-)",
                );
            });
            if ui
                .button("Score distance")
                .on_hover_text("Run ScoreCandidateSetDistance on selected set")
                .clicked()
            {
                if self.candidate_selected_set.trim().is_empty() {
                    self.op_status = "Select a candidate set first".to_string();
                } else if self.candidate_distance_metric.trim().is_empty() {
                    self.op_status = "Distance metric name cannot be empty".to_string();
                } else {
                    self.apply_operation_with_feedback(Operation::ScoreCandidateSetDistance {
                        set_name: self.candidate_selected_set.trim().to_string(),
                        metric: self.candidate_distance_metric.trim().to_string(),
                        feature_kinds: Self::parse_ids(&self.candidate_distance_feature_kinds),
                        feature_label_regex: if self
                            .candidate_distance_feature_label_regex
                            .trim()
                            .is_empty()
                        {
                            None
                        } else {
                            Some(
                                self.candidate_distance_feature_label_regex
                                    .trim()
                                    .to_string(),
                            )
                        },
                        feature_geometry_mode: None,
                        feature_boundary_mode: None,
                        feature_strand_relation: Some(
                            self.candidate_distance_feature_strand_relation,
                        ),
                    });
                }
            }
        });

        ui.horizontal(|ui| {
            ui.label("filter input");
            ui.text_edit_singleline(&mut self.candidate_filter_input_set);
            ui.label("output");
            ui.text_edit_singleline(&mut self.candidate_filter_output_set);
            ui.label("metric");
            ui.text_edit_singleline(&mut self.candidate_filter_metric);
        });
        ui.horizontal(|ui| {
            ui.label("min");
            ui.add(egui::TextEdit::singleline(&mut self.candidate_filter_min).desired_width(72.0));
            ui.label("max");
            ui.add(egui::TextEdit::singleline(&mut self.candidate_filter_max).desired_width(72.0));
            ui.label("min q");
            ui.add(
                egui::TextEdit::singleline(&mut self.candidate_filter_min_quantile)
                    .desired_width(72.0),
            );
            ui.label("max q");
            ui.add(
                egui::TextEdit::singleline(&mut self.candidate_filter_max_quantile)
                    .desired_width(72.0),
            );
            if ui
                .button("Filter")
                .on_hover_text("Run FilterCandidateSet")
                .clicked()
            {
                let min = Self::parse_optional_f64_text(&self.candidate_filter_min, "filter min");
                let max = Self::parse_optional_f64_text(&self.candidate_filter_max, "filter max");
                let min_q = Self::parse_optional_f64_text(
                    &self.candidate_filter_min_quantile,
                    "filter min quantile",
                );
                let max_q = Self::parse_optional_f64_text(
                    &self.candidate_filter_max_quantile,
                    "filter max quantile",
                );
                if self.candidate_filter_input_set.trim().is_empty() {
                    self.op_status = "Filter input set cannot be empty".to_string();
                } else if self.candidate_filter_output_set.trim().is_empty() {
                    self.op_status = "Filter output set cannot be empty".to_string();
                } else if self.candidate_filter_metric.trim().is_empty() {
                    self.op_status = "Filter metric cannot be empty".to_string();
                } else if let (Ok(min), Ok(max), Ok(min_quantile), Ok(max_quantile)) =
                    (min, max, min_q, max_q)
                {
                    self.apply_operation_with_feedback(Operation::FilterCandidateSet {
                        input_set: self.candidate_filter_input_set.trim().to_string(),
                        output_set: self.candidate_filter_output_set.trim().to_string(),
                        metric: self.candidate_filter_metric.trim().to_string(),
                        min,
                        max,
                        min_quantile,
                        max_quantile,
                    });
                    self.candidate_selected_set =
                        self.candidate_filter_output_set.trim().to_string();
                } else {
                    self.op_status = "Invalid numeric filter threshold".to_string();
                }
            }
        });

        ui.horizontal(|ui| {
            ui.label("set-op");
            egui::ComboBox::from_id_salt(format!(
                "candidate_setop_mode_combo_{}",
                self.seq_id.as_deref().unwrap_or("_global")
            ))
            .selected_text(if self.candidate_setop_mode.trim().is_empty() {
                "intersect"
            } else {
                self.candidate_setop_mode.as_str()
            })
            .show_ui(ui, |ui| {
                for mode in ["union", "intersect", "subtract"] {
                    if ui
                        .selectable_label(self.candidate_setop_mode == mode, mode)
                        .clicked()
                    {
                        self.candidate_setop_mode = mode.to_string();
                    }
                }
            });
            ui.label("left");
            ui.text_edit_singleline(&mut self.candidate_setop_left);
            ui.label("right");
            ui.text_edit_singleline(&mut self.candidate_setop_right);
            ui.label("output");
            ui.text_edit_singleline(&mut self.candidate_setop_output);
            if ui
                .button("Apply set-op")
                .on_hover_text("Run CandidateSetOp")
                .clicked()
            {
                let op = match self
                    .candidate_setop_mode
                    .trim()
                    .to_ascii_lowercase()
                    .as_str()
                {
                    "union" => Some(CandidateSetOperator::Union),
                    "intersect" => Some(CandidateSetOperator::Intersect),
                    "subtract" => Some(CandidateSetOperator::Subtract),
                    _ => None,
                };
                if let Some(op) = op {
                    if self.candidate_setop_left.trim().is_empty()
                        || self.candidate_setop_right.trim().is_empty()
                        || self.candidate_setop_output.trim().is_empty()
                    {
                        self.op_status =
                            "Set operation requires left, right, and output set names".to_string();
                    } else {
                        self.apply_operation_with_feedback(Operation::CandidateSetOp {
                            op,
                            left_set: self.candidate_setop_left.trim().to_string(),
                            right_set: self.candidate_setop_right.trim().to_string(),
                            output_set: self.candidate_setop_output.trim().to_string(),
                        });
                        self.candidate_selected_set =
                            self.candidate_setop_output.trim().to_string();
                    }
                } else {
                    self.op_status =
                        "Set operation mode must be union/intersect/subtract".to_string();
                }
            }
        });

        ui.separator();
        ui.label("Inspect and export");
        ui.horizontal(|ui| {
            ui.label("page limit");
            ui.add(egui::TextEdit::singleline(&mut self.candidate_page_limit).desired_width(72.0));
            ui.label("offset");
            ui.add(egui::TextEdit::singleline(&mut self.candidate_page_offset).desired_width(96.0));
            ui.label("sort");
            ui.text_edit_singleline(&mut self.candidate_sort_key);
            ui.checkbox(&mut self.candidate_sort_desc, "descending");
        });

        if !self.candidate_selected_set.trim().is_empty() {
            let requested_limit = self
                .candidate_page_limit
                .trim()
                .parse::<usize>()
                .ok()
                .filter(|v| *v > 0)
                .unwrap_or(50);
            let requested_offset = self
                .candidate_page_offset
                .trim()
                .parse::<usize>()
                .ok()
                .unwrap_or(0);

            let page_result = {
                let guard = engine.read().expect("Engine lock poisoned");
                guard.inspect_candidate_set_page(
                    &self.candidate_selected_set,
                    requested_limit,
                    requested_offset,
                )
            };

            match page_result {
                Ok((mut page, total, clamped_offset)) => {
                    if self.candidate_page_offset.trim() != clamped_offset.to_string() {
                        self.candidate_page_offset = clamped_offset.to_string();
                    }
                    Self::sort_candidate_records(
                        &mut page.candidates,
                        &self.candidate_sort_key,
                        self.candidate_sort_desc,
                    );

                    let end_exclusive = clamped_offset.saturating_add(page.candidates.len());
                    ui.horizontal(|ui| {
                        if ui
                            .button("Prev")
                            .on_hover_text("Show previous candidate page")
                            .clicked()
                        {
                            let new_offset = clamped_offset.saturating_sub(requested_limit);
                            self.candidate_page_offset = new_offset.to_string();
                        }
                        if ui
                            .button("Next")
                            .on_hover_text("Show next candidate page")
                            .clicked()
                        {
                            let next = clamped_offset.saturating_add(requested_limit);
                            self.candidate_page_offset = next.min(total).to_string();
                        }
                        ui.monospace(format!(
                            "set '{}' rows {}..{} of {}",
                            self.candidate_selected_set,
                            if total == 0 {
                                0
                            } else {
                                clamped_offset.saturating_add(1)
                            },
                            end_exclusive,
                            total
                        ));
                    });

                    let mut metric_names = set_summaries
                        .iter()
                        .find(|s| s.name == self.candidate_selected_set)
                        .map(|s| s.metrics.clone())
                        .unwrap_or_default();
                    metric_names.sort();
                    if !metric_names.is_empty() {
                        ui.small(format!("metrics: {}", metric_names.join(", ")));
                    }

                    egui::ScrollArea::vertical()
                        .max_height(180.0)
                        .show(ui, |ui| {
                            scroll_input_policy::apply_scrollarea_keyboard_navigation(
                                ui,
                                scroll_input_policy::DEFAULT_SCROLLAREA_KEYBOARD_STEP,
                            );
                            egui::Grid::new(format!(
                                "candidate_rows_grid_{}",
                                self.seq_id.as_deref().unwrap_or("_global")
                            ))
                            .striped(true)
                            .show(ui, |ui| {
                                ui.strong("seq_id");
                                ui.strong("start");
                                ui.strong("end");
                                ui.strong("len");
                                ui.strong("sort value");
                                ui.end_row();
                                for row in &page.candidates {
                                    let length_bp = row.end_0based.saturating_sub(row.start_0based);
                                    let sort_value = match self
                                        .candidate_sort_key
                                        .trim()
                                        .to_ascii_lowercase()
                                        .as_str()
                                    {
                                        "seq_id" => row.seq_id.clone(),
                                        "sequence" => row.sequence.clone(),
                                        "start" | "start_0based" => row.start_0based.to_string(),
                                        "end" | "end_0based" => row.end_0based.to_string(),
                                        "length" | "length_bp" => length_bp.to_string(),
                                        _ => Self::candidate_metric_lookup(
                                            row,
                                            self.candidate_sort_key.trim(),
                                        )
                                        .map(|v| format!("{v:.6}"))
                                        .unwrap_or_else(|| "-".to_string()),
                                    };
                                    ui.monospace(&row.seq_id);
                                    ui.monospace(row.start_0based.to_string());
                                    ui.monospace(row.end_0based.to_string());
                                    ui.monospace(length_bp.to_string());
                                    ui.monospace(sort_value);
                                    ui.end_row();
                                }
                            });
                        });

                    if ui
                        .button("Export selected set as JSON")
                        .on_hover_text("Export all rows from selected set to a JSON file")
                        .clicked()
                    {
                        let total_rows = set_summaries
                            .iter()
                            .find(|s| s.name == self.candidate_selected_set)
                            .map(|s| s.candidate_count)
                            .unwrap_or(total);
                        let export_result = {
                            let guard = engine.read().expect("Engine lock poisoned");
                            guard.inspect_candidate_set_page(
                                &self.candidate_selected_set,
                                total_rows.max(1),
                                0,
                            )
                        };
                        match export_result {
                            Ok((set, _, _)) => {
                                let path = rfd::FileDialog::new()
                                    .set_file_name(&format!(
                                        "{}.candidate_set.json",
                                        self.candidate_selected_set.replace(' ', "_")
                                    ))
                                    .add_filter("JSON", &["json"])
                                    .save_file();
                                if let Some(path) = path {
                                    let payload = serde_json::json!({
                                        "schema": "gentle.candidate_set.export.v1",
                                        "exported_at_unix_ms": std::time::SystemTime::now()
                                            .duration_since(std::time::UNIX_EPOCH)
                                            .map(|d| d.as_millis())
                                            .unwrap_or(0),
                                        "set": set
                                    });
                                    match serde_json::to_string_pretty(&payload) {
                                        Ok(text) => {
                                            if let Err(e) = fs::write(&path, text) {
                                                self.op_status = format!(
                                                    "Could not export candidate set to '{}': {e}",
                                                    path.display()
                                                );
                                            } else {
                                                self.op_status = format!(
                                                    "Exported candidate set '{}' to '{}'",
                                                    self.candidate_selected_set,
                                                    path.display()
                                                );
                                            }
                                        }
                                        Err(e) => {
                                            self.op_status = format!(
                                                "Could not serialize candidate set export: {e}"
                                            );
                                        }
                                    }
                                }
                            }
                            Err(e) => {
                                self.op_status =
                                    format!("Could not load selected set for export: {e}");
                            }
                        }
                    }
                }
                Err(e) => {
                    ui.colored_label(
                        egui::Color32::LIGHT_RED,
                        format!("inspect failed: {}", e.message),
                    );
                }
            }
        } else {
            ui.small("No candidate sets available yet.");
        }

        ui.separator();
        ui.label("Macro");
        ui.add(
            egui::TextEdit::multiline(&mut self.candidate_macro_script)
                .desired_rows(3)
                .hint_text(
                    "generate setA seq_1 --length 20 --step 1; score setA gc_score gc_fraction",
                ),
        );
        if ui
            .button("Run candidates macro")
            .on_hover_text("Execute candidates macro statements (same behavior as CLI/shell)")
            .clicked()
        {
            let script = self.candidate_macro_script.trim().to_string();
            if script.is_empty() {
                self.op_status = "Candidates macro script is empty".to_string();
            } else {
                let command = ShellCommand::CandidatesMacro {
                    script: script.clone(),
                    transactional: false,
                };
                let outcome = {
                    let mut guard = engine.write().expect("Engine lock poisoned");
                    let options = ShellExecutionOptions::from_env();
                    execute_shell_command_with_options(&mut guard, &command, &options)
                };
                match outcome {
                    Ok(run) => {
                        let output =
                            serde_json::to_string_pretty(&run.output).unwrap_or_else(|e| {
                                format!("{{\"error\":\"Could not format macro output: {e}\"}}")
                            });
                        if !self.shell_output_text.is_empty() {
                            self.shell_output_text.push('\n');
                        }
                        self.shell_output_text
                            .push_str(&format!("$ candidates macro {script}\n{output}\n"));
                        self.op_status = format!(
                            "Candidates macro executed ({} statement(s))",
                            run.output
                                .get("executed")
                                .and_then(|v| v.as_u64())
                                .unwrap_or(0)
                        );
                        self.sync_from_engine_display();
                    }
                    Err(e) => {
                        self.op_status = format!("Candidates macro failed: {e}");
                    }
                }
            }
        }
    }

    fn parse_ids(text: &str) -> Vec<String> {
        text.split(',')
            .map(|s| s.trim())
            .filter(|s| !s.is_empty())
            .map(|s| s.to_string())
            .collect()
    }

    fn append_unique_csv_token(text: &mut String, value: impl Into<String>) {
        let value = value.into();
        let trimmed = value.trim();
        if trimmed.is_empty() {
            return;
        }
        let mut values = Self::parse_ids(text);
        if values
            .iter()
            .any(|existing| existing.eq_ignore_ascii_case(trimmed))
        {
            return;
        }
        values.push(trimmed.to_string());
        *text = values.join(",");
    }

    fn project_sequence_ids(&self) -> Vec<String> {
        let mut seq_ids = if let Some(engine) = self.engine.as_ref() {
            engine
                .read()
                .ok()
                .map(|guard| guard.state().sequences.keys().cloned().collect::<Vec<_>>())
                .unwrap_or_default()
        } else {
            vec![]
        };
        seq_ids.sort_unstable();
        seq_ids
    }

    fn normalize_enzyme_match_token(text: &str) -> String {
        text.chars()
            .filter(|c| c.is_ascii_alphanumeric())
            .map(|c| c.to_ascii_uppercase())
            .collect()
    }

    fn rebase_name_lookup_by_normalized() -> HashMap<String, String> {
        let mut lookup = HashMap::new();
        for enzyme in active_restriction_enzymes() {
            let normalized = Self::normalize_enzyme_match_token(&enzyme.name);
            if !normalized.is_empty() {
                lookup.entry(normalized).or_insert(enzyme.name);
            }
        }
        lookup
    }

    fn canonicalize_rebase_enzyme_name(
        raw: &str,
        lookup: &HashMap<String, String>,
    ) -> Option<String> {
        let normalized = Self::normalize_enzyme_match_token(raw);
        lookup.get(&normalized).cloned()
    }

    fn extract_rebase_enzyme_names_from_text(
        text: &str,
        lookup: &HashMap<String, String>,
    ) -> Vec<String> {
        let tokens = text
            .split(|c: char| !c.is_ascii_alphanumeric())
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string)
            .collect::<Vec<_>>();
        let mut out = vec![];
        let mut seen = HashSet::new();
        let mut push_candidate = |candidate: String| {
            if let Some(name) = Self::canonicalize_rebase_enzyme_name(&candidate, lookup) {
                if seen.insert(name.clone()) {
                    out.push(name);
                }
            }
        };
        for idx in 0..tokens.len() {
            push_candidate(tokens[idx].clone());
            if idx + 1 < tokens.len() {
                push_candidate(format!("{}{}", tokens[idx], tokens[idx + 1]));
            }
            if idx + 2 < tokens.len() {
                push_candidate(format!(
                    "{}{}{}",
                    tokens[idx],
                    tokens[idx + 1],
                    tokens[idx + 2]
                ));
            }
        }
        out
    }

    fn text_mentions_mcs(text: &str) -> bool {
        let lower = text.to_ascii_lowercase();
        lower.contains("multiple cloning site")
            || lower == "mcs"
            || lower.contains(" mcs ")
            || lower.starts_with("mcs ")
            || lower.ends_with(" mcs")
            || lower.contains("(mcs)")
    }

    fn collect_active_cds_ranges_0based(dna: &DNAsequence) -> Vec<(usize, usize)> {
        let mut ranges = vec![];
        for feature in dna.features() {
            if !feature.kind.to_string().eq_ignore_ascii_case("CDS") {
                continue;
            }
            collect_location_ranges_usize(&feature.location, &mut ranges);
        }
        ranges.sort_unstable_by(|a, b| a.0.cmp(&b.0).then(a.1.cmp(&b.1)));
        ranges.dedup();
        ranges
    }

    fn single_cutter_enzymes_for_active_sequence(&self, require_cds_overlap: bool) -> Vec<String> {
        let Ok(dna) = self.dna.read() else {
            return vec![];
        };
        let seq_len = dna.len();
        if seq_len == 0 {
            return vec![];
        }
        let cds_ranges = if require_cds_overlap {
            Self::collect_active_cds_ranges_0based(&dna)
        } else {
            vec![]
        };
        let mut enzyme_cut_counts: HashMap<String, usize> = HashMap::new();
        let mut enzyme_first_cut_0based: HashMap<String, usize> = HashMap::new();
        let mut enzyme_has_cds_cut: HashMap<String, bool> = HashMap::new();
        for site in dna
            .restriction_enzyme_sites()
            .iter()
            .filter(|site| site.forward_strand)
        {
            let name = site.enzyme.name.clone();
            *enzyme_cut_counts.entry(name.clone()).or_insert(0) += 1;

            let cut_pos_0based = if dna.is_circular() {
                let len = seq_len as isize;
                let raw = site.offset.saturating_add(site.enzyme.cut);
                raw.rem_euclid(len) as usize
            } else {
                let raw = site.offset.saturating_add(site.enzyme.cut);
                if raw < 0 || raw >= seq_len as isize {
                    continue;
                }
                raw as usize
            };
            enzyme_first_cut_0based
                .entry(name.clone())
                .and_modify(|existing| *existing = (*existing).min(cut_pos_0based))
                .or_insert(cut_pos_0based);

            if require_cds_overlap
                && cds_ranges
                    .iter()
                    .any(|(start, end)| cut_pos_0based >= *start && cut_pos_0based < *end)
            {
                enzyme_has_cds_cut.insert(name, true);
            }
        }

        let mut names = enzyme_cut_counts
            .into_iter()
            .filter_map(|(name, cut_count)| {
                if cut_count != 1 {
                    return None;
                }
                if require_cds_overlap && !enzyme_has_cds_cut.get(&name).copied().unwrap_or(false) {
                    return None;
                }
                Some(name)
            })
            .collect::<Vec<_>>();
        names.sort_unstable_by(|left, right| {
            enzyme_first_cut_0based
                .get(left)
                .copied()
                .unwrap_or(usize::MAX)
                .cmp(
                    &enzyme_first_cut_0based
                        .get(right)
                        .copied()
                        .unwrap_or(usize::MAX),
                )
                .then(left.cmp(right))
        });
        names
    }

    fn collect_mcs_enzyme_candidates_for_active_sequence(&self) -> (Vec<String>, Vec<String>) {
        let Ok(dna) = self.dna.read() else {
            return (vec![], vec![]);
        };
        let lookup = Self::rebase_name_lookup_by_normalized();
        let available_sites: HashSet<String> = dna
            .restriction_enzyme_sites()
            .iter()
            .filter(|site| site.forward_strand)
            .map(|site| site.enzyme.name.clone())
            .collect();
        let mut selected = vec![];
        let mut missing = vec![];
        let mut seen_selected = HashSet::new();
        let mut seen_missing = HashSet::new();

        for feature in dna.features() {
            let mcs_hint = feature
                .qualifier_values("mcs_expected_sites")
                .next()
                .is_some()
                || feature.qualifier_values("mcs_preset").next().is_some()
                || Self::feature_tree_first_nonempty_qualifier(
                    feature,
                    &["label", "note", "gene", "name", "standard_name"],
                )
                .map(|text| Self::text_mentions_mcs(&text))
                .unwrap_or(false);
            if !mcs_hint {
                continue;
            }

            let mut candidates = vec![];
            for raw in feature.qualifier_values("mcs_expected_sites") {
                for token in raw
                    .split(',')
                    .map(str::trim)
                    .filter(|value| !value.is_empty())
                {
                    if let Some(name) = Self::canonicalize_rebase_enzyme_name(token, &lookup) {
                        candidates.push(name);
                    } else {
                        candidates
                            .extend(Self::extract_rebase_enzyme_names_from_text(token, &lookup));
                    }
                }
            }
            for key in ["note", "label", "gene", "name", "standard_name"] {
                for raw in feature.qualifier_values(key) {
                    candidates.extend(Self::extract_rebase_enzyme_names_from_text(raw, &lookup));
                }
            }

            for name in candidates {
                if available_sites.contains(&name) {
                    if seen_selected.insert(name.clone()) {
                        selected.push(name);
                    }
                } else if seen_missing.insert(name.clone()) {
                    missing.push(name);
                }
            }
        }
        (selected, missing)
    }

    fn set_digest_enzymes_from_list(&mut self, enzymes: Vec<String>, status: String) {
        if enzymes.is_empty() {
            self.op_status = status;
            return;
        }
        self.digest_enzymes_text = enzymes.join(",");
        self.op_status = format!("{status} -> {}", self.digest_enzymes_text);
    }

    fn set_digest_enzymes_from_mcs(&mut self) {
        let (selected, missing) = self.collect_mcs_enzyme_candidates_for_active_sequence();
        if selected.is_empty() {
            let mut status =
                "No usable MCS-linked enzymes were found on active sequence.".to_string();
            if !missing.is_empty() {
                status.push_str(&format!(
                    " MCS annotation mentioned unavailable/non-cutting enzymes: {}",
                    missing.join(",")
                ));
            }
            self.op_status = status;
            return;
        }
        let mut status = format!("Selected {} MCS-linked enzyme(s)", selected.len());
        if !missing.is_empty() {
            status.push_str(&format!(" (skipped: {})", missing.join(",")));
        }
        self.set_digest_enzymes_from_list(selected, status);
    }

    fn set_digest_enzymes_single_cutters(&mut self, require_cds_overlap: bool) {
        let selected = self.single_cutter_enzymes_for_active_sequence(require_cds_overlap);
        if require_cds_overlap {
            self.set_digest_enzymes_from_list(
                selected,
                "Selected single-cutter enzymes with cleavage in CDS".to_string(),
            );
        } else {
            self.set_digest_enzymes_from_list(
                selected,
                "Selected single-cutter enzymes from active REBASE scan".to_string(),
            );
        }
    }

    fn normalized_ids(text: &str) -> Vec<String> {
        let mut ids = Self::parse_ids(text)
            .into_iter()
            .map(|id| id.to_ascii_lowercase())
            .collect::<Vec<_>>();
        ids.sort_unstable();
        ids.dedup();
        ids
    }

    fn pool_gel_ladder_preset_label(text: &str) -> String {
        let current = Self::normalized_ids(text);
        for (label, preset) in POOL_GEL_LADDER_PRESETS {
            if current == Self::normalized_ids(preset) {
                return label.to_string();
            }
        }
        if current.is_empty() {
            "Auto".to_string()
        } else {
            "Custom".to_string()
        }
    }

    fn collect_tfbs_motifs(&self) -> Vec<String> {
        if self.tfbs_use_all_motifs {
            tf_motifs::all_motif_ids()
        } else {
            Self::parse_ids(&self.tfbs_motifs)
        }
    }

    fn has_tfbs_scan_motifs_configured(&self) -> bool {
        self.tfbs_use_all_motifs || !Self::parse_ids(&self.tfbs_motifs).is_empty()
    }

    fn add_tfbs_motif_selection(&mut self, motif_id: &str) {
        let mut motifs = Self::parse_ids(&self.tfbs_motifs);
        if motifs
            .iter()
            .any(|m| m.eq_ignore_ascii_case(motif_id.trim()))
        {
            return;
        }
        motifs.push(motif_id.trim().to_string());
        self.tfbs_motifs = motifs.join(",");
    }

    fn parse_tf_threshold_map(text: &str) -> Result<HashMap<String, f64>, String> {
        let mut out = HashMap::new();
        for chunk in text.split(|c| matches!(c, ',' | ';' | '\n' | '\r')) {
            let chunk = chunk.trim();
            if chunk.is_empty() {
                continue;
            }
            let Some((k, v)) = chunk.split_once('=') else {
                return Err(format!(
                    "Invalid per-TF threshold entry '{}'; expected TF=VALUE",
                    chunk
                ));
            };
            let key = k.trim().to_string();
            if key.is_empty() {
                return Err("Empty TF key in per-TF threshold map".to_string());
            }
            let value = v
                .trim()
                .parse::<f64>()
                .map_err(|_| format!("Invalid numeric threshold value '{}'", v.trim()))?;
            out.insert(key, value);
        }
        Ok(out)
    }

    fn collect_tfbs_scan_settings(
        &self,
    ) -> Result<
        (
            Vec<String>,
            Option<f64>,
            Option<f64>,
            Vec<TfThresholdOverride>,
        ),
        String,
    > {
        let motifs = self.collect_tfbs_motifs();
        if motifs.is_empty() {
            return Err("Provide at least one TF motif, or enable all JASPAR motifs".to_string());
        }

        let min_llr_bits = Self::parse_optional_f64_text(&self.tfbs_min_llr_bits, "min llr_bits")?;
        let min_llr_quantile =
            Self::parse_optional_f64_text(&self.tfbs_min_llr_quantile, "min llr_quantile")?;
        let per_bits = Self::parse_tf_threshold_map(&self.tfbs_per_tf_min_llr_bits)?;
        let per_quantiles = Self::parse_tf_threshold_map(&self.tfbs_per_tf_min_llr_quantile)?;

        let mut merged: BTreeMap<String, TfThresholdOverride> = BTreeMap::new();
        for (tf, value) in per_bits {
            merged.insert(
                tf.clone(),
                TfThresholdOverride {
                    tf,
                    min_llr_bits: Some(value),
                    min_llr_quantile: None,
                },
            );
        }
        for (tf, value) in per_quantiles {
            let entry = merged.entry(tf.clone()).or_insert(TfThresholdOverride {
                tf: tf.clone(),
                min_llr_bits: None,
                min_llr_quantile: None,
            });
            entry.min_llr_quantile = Some(value);
        }

        Ok((
            motifs,
            min_llr_bits,
            min_llr_quantile,
            merged.into_values().collect(),
        ))
    }

